begin;

insert into regulation_documents
    (document_code, title, document_type, scope, issuer)
values
    ('NRD_COST_STANDARD',
     '국가연구개발사업 연구개발비 사용 기준',
     'ADMINISTRATIVE_RULE',
     'NATIONAL_RND_COMMON',
     '과학기술정보통신부')
on conflict (document_code) do update set
    title = excluded.title,
    document_type = excluded.document_type,
    scope = excluded.scope,
    issuer = excluded.issuer;

insert into regulation_versions
    (document_id, version_code, version_label, notice_number,
     promulgated_at, effective_from, publication_status,
     source_filename, source_file_sha256, source_system,
     special_effective_dates)
select
    d.id,
    'NRD_COST_STANDARD_2026_38',
    '제2026-38호 시행본',
    '과학기술정보통신부고시 제2026-38호',
    date '2026-05-06',
    date '2026-05-06',
    'ACTIVE',
    '국가연구개발사업 연구개발비 사용 기준(고시)(제2026-38호)(20260506) (2).hwpx',
    '0687bc3e6351915b2a9d5f3c891e1bbbbddbe0bdd7d21022cca8d6908ca74ca5',
    '국가법령정보센터',
    $special$
[{"articles": ["제5조", "제10조의2", "제25조의2"], "effective_from": "2026-06-11", "reason": "부칙 제1조 단서"}]
$special$::jsonb
from regulation_documents d
where d.document_code = 'NRD_COST_STANDARD'
on conflict (version_code) do update set
    version_label = excluded.version_label,
    notice_number = excluded.notice_number,
    promulgated_at = excluded.promulgated_at,
    effective_from = excluded.effective_from,
    publication_status = excluded.publication_status,
    source_filename = excluded.source_filename,
    source_file_sha256 = excluded.source_file_sha256,
    source_system = excluded.source_system,
    special_effective_dates = excluded.special_effective_dates;

insert into expense_categories
