from jsonb_to_recordset($categories$
[{"code": "ALL", "name": "전체 연구개발비", "parent_code": null, "cost_class": null, "category_type": "SYSTEM", "display_order": 0, "is_active": true}, {"code": "DIRECT", "name": "직접비", "parent_code": "ALL", "cost_class": "DIRECT", "category_type": "LEGAL", "display_order": 10, "is_active": true}, {"code": "INDIRECT", "name": "간접비", "parent_code": "ALL", "cost_class": "INDIRECT", "category_type": "LEGAL", "display_order": 20, "is_active": true}, {"code": "DIRECT_LABOR", "name": "인건비", "parent_code": "DIRECT", "cost_class": "DIRECT", "category_type": "LEGAL", "display_order": 100, "is_active": true}, {"code": "DIRECT_STUDENT_LABOR", "name": "학생인건비", "parent_code": "DIRECT", "cost_class": "DIRECT", "category_type": "LEGAL", "display_order": 110, "is_active": true}, {"code": "DIRECT_EQUIPMENT", "name": "연구시설·장비비", "parent_code": "DIRECT", "cost_class": "DIRECT", "category_type": "LEGAL", "display_order": 120, "is_active": true}, {"code": "DIRECT_MATERIAL", "name": "연구재료비", "parent_code": "DIRECT", "cost_class": "DIRECT", "category_type": "LEGAL", "display_order": 130, "is_active": true}, {"code": "DIRECT_ACTIVITY", "name": "연구활동비", "parent_code": "DIRECT", "cost_class": "DIRECT", "category_type": "LEGAL", "display_order": 140, "is_active": true}, {"code": "ACTIVITY_IP", "name": "지식재산 창출 활동비", "parent_code": "DIRECT_ACTIVITY", "cost_class": "DIRECT", "category_type": "LEGAL", "display_order": 141, "is_active": true}, {"code": "ACTIVITY_EXTERNAL_TECH", "name": "외부 전문기술 활용비", "parent_code": "DIRECT_ACTIVITY", "cost_class": "DIRECT", "category_type": "LEGAL", "display_order": 142, "is_active": true}, {"code": "ACTIVITY_MEETING", "name": "회의비", "parent_code": "DIRECT_ACTIVITY", "cost_class": "DIRECT", "category_type": "LEGAL", "display_order": 143, "is_active": true}, {"code": "ACTIVITY_TRAVEL", "name": "출장비", "parent_code": "DIRECT_ACTIVITY", "cost_class": "DIRECT", "category_type": "LEGAL", "display_order": 144, "is_active": true}, {"code": "ACTIVITY_SOFTWARE", "name": "소프트웨어 활용비", "parent_code": "DIRECT_ACTIVITY", "cost_class": "DIRECT", "category_type": "LEGAL", "display_order": 145, "is_active": true}, {"code": "ACTIVITY_CLOUD", "name": "클라우드컴퓨팅서비스 활용비", "parent_code": "DIRECT_ACTIVITY", "cost_class": "DIRECT", "category_type": "LEGAL", "display_order": 146, "is_active": true}, {"code": "ACTIVITY_LAB_OPERATION", "name": "연구실운영비", "parent_code": "DIRECT_ACTIVITY", "cost_class": "DIRECT", "category_type": "LEGAL", "display_order": 147, "is_active": true}, {"code": "ACTIVITY_PERSONNEL_SUPPORT", "name": "연구인력 지원비", "parent_code": "DIRECT_ACTIVITY", "cost_class": "DIRECT", "category_type": "LEGAL", "display_order": 148, "is_active": true}, {"code": "ACTIVITY_FOREIGN_RESEARCHER", "name": "해외연구자 유치 지원비", "parent_code": "DIRECT_ACTIVITY", "cost_class": "DIRECT", "category_type": "LEGAL", "display_order": 149, "is_active": true}, {"code": "ACTIVITY_PROGRAM_MANAGEMENT", "name": "종합사업관리비", "parent_code": "DIRECT_ACTIVITY", "cost_class": "DIRECT", "category_type": "LEGAL", "display_order": 150, "is_active": true}, {"code": "ACTIVITY_OTHER", "name": "그 밖의 비용", "parent_code": "DIRECT_ACTIVITY", "cost_class": "DIRECT", "category_type": "LEGAL", "display_order": 151, "is_active": true}, {"code": "DIRECT_INNOVATION", "name": "연구혁신비", "parent_code": "DIRECT", "cost_class": "DIRECT", "category_type": "LEGAL", "display_order": 160, "is_active": true}, {"code": "DIRECT_INCENTIVE", "name": "연구수당", "parent_code": "DIRECT", "cost_class": "DIRECT", "category_type": "LEGAL", "display_order": 170, "is_active": true}, {"code": "DIRECT_SECURITY", "name": "보안수당", "parent_code": "DIRECT", "cost_class": "DIRECT", "category_type": "LEGAL", "display_order": 180, "is_active": true}, {"code": "DIRECT_SUBCONTRACT", "name": "위탁연구개발비", "parent_code": "DIRECT", "cost_class": "DIRECT", "category_type": "LEGAL", "display_order": 190, "is_active": true}, {"code": "DIRECT_INTERNATIONAL", "name": "국제공동연구개발비", "parent_code": "DIRECT", "cost_class": "DIRECT", "category_type": "LEGAL", "display_order": 200, "is_active": true}, {"code": "DIRECT_RND_CONTRIBUTION", "name": "연구개발부담비", "parent_code": "DIRECT", "cost_class": "DIRECT", "category_type": "LEGAL", "display_order": 210, "is_active": true}, {"code": "INDIRECT_HR_SUPPORT", "name": "인력지원비", "parent_code": "INDIRECT", "cost_class": "INDIRECT", "category_type": "LEGAL", "display_order": 300, "is_active": true}, {"code": "INDIRECT_RESEARCH_SUPPORT", "name": "연구지원비", "parent_code": "INDIRECT", "cost_class": "INDIRECT", "category_type": "LEGAL", "display_order": 310, "is_active": true}, {"code": "INDIRECT_OUTCOME_SUPPORT", "name": "성과활용지원비", "parent_code": "INDIRECT", "cost_class": "INDIRECT", "category_type": "LEGAL", "display_order": 320, "is_active": true}, {"code": "UI_EXISTING_LABOR_CASH", "name": "기존 인력 인건비", "parent_code": "DIRECT_LABOR", "cost_class": "DIRECT", "category_type": "UI_PROFILE", "display_order": 1001, "is_active": true}, {"code": "UI_NEW_HIRE_LABOR_CASH", "name": "신규채용 인건비", "parent_code": "DIRECT_LABOR", "cost_class": "DIRECT", "category_type": "UI_PROFILE", "display_order": 1002, "is_active": true}]
$categories$::jsonb)
as x(code text, name text, parent_code text, cost_class text,
     category_type text, display_order integer, is_active boolean)
on conflict (code) do update set
    name = excluded.name,
    parent_code = excluded.parent_code,
    cost_class = excluded.cost_class,
    category_type = excluded.category_type,
    display_order = excluded.display_order,
    is_active = excluded.is_active;

insert into regulation_articles
    (version_id, article_key, article_number, article_title, section,
     original_text, paragraph_start, paragraph_end, effective_from,
     effective_to, is_active)
select
    v.id, x.article_key, x.article_number, x.article_title, x.section,
    x.original_text, x.paragraph_start, x.paragraph_end, x.effective_from,
    x.effective_to, x.is_active
from regulation_versions v
cross join jsonb_to_recordset($articles$
[{"article_key": "MAIN_ART_1", "article_number": "1", "article_title": "목적", "section": "MAIN", "source_article": "제1조", "paragraph_start": 12, "paragraph_end": 12, "original_text": "제1조(목적) 이 고시는 「국가연구개발혁신법」(이하 \"법\"이라 한다) 제13조제4항에 따라 국가연구개발사업 연구개발비의 사용 기준 등 연구개발비에 관련한 사항을 정함을 목적으로 한다.", "effective_from": "2026-05-06", "effective_to": null, "is_active": true}, {"article_key": "MAIN_ART_2", "article_number": "2", "article_title": "정의", "section": "MAIN", "source_article": "제2조", "paragraph_start": 13, "paragraph_end": 43, "original_text": "제2조(정의) 이 기준에서 사용하는 용어의 뜻은 다음과 같다.\n1. \"연구개발과제\"란 법 제2조제2호에 따른 연구개발과제를 말한다.\n2. \"연구개발기관\"이란 법 제2조제3호에 따른 연구개발기관을 말한다.\n3. \"연구개발비\"란 연구개발과제의 연구개발비를 말한다.\n4. \"영리기관\"이란 「국가연구개발혁신법 시행령」(이하 \"영\"이라 한다) 제19조제1항 각 호에 따른 중소기업, 중견기업, 공기업(지방직영기업, 지방공사, 지방공단을 포함한다. 이하 같다) 및 대기업(중소기업, 중견기업 및 공기업이 아닌 기업을 말한다. 이하 같다)을 말한다.\n5. \"비영리기관\"이란 영리기관이 아닌 연구개발기관을 말한다.\n6. \"정부출연기관\"이란 다음 각 목의 어느 하나에 해당하는 다른 법률에 따라 직접 설립된 기관을 말한다.\n가.「정부출연연구기관 등의 설립ㆍ운영 및 육성에 관한 법률」제2조에 따른 정부출연연구기관 및 같은 법 제18조에 따른 연구회\n나.「과학기술분야 정부출연연구기관 등의 설립ㆍ운영 및 육성에 관한 법률」제2조에 따른 과학기술분야 정부출연연구기관 및 같은 법 제18조에 따른 연구회\n다.「특정연구기관 육성법」 제2조에 따른 특정연구기관\n라.「한국해양과학기술원법」에 따른 한국해양과학기술원\n마.「국방과학연구소법」에 따른 국방과학연구소\n바.「암관리법」 제27조제1항에 따른 국립암센터\n사.「지방자치단체출연 연구원의 설립 및 운영에 관한 법률」제2조에 따른 지방자치단체출연연구원\n7. \"대학\"이란 「고등교육법」 제2조에 따른 학교, 다른 법률에 따라 설치된 이에 준하는 교육기관, 평생교육시설 및 「산업교육진흥 및 산학협력 촉진에 관한 법률」 제25조에 따라 설립한 산학협력단을 말한다.\n8. \"연구비통합관리시스템\"이란 법 제20조에 따른 통합정보시스템 중 연구개발비의 정보를 처리하는 시스템으로서 「한국연구재단법」에 따라 설립된 한국연구재단이 운영하는 통합이지바로(통합Ezbaro)와 「산업기술혁신 촉진법」제39조제1항에 따라 설립된 한국산업기술기획평가원이 운영하는 통합알시엠에스(통합RCMS)를 말한다.\n9. \"간접비비율\"이란 연구개발과제의 전체 연구개발기간동안의 간접비를 직접비 중 현물 부담액과 위탁연구개발비, 국제공동연구개발비 및 연구개발부담비를 제외한 금액(이하 \"수정직접비\"라 한다)으로 나눈 값을 말한다.\n10. \"간접비고시비율\"이란 간접비비율을 정하기 위한 기준비율로서 제114조제2항부터 제5항까지에 따라 연구개발기관별로 정하는 비율을 말한다.\n11. \"참여연구자\"란 해당 연구개발과제에 참여하는 연구자(연구책임자 및 제14호에 따른 학생연구자를 포함한다)를 말한다.\n12. \"연구지원인력\"이란 법 제24조제2항제1호에 따른 연구지원인력을 말한다.\n13. \"정산\"이란 법 제11조제4항에 따라 연구개발과제의 협약이 해약되거나 법 제13조제7항에 따라 연구개발과제의 각 단계가 종료(연구개발과제가 단계로 구분되지 아니한 경우에는 연구개발과제의 종료를 말한다)되었을 때 연구개발기관이 사용한 연구개발비가 법 제13조제3항에 따른 연구개발비의 사용용도와 법 제13조제4항에 따른 연구개발비 사용 기준에 부합하게 사용되었는지를 확인하는 행위를 말한다.\n14. \"학생연구자\"란 영 별표 2 비고 제1호에 따른 학생연구자로 다음 각 목의 어느 하나에 해당하는 참여연구자를 말한다.\n가.「고등교육법」 등 관련 법률에 따라 운영하는 전문학사학위과정ㆍ학사학위과정ㆍ석사학위과정ㆍ학석사통합과정ㆍ박사학위과정ㆍ석박사통합과정 중에 있는 학생 신분의 연구자(연구생으로 등록한 수료생을 포함하며, 근로계약을 체결한 휴학생을 포함할 수 있다)\n나.가목의 학생연구자가 현행 학위과정을 졸업하여 상위 학위과정 진학이 확정된 경우 상위 학위과정의 첫 학기 시작 전까지 현행 학위과정 중 수행한 연구개발과제를 계속해서 수행하는 자\n15. \"4대보험\"이란 「국민연금법」에 따른 국민연금, 「국민건강보험법」에 따른 국민건강보험(「노인장기요양보험법」에 따른 장기요양보험을 포함한다), 「고용보험법」에 따른 고용보험, 「산업재해보상보험법」에 따른 산업재해보상보험을 말한다.\n16. \"연구기관출연금\"이란 정부출연기관의 기본사업의 수행을 위하여 「과학기술분야 정부출연연구기관 등의 설립ㆍ운영 및 육성에 관한 법률」 제5조제2항 및 「특정연구기관 육성법」 제3조제1항 등에 따라 정부가 반대급부 없이 예산이나 기금에서 연구개발기관에 지급하는 연구개발비를 말한다.\n17. \"학생인건비통합관리\"란 학생인건비 관리를 위한 별도 계정을 설정하여 하나 이상의 연구개발과제의 학생인건비를 통합관리하는 것을 말한다.\n18. \"학생인건비통합관리기관\"이란 제86조제1항에 따라 과학기술정보통신부장관이 지정하는 연구개발기관을 말한다.\n19. \"연구시설ㆍ장비비통합관리\"란 연구시설ㆍ장비비 관리를 위한 별도 계정을 설정하여 하나 이상의 연구개발과제의 연구시설ㆍ장비비를 통합관리하는 것을 말한다.\n20. \"연구시설ㆍ장비비통합관리기관\"이란 제100조제1항에 따라 과학기술정보통신부장관이 지정하는 연구개발기관을 말한다.\n21. \"원래계획\"이란 연구개발과제의 협약 체결 당시 연구개발계획서를 말한다. 단, 제73조제1항 각 호에 따라 중앙행정기관의 장의 사전 승인을 받아 연구개발비 사용계획이 변경된 경우에는 그 변경된 계획을 말한다.", "effective_from": "2026-05-06", "effective_to": null, "is_active": true}, {"article_key": "MAIN_ART_3", "article_number": "3", "article_title": "중앙행정기관의 책무", "section": "MAIN", "source_article": "제3조", "paragraph_start": 44, "paragraph_end": 44, "original_text": "제3조(중앙행정기관의 책무) 중앙행정기관(전문기관을 포함한다. 이하 같다)은 연구개발기관이 법, 영, 「국가연구개발혁신법 시행규칙」(이하 \"규칙\"이라 한다), 이 고시에서 정하는 연구개발비 사용과 관련된 규정을 준수할 수 있도록 안내하여야 하고, 연구개발 자율성이 보장될 수 있도록 이를 과도하게 해석하여 적용하여서는 아니 된다.", "effective_from": "2026-05-06", "effective_to": null, "is_active": true}, {"article_key": "MAIN_ART_4", "article_number": "4", "article_title": "연구개발기관의 책무", "section": "MAIN", "source_article": "제4조", "paragraph_start": 45, "paragraph_end": 48, "original_text": "제4조(연구개발기관의 책무) ① 연구개발기관은 법, 영, 규칙, 이 고시, 다른 법령 및 행정규칙, 협약 및 연구개발기관의 자체규정에서 정하는 연구개발비 사용과 관련된 규정에 따라 책임감 있고 투명하게 연구개발비를 사용하여야 한다.\n② 연구개발기관은 연구개발과제 참여연구자가 법, 영, 규칙, 이 고시에서 정하는 연구개발비 사용과 관련된 규정의 목적과 취지에 맞게 연구개발과제를 수행할 수 있도록 참여연구자를 체계적이고 전문적으로 지원하고, 연구개발 자율성이 보장될 수 있도록 이를 과도하게 해석하여 적용하여서는 아니 된다.\n제2장 연구개발비의 계상기준, 인정기준 및 사용절차\n제1절 사용용도", "effective_from": "2026-05-06", "effective_to": null, "is_active": true}, {"article_key": "MAIN_ART_5", "article_number": "5", "article_title": "직접비와 간접비의 사용용도", "section": "MAIN", "source_article": "제5조", "paragraph_start": 49, "paragraph_end": 50, "original_text": "제5조(직접비와 간접비의 사용용도) ① 법 제13조제3항제1호에 따른 직접비는 인건비, 학생인건비, 연구시설ㆍ장비비, 연구재료비, 연구활동비, 연구수당, 보안수당, 위탁연구개발비, 국제공동연구개발비, 연구개발부담비, 연구혁신비로 사용할 수 있다.\n② 법 제13조제3항제2호에 따른 간접비는 인력지원비, 연구지원비, 성과활용지원비로 사용할 수 있다.", "effective_from": "2026-06-11", "effective_to": null, "is_active": true}, {"article_key": "MAIN_ART_6", "article_number": "6", "article_title": "인건비 사용용도", "section": "MAIN", "source_article": "제6조", "paragraph_start": 51, "paragraph_end": 55, "original_text": "제6조(인건비 사용용도) 제5조제1항에 따른 인건비의 사용용도는 다음 각 호와 같다.\n1. 참여연구자가 해당 연구개발과제 수행에 참여하는 동안 해당 참여연구자에게 지급하는 급여(4대보험의 본인부담금을 포함한다)\n2. 비영리기관의 연구부서에 소속되어 해당 연구개발과제 수행을 지원하는 연구지원인력(이하 \"연구근접지원인력\"이라 한다)에게 지급하는 급여(4대보험의 본인부담금을 포함한다)\n3. 참여연구자가 해당 연구개발과제 수행에 참여하는 동안 해당 참여연구자에 대한 4대보험의 기관부담금 및 퇴직급여충당금\n4. 연구근접지원인력이 해당 연구개발과제 수행을 지원하는 동안 연구근접지원인력에 대한 4대보험의 기관부담금 및 퇴직급여충당금", "effective_from": "2026-05-06", "effective_to": null, "is_active": true}, {"article_key": "MAIN_ART_7", "article_number": "7", "article_title": "학생인건비 사용용도", "section": "MAIN", "source_article": "제7조", "paragraph_start": 56, "paragraph_end": 67, "original_text": "제7조(학생인건비 사용용도) 제5조제1항에 따른 학생인건비의 사용용도는 다음 각 호와 같다.\n1. 학생연구자에게 지급하는 다음 각 목의 어느 하나에 해당하는 인건비(학생연구자와 근로계약을 체결한 경우 4대보험의 본인부담금을 포함한다)\n가.다음의 어느 하나에 해당하는 연구개발기관(이하 \"대학등\"이라 한다)이 학생연구자에게 지급하는 인건비\n1) 법 제2조제3호나목의 대학\n2) 「특정연구기관 육성법 시행령」 제3조제1호부터 제3호까지 및 제3호의2에 따른 연구기관\n3) 「과학기술분야 정부출연연구기관 등의 설립ㆍ운영 및 육성에 관한 법률」 제33조제1항에 따른 대학원대학과 대학원대학을 설립할 수 있는 연구기관 및 같은 조 제3항에 따른 참여기관\n나.다음의 어느 하나에 해당하는 기관이 대학등 또는 외국대학과 계약을 체결하여 운영하는 학ㆍ연 협동과정을 통하여 연구개발과제에 참여하는 학생연구자 또는 외국대학 소속의 학생 신분의 연구자에게 지급하는 인건비\n1) 「정부출연연구기관 등의 설립ㆍ운영 및 육성에 관한 법률」제2조에 따른 정부출연연구기관\n2) 「과학기술분야 정부출연연구기관 등의 설립ㆍ운영 및 육성에 관한 법률」제2조에 따른 과학기술분야 정부출연연구기관\n3) 「특정연구기관 육성법 시행령」 제3조제4호부터 11호까지의 규정에 따른 연구기관\n다.나목1)부터 3)까지에 해당하는 연구개발기관에서 실시하는 6개월 이상의 연수프로그램을 통하여 연구개발과제에 참여하는 학생연구자에게 지급하는 인건비\n2. 제1호에 따른 학생인건비를 지급받는 학생연구자에 대한 4대보험의 기관부담금 및 퇴직급여충당금(근로계약을 체결하는 경우에만 해당한다)", "effective_from": "2026-05-06", "effective_to": null, "is_active": true}, {"article_key": "MAIN_ART_8", "article_number": "8", "article_title": "연구시설ㆍ장비비 사용용도", "section": "MAIN", "source_article": "제8조", "paragraph_start": 68, "paragraph_end": 72, "original_text": "제8조(연구시설ㆍ장비비 사용용도) 제5조제1항에 따른 연구시설ㆍ장비비의 사용용도는 다음 각 호와 같다.\n1. 연구시설ㆍ장비 구입ㆍ설치비: 연구개발과제 수행에 필요한 연구시설ㆍ장비의 구입ㆍ설치비, 관련 부대 비용 또는 성능향상비\n2. 연구시설ㆍ장비 임차비: 연구개발과제 수행에 필요한 연구시설ㆍ장비의 임차비\n3. 연구시설ㆍ장비 운영ㆍ유지비: 유지ㆍ보수비, 운영비 또는 이전 설치비(연구시설ㆍ장비를 다른 기관으로부터 이전받거나 같은 기관 내의 공동활용시설로 이전ㆍ설치하는 비용을 포함한다)\n4. 연구인프라 조성비: 연구인프라 조성을 목적으로 하는 국가연구개발사업의 연구인프라 부지ㆍ시설의 매입ㆍ임차ㆍ조성비, 설계ㆍ건축ㆍ감리비 또는 장비 구입ㆍ설비비(연구개발과제의 목표 달성을 위하여 기획, 설계, 건설, 완공 후 운영 등 추진과정의 전부 또는 일부에 대하여 자문 또는 관리를 수행하는 종합사업관리 추진비용을 포함한다)", "effective_from": "2026-05-06", "effective_to": null, "is_active": true}, {"article_key": "MAIN_ART_9", "article_number": "9", "article_title": "연구재료비 사용용도", "section": "MAIN", "source_article": "제9조", "paragraph_start": 73, "paragraph_end": 76, "original_text": "제9조(연구재료비 사용용도) 제5조제1항에 따른 연구재료비의 사용용도는 다음 각 호와 같다.\n1. 연구재료 구입비: 시약ㆍ재료 구입비 및 관련 부대비용\n2. 연구개발과제 관리비: 연구개발과제 수행을 위하여 필요한 관리시스템 등의 운영비\n3. 연구재료 제작비: 시험제품ㆍ시험설비 제작(자체제작과 외부제작을 모두 포함한다)비용", "effective_from": "2026-05-06", "effective_to": null, "is_active": true}, {"article_key": "MAIN_ART_10", "article_number": "10", "article_title": "연구활동비 사용용도", "section": "MAIN", "source_article": "제10조", "paragraph_start": 77, "paragraph_end": 88, "original_text": "제10조(연구활동비 사용용도) 제5조제1항에 따른 연구활동비의 사용용도는 다음 각 호와 같다.\n1. 지식재산 창출 활동비: 기술ㆍ특허ㆍ표준 정보 조사ㆍ분석, 원천ㆍ핵심특허 확보전략 수립 등 지식재산 창출 활동에 필요한 비용\n2. 외부 전문기술 활용비(국외에 소재한 기관 또는 외국인의 전문기술 활용을 위하여 지급하는 비용을 포함한다): 기술도입비, 전문가 활용비(원고료, 강사료, 자문료 등을 포함한다), 연구개발서비스 활용비 등 외부 전문기술 활용을 위하여 필요한 비용\n3. 회의비: 회의장 임차료, 속기료, 통역료 또는 회의비 등 연구개발과제 수행을 위하여 필요한 회의ㆍ세미나 개최 비용\n4. 출장비: 연구개발과제 수행을 위한 국내외 출장 비용(연구개발과제 수행을 위해 파견 또는 전보되는 인력에 대한 파견ㆍ전보ㆍ주거 관련 지원 비용을 포함한다)\n5. 소프트웨어 활용비: 연구개발과제 수행을 위한 소프트웨어의 구입ㆍ설치ㆍ임차ㆍ사용대차 비용 또는 데이터베이스ㆍ네트워크의 이용료\n6. 클라우드컴퓨팅서비스 활용비: 연구개발과제 수행을 위한 클라우드컴퓨팅서비스의 이용료\n7. 연구실운영비: 연구개발과제 수행을 위하여 필요한 사무용 기기 및 사무용 소프트웨어의 구입ㆍ설치ㆍ임차ㆍ사용대차 비용, 사무용품비, 연구실 운영에 필요한 소모성 비용 또는 연구실 냉난방 및 청결한 환경 유지를 위하여 필요한 기기ㆍ비품의 구입ㆍ유지 비용\n8. 연구인력 지원비: 연구개발과제 수행과 직접 관련된 교육ㆍ훈련 비용, 학회ㆍ세미나 참가비 또는 연구개발과제 수행을 위하여 지출된 야근(특근) 식대\n9. 해외 연구자 유치 지원비 : 외국에 소재한 정부ㆍ기관ㆍ단체에 소속된 연구자 등 연구개발과제 관련 전문성을 갖춘 연구자에게 지급하는 장려금, 체재비 등 해외 연구자의 국내 유치에 필요한 비용\n10. 종합사업관리비 : 연구인프라 조성을 목적으로 하는 사업의 목표 달성을 위한 기획ㆍ조정 또는 추진과정에 대한 자문이나 관리 비용\n11. 그 밖의 비용 : 문헌구입비, 논문 게재료, 인쇄ㆍ복사ㆍ인화비, 슬라이드 제작비, 각종 세금 및 공과금, 우편요금, 택배비, 수수료, 공공요금, 일용직(연구실증 참여자 등 연구개발과제 수행을 위하여 활용된 사람을 포함한다) 활용비 등 연구개발과제와 직접 관련있는 그 밖의 비용", "effective_from": "2026-05-06", "effective_to": null, "is_active": true}, {"article_key": "MAIN_ART_10_2", "article_number": "10의2", "article_title": "연구혁신비 사용용도", "section": "MAIN", "source_article": "제10의2조", "paragraph_start": 89, "paragraph_end": 89, "original_text": "제10조의2(연구혁신비 사용용도) 제5조제1항에 따른 연구혁신비의 사용용도는 연구개발기관의 효율적인 연구개발과제 수행을 위하여 필요한 비용으로서 제9조 또는 제10조(외부 전문기술 활용비는 제외한다)에 해당하는 비용을 말한다.", "effective_from": "2026-06-11", "effective_to": null, "is_active": true}, {"article_key": "MAIN_ART_11", "article_number": "11", "article_title": "연구수당 사용용도", "section": "MAIN", "source_article": "제11조", "paragraph_start": 90, "paragraph_end": 90, "original_text": "제11조(연구수당 사용용도) 제5조제1항에 따른 연구수당의 사용용도는 연구개발과제 수행에 참여하는 연구책임자 및 연구자(학생연구자를 포함한다)를 대상으로 지급하는 장려금으로 한다.", "effective_from": "2026-05-06", "effective_to": null, "is_active": true}, {"article_key": "MAIN_ART_11_2", "article_number": "11의2", "article_title": "보안수당 사용용도", "section": "MAIN", "source_article": "제11의2조", "paragraph_start": 91, "paragraph_end": 91, "original_text": "제11조의2(보안수당 사용용도) 제5조제1항에 따른 보안수당의 사용용도는 영 제45조에 따른 보안과제 수행에 참여하는 연구책임자, 연구자(학생연구자를 포함한다) 및 연구근접지원인력을 대상으로 지급하는 장려금으로 한다.", "effective_from": "2026-05-06", "effective_to": null, "is_active": true}, {"article_key": "MAIN_ART_12", "article_number": "12", "article_title": "위탁연구개발비 사용용도", "section": "MAIN", "source_article": "제12조", "paragraph_start": 92, "paragraph_end": 92, "original_text": "제12조(위탁연구개발비 사용용도) 제5조제1항에 따른 위탁연구개발비의 사용용도는 주관연구개발기관이 연구개발과제의 일부를 위탁할 때 위탁연구개발기관에 지급하는 비용으로 한다.", "effective_from": "2026-05-06", "effective_to": null, "is_active": true}, {"article_key": "MAIN_ART_13", "article_number": "13", "article_title": "국제공동연구개발비 사용용도", "section": "MAIN", "source_article": "제13조", "paragraph_start": 93, "paragraph_end": 93, "original_text": "제13조(국제공동연구개발비 사용용도) 제5조제1항에 따른 국제공동연구개발비의 사용용도는 연구개발과제협약으로 정하는 바에 따라 중앙행정기관의 장의 승인을 받아 외국에 소재한 기관 또는 외국인과 공동으로 연구를 수행하는 경우에 그 기관 또는 외국인에게 지급하는 비용으로 한다.", "effective_from": "2026-05-06", "effective_to": null, "is_active": true}, {"article_key": "MAIN_ART_14", "article_number": "14", "article_title": "연구개발부담비 사용용도", "section": "MAIN", "source_article": "제14조", "paragraph_start": 94, "paragraph_end": 96, "original_text": "제14조(연구개발부담비 사용용도) 제5조제1항에 따른 연구개발부담비의 사용용도는 다음 각 호와 같다.\n1. 법률로 직접 설립된 연구개발기관이 영 제19조제4항 각 호에 해당하는 연구개발과제를 수행하는 경우 법 제4조에 따른 기본사업 연구개발비에서 부담하는 비용\n2. 법률로 직접 설립된 연구개발기관이 법 제4조에 따른 기본사업 연구개발과제를 수행하기 위하여 연구개발과제협약으로 정하는 바에 따라 다른 연구개발기관에 지급하는 비용", "effective_from": "2026-05-06", "effective_to": null, "is_active": true}, {"article_key": "MAIN_ART_15", "article_number": "15", "article_title": "영리기관의 인력지원비 사용용도", "section": "MAIN", "source_article": "제15조", "paragraph_start": 97, "paragraph_end": 108, "original_text": "제15조(영리기관의 인력지원비 사용용도) 제5조제2항에 따른 영리기관의 인력지원비의 사용용도는 다음 각 호와 같다.\n1. 연구지원인력 인건비\n2. 우수한 연구자 및 연구지원인력에게 지급하는 연구개발능률성과급\n3. 삭제\n가.삭제\n나.삭제\n4. 삭제\n가.삭제\n나.삭제\n다.삭제\n라.삭제\n5. 참여연구자 또는 연구지원인력의 「남녀고용평등과 일ㆍ가정 양립 지원에 관한 법률」제19조에 따른 육아휴직 기간동안의 4대보험의 기관부담금 및 퇴직급여충당금", "effective_from": "2026-05-06", "effective_to": null, "is_active": true}, {"article_key": "MAIN_ART_15_2", "article_number": "15의2", "article_title": "비영리기관의 인력지원비 사용용도", "section": "MAIN", "source_article": "제15의2조", "paragraph_start": 109, "paragraph_end": 111, "original_text": "제15조의2(비영리기관의 인력지원비 사용용도) 제5조제2항에 따른 인력지원비는 제15조 각 호의 비용 및 이와 유사한 비용으로서 연구개발과제 수행을 위해 연구개발기관이 연구자 또는 연구지원인력에게 지급하는 인건비 관련 비용을 말한다. 다만, 다음 각 호의 어느 하나에 해당하는 비용은 인력지원비로 사용할 수 없다.\n1. 대학에 소속된 「고등교육법」 제14조제2항에 따른 교원 또는 과제에서 이미 인건비를 지급받는 연구자 또는 연구근접지원인력의 인건비\n2. 학생연구자에게 지급되는 우수학생장학금, 근로장학금", "effective_from": "2026-05-06", "effective_to": null, "is_active": true}, {"article_key": "MAIN_ART_16", "article_number": "16", "article_title": "영리기관의 연구지원비 사용용도", "section": "MAIN", "source_article": "제16조", "paragraph_start": 112, "paragraph_end": 127, "original_text": "제16조(영리기관의 연구지원비 사용용도) 제5조제2항에 따른 영리기관의 연구지원비의 사용용도는 다음 각 호와 같다.\n1. 기관 공통 비용 : 연구개발수행을 위해 필요한 기관 공통 경비\n2. 사업단 운영비 : 연구개발과제의 효율적인 수행을 위하여 전문적인 과제관리를 위한 사업단ㆍ연구단 등이 운영되는 경우 그 운영비용 및 비품 구입 비용\n3. 기반시설ㆍ장비 구축ㆍ운영비 : 연구개발 관련 기반시설 및 장비 운영에 필요한 다음의 비용 중 직접비로 계상되지 않는 비용\n가.삭제\n나.삭제\n다.클라우드컴퓨팅서비스 활용비\n4. 연구실안전관리비 : 「연구실 안전환경 조성에 관한 법률」 제22조제3항에 따라 확보해야 할 연구실의 안전 및 유지관리에 필요한 비용\n5. 삭제\n6. 연구보안관리비 : 연구개발과제 수행과 관련한 다음 각 목의 비용\n가.보안장비 구입, 보안교육, 보안취약점 진단, 보안사고 대응 지원 또는 보안컨설팅 등 연구보안 활동 관련 비용\n나.「대ㆍ중소기업 상생협력 촉진에 관한 법률」 제24조의2에 따른 기술자료 임치 관련 비용\n다.「산업기술의 유출방지 및 보호에 관한 법률」 제10조제1항에 따른 국가핵심기술의 보호조치 관련 비용\n라.그 밖에 연구개발과제 보안을 위한 비용\n7. 연구윤리활동비 : 연구윤리규정 제정ㆍ운영, 연구윤리 교육 또는 연구윤리 인식확산 활동 등 연구윤리 확립 및 연구부정행위 예방 등과 관련된 연구윤리활동 비용\n8. 삭제", "effective_from": "2026-05-06", "effective_to": null, "is_active": true}, {"article_key": "MAIN_ART_16_2", "article_number": "16의2", "article_title": "비영리기관의 연구지원비 사용용도", "section": "MAIN", "source_article": "제16의2조", "paragraph_start": 128, "paragraph_end": 130, "original_text": "제16조의2(비영리기관의 연구지원비 사용용도) 제5조제2항에 따른 연구지원비는 제16조 각 호의 비용 및 이와 유사한 비용으로서 연구개발과제 수행을 위해 필요한 연구시설ㆍ장비 구축ㆍ운영 또는 연구환경 유지를 위한 비용을 말한다. 다만, 다음 각 호의 어느 하나에 해당하는 비용은 연구지원비로 사용할 수 없다\n1. 연구개발과제 수주에 대한 보상으로 지급하는 비용\n2. 「건축법」 및 「건축법 시행령」 등에 따른 건축물의 신축, 증축, 개축이나 리모델링 등을 위한 비용", "effective_from": "2026-05-06", "effective_to": null, "is_active": true}, {"article_key": "MAIN_ART_17", "article_number": "17", "article_title": "영리기관의 성과활용지원비 사용용도", "section": "MAIN", "source_article": "제17조", "paragraph_start": 131, "paragraph_end": 142, "original_text": "제17조(영리기관의 성과활용지원비 사용용도) 제5조제2항에 따른 영리기관의 성과활용지원비의 사용용도는 다음 각 호와 같다.\n1. 과학문화활동비 : 과학기술문화 확산에 관련된 다음 각 목의 활동 비용\n가.연구개발과 관련된 홍보를 위한 과학홍보물 및 행사프로그램\n나.강연ㆍ체험활동 및 연구실 개방\n다.홍보전문가 양성\n라.그 밖에 과학기술 문화 확산에 관련된 활동\n2. 지식재산권 출원ㆍ등록비 : 다음 각 목에 해당하는 비용\n가.연구개발기관에서 수행하는 국가연구개발사업과 관련된 지식재산권의 출원ㆍ등록ㆍ유지에 필요한 모든 비용\n나.기술가치평가 등 기술이전에 필요한 비용\n다.표준 활동에 필요한 비용\n라.연구노트의 작성ㆍ관리에 관한 자체 규정 제정ㆍ운영 또는 연구노트 교육ㆍ인식확산 활동, 그 밖에 연구노트 활성화 등에 관련된 비용\n3. 삭제", "effective_from": "2026-05-06", "effective_to": null, "is_active": true}, {"article_key": "MAIN_ART_17_2", "article_number": "17의2", "article_title": "비영리기관의 성과활용지원비 사용용도", "section": "MAIN", "source_article": "제17의2조", "paragraph_start": 143, "paragraph_end": 144, "original_text": "제17조의2(비영리기관의 성과활용지원비 사용용도) 제5조제2항에 따른 성과활용지원비는 제17조 각 호의 비용 및 이와 유사한 비용으로서 연구개발과 관련된 과학기술문화 확산을 위한 홍보 및 지식재산권 출원ㆍ등록, 연구성과 활용을 지원하기 위한 비용을 말한다.\n제2절 공통 계상기준 및 인정기준", "effective_from": "2026-05-06", "effective_to": null, "is_active": true}, {"article_key": "MAIN_ART_18", "article_number": "18", "article_title": "연구개발비 사용계획 수립", "section": "MAIN", "source_article": "제18조", "paragraph_start": 145, "paragraph_end": 147, "original_text": "제18조(연구개발비 사용계획 수립) ① 연구개발과제 공모에 참여하려는 기관ㆍ단체는 연구개발비 사용에 대한 개괄적인 계획을 수립하고, 이를 영 제9조제2항에 따른 연구개발계획서에 포함하여 중앙행정기관의 장에게 제출하여야 한다. 다만, 하나의 연구개발과제에 다수의 기관ㆍ단체가 참여하려는 경우에는 주관연구개발기관으로 참여하려는 기관ㆍ단체가 각 기관ㆍ단체의 연구개발계획서를 종합하여 제출할 수 있다.\n② 연구개발기관은 연구개발과제 선정평가에 따라 연구개발비 규모가 조정된 경우(하나의 연구개발과제에 다수의 연구개발기관이 참여할 때에 연구개발비 총액의 변동 없이 연구개발기관 간 연구개발비가 조정된 경우를 포함한다)에 그 조정된 내역을 반영하여 연구개발비 사용에 대한 개괄적인 계획을 다시 수립하고, 이를 영 제12조제6항에 따라 보완된 연구개발계획서에 포함하여 중앙행정기관의 장에게 제출하여야 한다. 다만, 하나의 연구개발과제에 다수의 연구개발기관이 참여하는 경우에는 주관연구개발기관이 각 연구개발기관의 연구개발계획서를 종합하여 제출할 수 있다.\n③ 이 고시에 따라 중앙행정기관의 장의 인정을 받아 계상할 수 있는 연구개발비를 계상하려는 연구개발기관의 장은 제1항 및 제2항에 따른 연구개발계획서를 제출할 때 별지 제21호 서식을 작성하여 함께 제출하여야 한다.", "effective_from": "2026-05-06", "effective_to": null, "is_active": true}, {"article_key": "MAIN_ART_19", "article_number": "19", "article_title": "연구개발비 지급", "section": "MAIN", "source_article": "제19조", "paragraph_start": 148, "paragraph_end": 149, "original_text": "제19조(연구개발비 지급) ① 중앙행정기관의 장은 연구개발기관에 연구개발비를 일시불 또는 협약으로 정한 시점에 분할하여 지급(이하 \"일괄지급\"이라 한다)하거나 연구개발기관이 연구개발비 일부의 사용을 위하여 지급을 신청하는 금액을 연구개발기관에 건별로 지급(이하 \"건별지급\"이라 한다)할 수 있다.\n② 중앙행정기관의 장은 연구개발기관에 연구개발비를 지급하기 이전에 연구개발비 지급 및 관리를 위한 연구비통합관리시스템 유형을 결정하여 통보하여야 하며, 연구비통합관리시스템으로 연구개발비를 지급하지 아니하는 경우에는 별도의 지급방법을 정하여 통보하여야 한다.", "effective_from": "2026-05-06", "effective_to": null, "is_active": true}, {"article_key": "MAIN_ART_20", "article_number": "20", "article_title": "연구개발비 지급 등의 대행", "section": "MAIN", "source_article": "제20조", "paragraph_start": 150, "paragraph_end": 150, "original_text": "제20조(연구개발비 지급 등의 대행) 중앙행정기관의 장은 법 제22조제1항에 따라 제34조제2항, 제45조, 제52조, 제60조제2항에 따른 연구개발비를 납부받는 업무와 제35조, 제45조, 제53조, 제61조에 따른 연구개발비를 지급하는 업무를 연구비통합관리시스템을 운영하는 한국연구재단 또는 한국산업기술기획평가원(이하 \"연구비관리전담기관\"이라 한다 )이 대행하도록 할 수 있다.", "effective_from": "2026-05-06", "effective_to": null, "is_active": true}, {"article_key": "MAIN_ART_21", "article_number": "21", "article_title": "연구개발비 공통 계상기준", "section": "MAIN", "source_article": "제21조", "paragraph_start": 151, "paragraph_end": 173, "original_text": "제21조(연구개발비 공통 계상기준) ① 연구개발기관의 장은 직접비로 해당 연구개발과제 수행에 필요한 금액을 계상하여야 한다.\n② 연구개발기관의 장은 간접비로 여러 연구개발과제 수행에 공통적으로 소요되는 비용으로서 필요한 금액을 계상하여야 한다.\n③ 연구개발기관의 장은 제1항ㆍ제2항에 따른 계상이 필요한 금액을 산출하기 어려운 경우, 연구개발비 사용에 관한 자체규정에 따라 해당 금액을 계상하여야 한다. 이 경우 자체규정에 따라 국가연구개발사업에 적용되는 금액이 그 외의 경우에 적용되는 금액보다 높아서는 아니 된다.\n④ 연구개발기관의 장은 연구개발비로 다음 각 호에 해당하는 비용을 계상하여서는 아니 된다.\n1. 환급받을 수 있는 관세, 부가가치세 등에 해당하는 금액(실제 환급받지 아니한 경우에도 해당한다)\n2. 주류 등 유흥성 비용\n3. 다음 각 목의 어느 하나에 해당하는 중복계상으로 발생하는 비용\n가.동일한 비용을 2회 이상 중복계상\n나.동일한 비용을 현금과 현물로 중복계상\n다.동일한 비용을 직접비와 간접비로 중복계상\n4. 하나의 연구개발과제에서 동일한 참여연구자에게 인건비와 학생인건비를 동일기간에 계상하여 발생하는 비용(참여연구자의 입학, 졸업 등 신분상 변동이 있는 경우에는 제외한다)\n5. 연구개발기관 내부 및 하나의 연구개발과제를 수행하는 연구개발기관 간 발생하는 비용(다음 각 목의 어느 하나에 해당하는 비용은 제외한다)\n가.대학이 같은 대학 내 별도의 사업자가 운영하는 회의장, 숙박시설 등 부대시설을 사용하는 데 필요한 비용\n나.동일한 연구개발기관 내 계좌이체 또는 계정대체하거나 하나의 연구개발과제를 수행하는 연구개발기관 간 계좌이체 또는 계정대체한 비용 중 다음의 어느 하나에 해당하는 비용\n1) 비영리기관이 공동활용을 위하여 구축한 연구시설ㆍ장비를 사용하는 데 필요한 비용\n2) 연구개발과제 수행 중 시험ㆍ검사ㆍ분석에 필요한 비용 중 다음의 어느 하나에 해당하는 비용\n가) 연구개발기관이 자체 분석기관에서 인정하는 시험분석결과서를 발행하고, 그 비용을 분석기관으로 계정대체하는 경우 해당 금액을 현금으로 계상한 비용\n나) 가)에 해당하지 아니하는 비용으로서 영리기관인 연구개발기관이 현물로 계상하는 비용\n3) 비영리기관 내 중앙창고를 두어 물품을 구매하고, 그 후 필요한 금액을 이체 또는 계정대체하는 비용\n4) 단독 판매처 등의 정당한 사유로 중앙행정기관의 장이 인정하는 경우 해당 금액을 현금으로 계상한 비용\n다.정부가 출연하여 설립ㆍ운영하는 연구개발기관과 그 연구개발기관의 분원 간 발생하는 비용(중앙행정기관의 장이 인정하는 경우에만 해당한다)\n6. 영리기관으로서 계열사 등으로 법인이 분리되어 있으나 인적ㆍ물적 구분이 명확하지 아니한 계열사 또는 기관 간 발생하는 비용\n7. 중앙행정기관의 장이 인정하지 아니한 연구개발기관 내부 연구공간 및 외부 연구공간에 대한 임차료", "effective_from": "2026-05-06", "effective_to": null, "is_active": true}, {"article_key": "MAIN_ART_22", "article_number": "22", "article_title": "연구개발비 공통 인정기준", "section": "MAIN", "source_article": "제22조", "paragraph_start": 174, "paragraph_end": 182, "original_text": "제22조(연구개발비 공통 인정기준) ① 연구개발기관의 장은 연구개발비를 계상한 바에 따라 사용하여야 한다.\n② 연구개발기관의 장은 연구개발비 사용(재난, 재해, 그 밖에 경제적ㆍ사회적으로 중대한 사유 발생에 따라 물품 및 서비스를 위한 계약이 취소ㆍ변경되어 수수료 등 부대비용이 발생하여 사용한 것을 포함한다)을 입증할 증명자료를 갖추어야 한다.\n③ 연구개발기관의 장은 연구시설ㆍ장비와 연구재료(연구활동비 또는 간접비로 구매하는 경우를 포함한다. 이하 이 조에서 같다)를 구매하는 경우 자체규정에 따라 구매ㆍ검수하여야 한다. 다만, 법 제2조제3호나목, 라목 및 바목의 연구개발기관의 장은 100만 원 이하의 연구재료를 구매하는 경우(연차별 1,000만 원 이내로 한한다) 검수 절차를 간소화하고 검수확인서 외에 추가적인 증명자료를 갖추지 않는 것으로 자체규정을 마련할 수 있다.\n④ 연구개발기관의 장은 연구개발비를 연구개발기간 종료일 이전에 사용하여야 한다. 다만, 다음 제1호부터 제3호에 해당하는 비용에 대하여는 영 제26조제1항에 따른 연구개발비 사용실적 보고일까지 사용할 수 있으며, 제4호에 해당하는 비용에 대하여는 중앙행정기관의 장이 인정하는 경우에는 연구개발기간 종료일부터 2년 후까지 사용할 수 있다.\n1. 보고서 발간 및 평가 관련 비용(시험분석결과서 발행 비용 포함), 정산 수수료, 공공요금, 제세공과금\n2. 연구수당\n3. 연구개발기간 종료일 이전에 지출원인행위한 금액(연구개발기간 중 사용한 소프트웨어의 후불지급 사용액을 포함한다)\n4. 논문게재료, 저술출판비용\n⑤ 연구개발기관의 장은 직접비를 사용할 때에 연구비카드를 사용(연구비카드를 발급받기 전에 법인명의의 카드를 사용한 것을 포함한다)하거나 계좌이체의 형태로 사용하여야 한다. 다만, 외국 물품의 수입 등 연구비카드를 사용하거나 계좌이체의 형태로 사용할 수 없는 경우에 한하여 지폐나 주화를 사용할 수 있다.", "effective_from": "2026-05-06", "effective_to": null, "is_active": true}, {"article_key": "MAIN_ART_23", "article_number": "23", "article_title": "연구시설ㆍ장비비 공통 사용기준", "section": "MAIN", "source_article": "제23조", "paragraph_start": 183, "paragraph_end": 193, "original_text": "제23조(연구시설ㆍ장비비 공통 사용기준) ① 제21조제1항에도 불구하고 연구개발기관의 장은 연구개발기관이 보유 또는 생산하여 자산으로 등록하는 연구시설ㆍ장비에 대하여는 구입가로 계상하여야 한다.\n② 연구개발기관의 장은 제73조제1항제5호 각 목의 어느 하나에 해당하는 경우에는 중앙행정기관의 장의 사전 승인을 거쳐 협약을 변경한 후 해당 연구시설ㆍ장비비를 사용하여야 한다.\n③ 연구개발기관의 장은 1억 원 이상(부가가치세 및 구입ㆍ설치 등에 필요한 부대비용을 포함)의 연구시설ㆍ장비를 구입하려는 경우에 「국가연구개발 시설ㆍ장비의 관리 등에 관한 표준지침」에서 정하는 바에 따라 필요한 비용을 사용하여야 한다.\n④ 연구개발기관의 장은 취득가격이 3천만 원 이상(부가가치세 및 구입ㆍ설치 등에 필요한 부대비용을 포함)인 연구시설ㆍ장비 또는 3천만 원 미만이라도 공동활용이 가능한 연구시설ㆍ장비는 「과학기술기본법 시행령」 제42조제4항제2호에 따른 연구개발 시설ㆍ장비 종합정보시스템(이하 \"연구시설ㆍ장비종합정보시스템(ZEUS)\"라 한다)에 등록된 연구시설ㆍ장비의 공동활용여부를 확인한 후 필요한 경우 「국가연구개발 시설ㆍ장비의 관리 등에 관한 표준지침」에서 정하는 바에 따라 필요한 비용을 계상하여야 한다.\n⑤ 연구개발기관의 장은 기관 단위 연구시설ㆍ장비의 통합구축ㆍ운영을 위하여 필요한 비용을 연구개발과제별로 안분할 수 있다.\n⑥ 연구개발기관의 장은 연구시설ㆍ장비에 대하여 다음 각 호의 기간 내에 구입ㆍ설치 또는 임차를 완료한 경우에 해당 연구시설ㆍ장비비를 계상할 수 있다.\n1. 연구시설ㆍ장비 구축을 주된 목적으로 하는 연구개발과제로서 중앙행정기관의 장이 인정하는 경우: 연구개발과제(연구개발과제가 단계로 구분된 경우에는 해당 단계를 말한다. 이하 이 항에서 같다)의 종료일\n2. 다른 법률에 따라 직접 설립된 기관의 기본사업 연구개발과제를 수행하는 경우 : 연구개발과제의 종료일\n3. 재난, 재해, 그 밖에 경제적ㆍ사회적으로 중대한 사유가 발생하여 중앙행정기관의 장이 인정하는 경우: 연구개발과제의 종료일 1개월 전\n4. 제1호부터 제3호에 해당하지 아니하는 경우: 연구개발과제의 종료일 2개월 전\n⑦ 제5항 각 호에도 불구하고 중앙행정기관의 장이 인정하는 경우에는 연구시설ㆍ장비의 구축이 완료되는 단계의 종료일을 제5항 각호에 따른 연구개발과제의 종료일로 적용할 수 있다.", "effective_from": "2026-05-06", "effective_to": null, "is_active": true}, {"article_key": "MAIN_ART_24", "article_number": "24", "article_title": "연구재료비 공통 사용기준", "section": "MAIN", "source_article": "제24조", "paragraph_start": 194, "paragraph_end": 194, "original_text": "제24조(연구재료비 공통 사용기준) 제21조제1항에도 불구하고 연구개발기관의 장은 연구개발기관이 보유 또는 생산하여 자산으로 등록하는 시험제품ㆍ시험설비에 대하여는 구입가로 계상하여야 한다.", "effective_from": "2026-05-06", "effective_to": null, "is_active": true}, {"article_key": "MAIN_ART_25", "article_number": "25", "article_title": "연구활동비 공통 사용기준", "section": "MAIN", "source_article": "제25조", "paragraph_start": 195, "paragraph_end": 230, "original_text": "제25조(연구활동비 공통 사용기준) ① 제10조제1호에 따른 지식재산 창출 활동비에 제17조제2호가목에 따른 연구개발기관에서 수행하는 국가연구개발사업과 관련된 지식재산권의 출원ㆍ등록ㆍ유지에 필요한 비용은 제외한다.\n② 연구개발기관의 장은 외부 전문기술 활용비를 직접비의 40퍼센트 범위에서 다음 각 호에 따라 사용하여야 한다. 다만, 중앙행정기관의 장이 연구개발과제의 특성을 감안하여 필요하다고 인정하는 경우에는 직접비의 40퍼센트를 초과하여 사용할 수 있다.\n1. 기술도입비: 연구개발기관의 자체규정에 따라 해당 기술을 도입하는 데 실제 필요한 비용을 계상\n2. 전문가활용비: 다음 각 목에 따라 계상\n가.연구개발기관의 자체규정이 있는 경우: 그 자체규정에 따라 계상\n나.연구개발기관의 자체규정이 없는 경우: 실제 필요한 금액으로 계상\n3. 연구개발서비스 활용비: 연구개발기관의 자체규정에 따라 해당 연구개발서비스를 활용하는 데 실제 필요한 비용을 계상\n③ 삭제\n④ 연구개발기관의 장은 해당 연구개발과제의 참여연구자만 참여하는 회의에 대하여는 회의비 중 식비를 계상하여서는 아니 된다.\n⑤ 연구개발기관의 장은 회의비를 사용할 때에는 내부결재문서 또는 회의록 중 어느 하나와 영수증서를 갖추어야 한다. 다만, 10만 원(부가가치세를 포함한다) 이하의 회의비를 사용하는 경우에는 회의의 목적, 일시, 장소, 내용, 참석자 명단이 기재된 증명자료로 내부결재문서 또는 회의록을 대신할 수 있다.\n⑥ 연구개발기관의 장은 출장비를 다음 각 호에 따라 계상하여야 하며, 연구개발과제 수행을 위해 소속기관 이외의 기관으로 파견 또는 소속기관으로 전보되는 인력에 대한 파견ㆍ전보ㆍ주거 관련 지원 비용을 계상하려는 경우에는 중앙행정기관의 장의 인정을 받아야 한다.\n1. 참여연구자ㆍ연구근접지원인력이 공무원인 경우: 「공무원 여비 규정」에 따라 계상\n2. 참여연구자ㆍ연구근접지원인력이 공무원이 아닌 경우: 연구개발기관의 자체규정 또는 「공무원 여비 규정」중 선택하여 계상\n⑦ 출장지 관계기관에서 식대 또는 식사를 제공하는 경우에는 출장비에서 해당 금액을 차감하고 계상하여야 한다.\n⑧ 연구개발기관의 장은 출장비 중 국외 출장비를 사용하려는 때에는 출장계획서를 갖추어야 하고, 국외 출장비를 사용한 때에는 출장결과보고서를 갖추어야 한다.\n⑨ 연구개발기관의 장은 다음 각 호의 기간 내에 사용계약을 체결하는 소프트웨어(데이터베이스와 네트워크를 포함한다)에 대하여 제10조제5호의 소프트웨어 활용비를 계상할 수 있다.\n1. 법 제4조에 해당하는 사업의 경우: 연구개발과제(연구개발과제가 단계로 구분된 경우에는 해당 단계를 말한다. 이하 이 조에서 같다)의 종료일\n2. 재난, 재해, 그 밖에 경제적ㆍ사회적으로 중대한 사유가 발생하여 중앙행정기관의 장이 인정하는 경우: 연구개발과제의 종료일 1개월 전\n3. 제1호 및 제2호에 해당하지 아니하는 경우: 연구개발과제의 종료일 2개월 전\n⑩ 연구개발기관의 장은 소프트웨어(데이터베이스와 네트워크를 포함한다) 사용계약기간이 연구개발과제의 연구개발기간을 초과하더라도 소프트웨어 사용계약기간이 최소 단위임을 소명하는 경우에는 소프트웨어 활용비를 해당 사용계약기간에 대한 계약금액 전부로 계상할 수 있다.\n⑪ 연구개발기관의 장이 클라우드컴퓨팅서비스 활용비 중 정액제를 사용하려는 경우에는 제9항, 제10항을 준용한다. 이 경우 \"소프트웨어\"는 \"클라우드컴퓨팅서비스\"로 본다.\n⑫ 연구개발기관의 장은 클라우드컴퓨팅서비스 활용비를 계상하려는 경우에 「클라우드컴퓨팅 발전 및 이용자 보호에 관한 법률 시행령」제8조의2 제3항에 따라 구축하여 운영되는 이용지원시스템을 확인한 후, 클라우드컴퓨팅서비스를 선정하고 필요한 비용을 계상하여야 한다.\n⑬ 연구개발기관의 장은 연구실운영비를 사용할 때에 연구개발기관 자체규정에 따라 사용하여야 한다.\n⑭ 연구개발기관의 장은 다음 각 호의 어느 하나에 해당하는 금액에 대하여는 연구인력 지원비를 계상하여서는 아니 된다.\n1. 참여연구자 및 연구근접지원인력이 아닌 자의 연구인력 지원비(단, 연구개발인력 양성을 목적으로 하는 연구개발과제의 경우 지원대상 인력에 대한 비용은 제외한다)\n2. 참여연구자의 종신 학회비\n3. 연구개발과제의 수행에 관련되지 아니하는 학회ㆍ세미나 참가비, 교육훈련비\n4. 참여연구자의 학위과정에 필요한 비용\n5. 「근로자직업능력개발법」 및 「고용보험법」 등에 따라 환급 가능한 교육비 등으로 지급한 금액의 전부 또는 일부(연구개발기관의 사정으로 환급을 신청하지 못한 금액을 포함한다)\n6. 평일 점심 또는 출장비 중 식비가 포함된 출장일의 참여연구자 및 연구근접지원인력의 식대\n⑮ 연구개발기관의 장은 다음 각 호의 요건을 모두 갖추어 중앙행정기관의 장의 인정을 받은 경우에만 해외연구자 유치 지원비를 계상할 수 있다.\n1. 지원 대상자가 전체 연구개발과제(연구개발과제가 단계로 구분된 경우에는 해당 단계를 말한다) 기간 중 6개월 이상 국내에 거주하며 연구개발과제에 참여할 것\n2. 지원 대상자가 해당 연구개발과제의 참여연구자 또는 연구개발기관의 장과 6촌 이내의 혈족 또는 4촌 이내의 인척 관계에 있지 아니할 것\n3. 연구개발기관의 자체규정에 따라 해외연구자 유치를 위한 절차가 진행되었을 것\n⑯ 연구개발기관의 장은 해외연구자 유치 지원비를 원래계획보다 증액하여 사용하려는 때에는 제73조제1항제12호에 따라 중앙행정기관의 장의 사전 승인을 받아야 한다.\n⑰ 제2항, 제6항 및 제15항에도 불구하고 정부출연기관이 수행하는 기본사업의 경우에는 정부출연기관의 장의 인정으로 중앙행정기관의 장의 인정을 갈음할 수 있다.", "effective_from": "2026-05-06", "effective_to": null, "is_active": true}, {"article_key": "MAIN_ART_25_2", "article_number": "25의2", "article_title": "연구혁신비 공통 사용기준", "section": "MAIN", "source_article": "제25의2조", "paragraph_start": 231, "paragraph_end": 242, "original_text": "제25조의2(연구혁신비 공통 사용기준) ① 연구개발기관의 장은 연구혁신비를 다음 각 호에 해당하는 금액의 합의 10퍼센트 범위 내에서 연구개발과제의 특성을 고려하여 계상할 수 있다.\n1. 해당 연구개발과제(연구개발과제가 단계로 구분된 경우에는 해당 단계를 말한다. 이하 이 조에서 같다)에서 단계가 시작되는 시점에 계상하는 연구재료비\n2. 해당 연구개발과제에서 단계가 시작되는 시점에 계상하는 연구활동비\n② 제1항에도 불구하고 연구개발기관의 장은 연구혁신비를 연구개발과제에서 연차별 평균 5천만 원을 초과하여 계상할 수 없다.\n③ 연구개발기관의 장은 다음 각 호의 어느 하나에 해당하는 금액에 대하여는 연구혁신비를 계상하여서는 아니 된다.\n1. 제9조에 따른 사용용도로 집행하는 경우로서 건별 300만원을 초과하는 비용\n2. 제10조에 따른 사용용도로 집행하는 경우로서 건별 50만원을 초과하는 비용\n3. 인건비에 해당하거나 인건비의 성격을 가지는 비용\n4. 국외에서 사용되는 비용\n④ 연구개발기관의 장은 연구혁신비를 증액하여 사용하려는 때에는 제73조제1항제13호에 따라 중앙행정기관의 장의 사전 승인을 받아야 한다.\n⑤ 중앙행정기관의 장은 연구개발기관의 장이 사용한 연구혁신비에 대하여 연구비통합관리시스템을 통해 사용목적 및 거래내역을 입력한 경우에는 해당 연구혁신비에 대한 증명자료를 적정하게 갖춘 것으로 볼 수 있다\n⑥ 연구개발기관의 장은 연구혁신비로 해당 연구개발과제의 참여연구자만 참여하는 회의에 회의비 중 식비를 계상할 수 있다.", "effective_from": "2026-06-11", "effective_to": null, "is_active": true}, {"article_key": "MAIN_ART_26", "article_number": "26", "article_title": "연구수당 공통 사용기준", "section": "MAIN", "source_article": "제26조", "paragraph_start": 243, "paragraph_end": 258, "original_text": "제26조(연구수당 공통 사용기준) ① 연구개발기관의 장은 연구수당을 다음 각 호에 해당하는 금액의 합(이하 \"수정인건비\"라 한다)의 20퍼센트 범위 내에서 연구개발과제의 특성을 고려하여 계상할 수 있다.\n1. 해당 연구개발과제의 연구개발비에서 계상하는 인건비(현물로 계상된 금액을 포함하되, 연구근접지원인력의 인건비는 제외한다)\n2. 해당 연구개발과제의 연구개발비에서 계상하는 학생인건비(연구개발기간 동안 참여연구자로 등록된 학생연구자가 없는 경우에는 계상된 학생인건비 전액을 제외한다)\n3. 해당 연구개발과제의 연구개발비에서 계상하지 아니하는 금액으로서 다음의 계산식에 따라 계산한 미지급인건비(미지급인건비를 계산하는 경우 연구개발계획서에 해당 미지급인건비 총액을 명시하여야 한다)\n4. 국가연구개발사업에서 「과학기술분야 정부출연연구기관 등의 설립ㆍ운영 및 육성에 관한 법률」제2조에 따른 과학기술분야 정부출연연구기관의 출연(연) 지원사업으로 이관된 인건비로서 중앙행정기관 장이 인정하는 인건비\n② 연구개발기관의 장은 수정인건비가 변경된 경우에 변경된 수정인건비의 20퍼센트 범위 내에서 연구수당을 변경하여 계상하여야 한다. 이 경우 연구수당을 연구개발과제(연구개발과제가 단계로 구분된 경우에는 해당 단계를 말한다)가 시작되는 시점에 계상한 금액보다 증액하여 계상하여서는 아니 된다.\n③ 제2항 후단에도 불구하고 연구개발기관의 장이 다음 각 호의 어느 하나에 해당하는 사유로 연구수당을 원래계획보다 증액하여 계상하려는 경우에는 제73조제1항제10호에 따라 중앙행정기관의 장의 사전 승인을 받아 협약을 변경한 후 해당 연구수당을 계상하여야 한다.\n1. 연구개발과제의 연구개발비 총액(연구개발과제가 단계로 구분되는 경우에는 해당 단계의 총액을 말한다)이 증액되는 경우\n2. 법 제11조제2항에 따라 연구개발기관이 추가ㆍ변경되는 경우\n④ 연구개발기관의 장은 제1항제3호에 따른 미지급인건비가 있는 경우에 해당 참여연구자와 협의하여 참여연구자가 연구개발과제에 참여하면서 연구개발비가 아닌 재원으로 인건비를 지급받는 기간 동안 실제 연구개발과제에 참여하는 정도(이하 \"미지급인건비계상률\"이라 한다)를 산출하고, 이를 연구비통합관리시스템에 해당 회계연도 종료일까지 입력하여야 한다.\n⑤ 연구개발기관의 장은 참여연구자 전부를 대상으로 하는 기여도 평가 등 연구수당 지급에 관한 합리적인 기준을 마련하여야 하고, 그 기준에 따라 연구수당을 지급하여야 한다.\n⑥ 연구개발기관의 장은 참여연구자가 2명 이상인 경우에 한 명의 참여연구자에게 해당 연구개발과제의 연구수당 계상액의 70퍼센트를 초과하여 연구수당을 지급하여서는 아니 된다.\n⑦ 연구개발기관의 장은 다음 각 호의 어느 하나에 해당하는 금액을 연구수당으로 사용하여서는 아니 된다.\n1. 연구개발비의 정산 결과에 따라 영 제20조제1항에 따른 연구개발비 사용용도와 법 제13조제4항에 따른 연구개발비 사용기준에 적합하게 사용한 것으로 중앙행정기관의 장에 의해 인정된 수정인건비의 20퍼센트를 초과한 금액\n2. 연구수당으로 계상한 금액 대비 지급한 금액의 비율(이하 \"연구수당지급비율\"이라 한다)이 직접비로 계상한 금액(현물로 계상한 금액은 제외한다) 대비 사용한 금액의 비율(이하 \"직접비사용비율\"이라 한다)을 20퍼센트포인트 초과한 경우에 다음의 계산식에 따라 계산한 금액\n⑧ 연구개발기관의 장은 해당 단계의 연구수당을 다음 단계의 연구수당에 포함하여 사용하여서는 아니 된다.", "effective_from": "2026-05-06", "effective_to": null, "is_active": true}, {"article_key": "MAIN_ART_26_2", "article_number": "26의2", "article_title": "보안수당 공통 사용기준", "section": "MAIN", "source_article": "제26의2조", "paragraph_start": 259, "paragraph_end": 260, "original_text": "제26조의2(보안수당 공통 사용기준) ① 연구개발기관의 장은 영 제45조에 따른 보안과제(이하 \"보안과제\"라 한다)를 수행하는 참여연구자 및 연구근접지원인력을 대상으로 해당 과제의 수정인건비 중 각 개인별 인건비의 3퍼센트 범위 내에서 보안수당을 계상할 수 있으며, 계상한 보안수당은 해당 참여연구자 및 연구근접지원인력에게만 지급할 수 있다.\n② 제1항에도 불구하고 연구개발기관의 장은 학생인건비통합관리 대상 보안과제에서 학생연구자의 보안수당을 계상하려는 경우 해당 과제를 수행하는 학생연구자별로 학생인건비통합관리계정에서 지급하는 학생인건비의 3퍼센트 범위 내에서 보안수당을 계상할 수 있다. 다만, 학생연구자에게 지급하는 보안수당의 총액은 해당 과제에서 학생인건비통합관리계정으로 이체된 금액의 3퍼센트를 초과할 수 없다.", "effective_from": "2026-05-06", "effective_to": null, "is_active": true}, {"article_key": "MAIN_ART_27", "article_number": "27", "article_title": "위탁연구개발비 공통 사용기준", "section": "MAIN", "source_article": "제27조", "paragraph_start": 261, "paragraph_end": 267, "original_text": "제27조(위탁연구개발비 공통 사용기준) ① 연구개발기관의 장은 위탁연구개발비를 계상할 때에 원칙적으로 해당 연구개발과제 직접비에서 위탁연구개발비, 국제공동연구개발비 및 연구개발부담비를 제외한 금액의 40퍼센트를 초과하여서는 아니 된다. 다만, 중앙행정기관의 장의 인정을 받은 경우에는 해당 연구개발과제 직접비에서 위탁연구개발비, 국제공동연구개발비 및 연구개발부담비를 제외한 금액의 40퍼센트를 초과하여 위탁연구개발비를 계상할 수 있다.\n② 제1항의 단서에도 불구하고 정부출연기관의 장은 정부출연기관이 수행하는 기본사업에 한하여 직접비에서 위탁연구개발비, 국제공동연구개발비 및 연구개발부담비를 제외한 금액의 40%를 초과하여 사용할 수 있다.\n③ 연구개발기관의 장은 위탁연구개발비를 원래계획보다 20퍼센트 이상 증액하여 계상하려는 때에는 제73조제1항제6호에 따라 중앙행정기관의 장의 사전 승인을 받아야 한다.\n④ 연구개발기관의 장은 영 제24조제1항에 따른 연구개발과제 마다 관리하는 별도의 계정(이하 \"연구개발과제계정\"이라 한다)에서 위탁연구개발기관의 계정으로 이체 또는 계정대체된 위탁연구개발비를 영 제15조제1항 및 영 제25조에 따른 연구개발비 사용내역, 영 제26조제1항에 따른 사용실적보고서(이하 \"사용실적보고서등\"이라 한다)에서 사용된 연구개발비로 본다.\n⑤ 연구개발기관의 장은 위탁연구개발비 사용에 관한 계좌이체증명 등 증명자료를 갖추어야 한다.\n⑥ 위탁연구개발기관의 장은 제1항에 따라 이체 또는 계정대체된 금액을 사용할 때에 영 제20조제1항ㆍ제2항에 따른 사용용도와 이 고시에 따른 사용기준에 따라야 한다. 다만, 이 경우 위탁연구개발기관의 장은 위탁연구개발비, 국제공동연구개발비 및 연구개발부담비를 계상할 수 없다.\n⑦ 중앙행정기관의 장은 위탁연구개발기관이 사용한 금액에 대하여 위탁연구개발기관으로부터 사용실적 보고를 받고, 정산ㆍ회수 등 필요한 조치를 할 수 있다. 이 경우 위탁연구개발비를 지급한 연구개발기관의 장은 적극 협조하여야 한다.", "effective_from": "2026-05-06", "effective_to": null, "is_active": true}, {"article_key": "MAIN_ART_28", "article_number": "28", "article_title": "국제공동연구개발비 공통 사용기준", "section": "MAIN", "source_article": "제28조", "paragraph_start": 268, "paragraph_end": 273, "original_text": "제28조(국제공동연구개발비 공통 사용기준) ① 연구개발기관의 장은 중앙행정기관 장이 필요하다고 인정하는 경우에 한하여 국제공동연구개발비를 계상할 수 있다.\n② 제1항에도 불구하고 정부출연기관의 기본사업에 대해서는 정부출연기관의 장이 필요하다고 인정하는 경우 국제공동연구개발비를 계상할 수 있다.\n③ 연구개발기관의 연구개발과제계정에서 국외에 소재한 기관 또는 외국인의 계좌 또는 계정으로 이체 또는 계정대체된 국제공동연구개발비는 사용실적보고서등에서 사용된 연구개발비로 본다.\n④ 연구개발기관의 장은 국제공동연구개발비 사용에 관한 연구개발기관과 국외기관 간 계약서, 계좌이체증명 등 증명자료를 갖추어야 한다.\n⑤ 연구개발기관의 장은 국제공동연구개발비를 원래계획과 다르게 변경하여 사용하려는 때에는 제73조제1항제7호에 따라 중앙행정기관의 장의 사전 승인을 거쳐 협약을 변경한 후 해당 국제공동연구개발비를 계상하여야 한다(단, 환율의 변동만으로 금액이 달라지는 경우에는 제외한다).\n⑥ 국외에 소재한 기관 또는 외국인은 제1항에 따라 이체 또는 계정대체된 금액을 사용할 때에 영 제20조제1항ㆍ제2항에 따른 사용용도와 이 고시에 따른 사용기준에 따르도록 노력하여야 한다.", "effective_from": "2026-05-06", "effective_to": null, "is_active": true}, {"article_key": "MAIN_ART_29", "article_number": "29", "article_title": "연구개발부담비 공통 사용기준", "section": "MAIN", "source_article": "제29조", "paragraph_start": 274, "paragraph_end": 274, "original_text": "제29조(연구개발부담비 공통 사용기준) 연구개발부담비는 정부출연기관에 한하여 계상할 수 있다.", "effective_from": "2026-05-06", "effective_to": null, "is_active": true}, {"article_key": "MAIN_ART_30", "article_number": "30", "article_title": "인력지원비 공통 사용기준", "section": "MAIN", "source_article": "제30조", "paragraph_start": 275, "paragraph_end": 276, "original_text": "제30조(인력지원비 공통 사용기준) ① 삭제\n② 삭제", "effective_from": "2026-05-06", "effective_to": null, "is_active": true}, {"article_key": "MAIN_ART_31", "article_number": "31", "article_title": "연구지원비 공통 사용기준", "section": "MAIN", "source_article": "제31조", "paragraph_start": 277, "paragraph_end": 279, "original_text": "제31조(연구지원비 공통 사용기준) ① 삭제\n② 삭제\n③ 삭제", "effective_from": "2026-05-06", "effective_to": null, "is_active": true}, {"article_key": "MAIN_ART_32", "article_number": "32", "article_title": "성과활용지원비 공통 사용기준", "section": "MAIN", "source_article": "제32조", "paragraph_start": 280, "paragraph_end": 280, "original_text": "제32조(성과활용지원비 공통 사용기준) 삭제", "effective_from": "2026-05-06", "effective_to": null, "is_active": true}, {"article_key": "MAIN_ART_33", "article_number": "33", "article_title": "연구개발비사용액부당회수 등 금지", "section": "MAIN", "source_article": "제33조", "paragraph_start": 281, "paragraph_end": 289, "original_text": "제33조(연구개발비사용액부당회수 등 금지) ① 연구개발기관 소속 임직원(고등교육법 제14조 제2항에 따른 교원을 포함한다. 이하 같다) 또는 참여연구자는 정당한 사유없이 연구개발비에서 사용된 금액의 전부 또는 일부를 돌려받는 행위(이하 \"연구개발비사용액부당회수\"라 한다)를 하여서는 아니 된다.\n② 연구개발기관 소속 임직원은 다음 각 호의 어느 하나에 해당하는 행위(이하 \"인건비부당회수등\"이라 한다)를 하여서는 아니 된다.\n1. 참여연구자에게 인건비 또는 학생인건비를 지급하지 아니하는 행위\n2. 연구개발과제 수행을 지원한 연구근접지원인력에게 인건비를 지급하지 아니하는 행위\n3. 참여연구자에게 지급된 인건비 또는 학생인건비를 회수하여 관리 또는 사용하는 행위\n4. 연구근접지원인력에게 지급된 인건비를 회수하여 관리ㆍ사용하는 행위\n③ 연구개발기관의 장은 연구개발비사용액부당회수 및 인건비부당회수등이 발생하지 아니하도록 관리하여야 한다.\n④ 연구개발비사용액부당회수 및 인건비부당회수등은 법 제13조제3항에 따른 연구개발비의 사용용도를 위반한 행위로 본다.\n제3절 정부출연기관의 계상기준 및 인정기준", "effective_from": "2026-05-06", "effective_to": null, "is_active": true}, {"article_key": "MAIN_ART_34", "article_number": "34", "article_title": "정부출연기관 연구개발비 구성", "section": "MAIN", "source_article": "제34조", "paragraph_start": 290, "paragraph_end": 296, "original_text": "제34조(정부출연기관 연구개발비 구성) ① 정부출연기관이 사용하는 연구개발비는 다음 각 호에 따라 구성한다.\n1. 영 제19조제4항에 따라 정부출연기관이 연구개발비를 부담하는 경우: 다음 각 목에 따른 연구개발비\n가.정부(중앙행정기관을 말한다. 이하 같다)가 지원하는 연구개발비\n나.정부출연기관이 부담하는 연구개발비\n다.그 외 기관ㆍ단체ㆍ개인이 지원하는 연구개발비\n2. 영 제19조제4항에 해당하지 아니하여 정부출연기관이 연구개발비를 부담하지 아니하는 경우: 정부가 지원하는 연구개발비\n② 영 제19조제4항에 따라 정부출연기관이 연구개발비를 부담하거나 그 외 기관ㆍ단체ㆍ개인이 연구개발비를 지원하려는 경우에는 해당 금액을 연구개발과제협약에서 정하는 기한까지 중앙행정기관에 납부하여야 한다. 다만, 연구개발과제협약에서 별도로 기한을 정하지 않은 경우 연도별 연구개발기간이 종료되기 3개월 전까지 납부해야 한다.", "effective_from": "2026-05-06", "effective_to": null, "is_active": true}, {"article_key": "MAIN_ART_35", "article_number": "35", "article_title": "정부출연기관 연구개발비 지급", "section": "MAIN", "source_article": "제35조", "paragraph_start": 297, "paragraph_end": 299, "original_text": "제35조(정부출연기관 연구개발비 지급) ① 중앙행정기관의 장은 연구비통합관리시스템 중 통합이지바로(통합Ezbaro)를 사용하여 정부출연기관에 연구개발비를 지급하는 경우에 연구개발비를 일괄지급하여야 한다.\n② 중앙행정기관의 장은 연간 연구개발비 규모가 100억 원 이상인 연구개발과제에 대하여는 정부출연기관에 이자를 포함한 연구개발비 사용규모의 정확한 파악을 위하여 별도계좌로 연구개발비를 관리하도록 요구할 수 있고, 제1항에도 불구하고 정부출연기관에 연구개발비를 건별지급할 수 있다.\n③ 중앙행정기관의 장은 통합알시엠에스(통합RCMS)를 사용하여 정부출연기관에 연구개발비를 지급하는 경우에 연구개발비를 건별지급하여야 한다.", "effective_from": "2026-05-06", "effective_to": null, "is_active": true}, {"article_key": "MAIN_ART_36", "article_number": "36", "article_title": "정부출연기관 연구개발비 이관", "section": "MAIN", "source_article": "제36조", "paragraph_start": 300, "paragraph_end": 303, "original_text": "제36조(정부출연기관 연구개발비 이관) ① 연구개발과제의 협약이 체결된 후에 연구개발기관이 정부출연기관에서 다른 기관ㆍ단체로 변경된 경우에는 정부출연기관은 다음 각 호에 따라 연구개발비를 다른 기관ㆍ단체로 이관하여야 한다.\n1. 직접비: 직접비 잔액\n2. 간접비: 다음의 계산식에 따라 계산한 금액\n② 제1항에 따라 연구개발비를 이관받은 연구개발기관의 간접비비율 적용에 관하여는 제37조제1항부터 제3항을 준용한다. 다만, 제37조제1항의 연구개발과제가 시작되는 시점은 연구개발기관이 변경된 날로 한다.", "effective_from": "2026-05-06", "effective_to": null, "is_active": true}, {"article_key": "MAIN_ART_37", "article_number": "37", "article_title": "정부출연기관 간접비비율 적용기준", "section": "MAIN", "source_article": "제37조", "paragraph_start": 304, "paragraph_end": 316, "original_text": "제37조(정부출연기관 간접비비율 적용기준) ① 정부출연기관이 사용하는 연구개발비의 간접비비율은 연구개발과제(연구개발과제가 단계로 구분된 경우에는 해당 단계를 말한다)가 시작되는 시점에 해당 정부출연기관의 간접비고시비율을 적용하는 것을 원칙으로 한다.\n② 제1항에도 불구하고 각 호의 어느 하나에 해당하는 연구개발과제에 대하여는 간접비비율을 정부출연기관별 간접비고시비율보다 낮게 적용할 수 있다. 다만, 제1호에 해당하는 연구개발과제의 경우에는 정부출연기관의 장이 정하는 기준에 따라 간접비비율을 정부출연기관별 간접비고시비율보다 낮거나 높게 적용할 수 있다.\n1. 정부출연기관의 기본사업의 연구개발과제(단, 제44조제3항에 따라 과학기술정보통신부장관이 인정하는 연구개발과제는 제외한다)\n2. 연구개발시설ㆍ장비 구축 및 연구개발인프라 조성을 주된 목적으로 하는 연구개발과제\n3. 정보시스템 구축ㆍ개발을 주된 목적으로 하는 연구개발과제\n4. 기술이전ㆍ사업화를 주된 목적으로 하는 연구개발과제\n5. 연구개발인력 및 전문기술인력 양성을 주된 목적으로 하는 사업\n6. 외국의 정부ㆍ기관ㆍ단체와 공동으로 추진하는 연구개발과제\n7. 중앙행정기관의 장이 정부의 예산 사정 등으로 간접비고시비율 적용이 어렵다고 인정하는 연구개발과제\n③ 제2항 본문에 따라 연구개발과제의 간접비비율을 정부출연기관별 간접비고시비율보다 낮게 적용할 경우에는 연구개발과제의 목적과 특성 등을 고려하여 다음 각 호 중 어느 하나의 방법을 적용하여야 한다. 이 경우 중앙행정기관의 장은 법 제9조제4항에 따라 연구개발과제를 공모할 때 그 간접비비율 적용 방법을 알려야 한다.\n1. 다음의 계산식에 따라 계산한 비율을 적용하는 방법\n2. 정부출연기관별 간접비고시비율에 1.0이하의 조정비율을 적용(직접비 규모별로 구간을 설정하여 구간별로 차별적인 조정비율을 적용하는 경우를 포함한다)하는 방법\n3. 간접비비율을 5퍼센트로 하는 방법", "effective_from": "2026-05-06", "effective_to": null, "is_active": true}, {"article_key": "MAIN_ART_38", "article_number": "38", "article_title": "정부출연기관 연구개발비 현금ㆍ현물 구분기준", "section": "MAIN", "source_article": "제38조", "paragraph_start": 317, "paragraph_end": 317, "original_text": "제38조(정부출연기관 연구개발비 현금ㆍ현물 구분기준) 정부출연기관의 장은 연구개발비를 현금으로 계상하여야 한다. 다만, 정부출연기관이 영 제19조제4항에 따라 연구개발비를 부담하는 경우에는 제21조제4항제5호나목, 제64조, 제66조, 제67조, 제68조제1항부터 제3항을 준용하여 현금 또는 현물로 계상하여야 한다. 이 경우 \"영리기관\"을 \"정부출연기관\"으로 본다.", "effective_from": "2026-05-06", "effective_to": null, "is_active": true}, {"article_key": "MAIN_ART_39", "article_number": "39", "article_title": "정부출연기관 인건비 사용기준", "section": "MAIN", "source_article": "제39조", "paragraph_start": 318, "paragraph_end": 335, "original_text": "제39조(정부출연기관 인건비 사용기준) ① 정부출연기관의 장은 참여연구자ㆍ연구근접지원인력의 인건비를 연 단위로 다음의 계산식에 따른 인건비계상률에 따라 계상하여야 한다.\n② 연구개발기관의 장과 참여연구자ㆍ연구근접지원인력은 협의하여 제1항에 따른 인건비계상률을 연 단위로 산출하고, 이를 연구비통합관리시스템에 해당 회계연도 종료일까지 입력하여야 한다.\n③ 참여연구자ㆍ연구근접지원인력의 연 급여는 다음 각 호의 법령과 규정 등에 따라 지급하는 1년간의 급여(연구수당, 연구개발능률성과급 및 「국가연구개발사업 등의 성과평가 및 성과관리에 관한 법률」 제29조제1항 따른 포상은 제외한다) 총액으로 한다. 다만, 출산전후휴가 기간 동안의 급여는 관계 법령 또는 자체규정에 따라 정부출연기관이 지급할 의무가 있는 급여 총액(「고용보험법」 등에 따라 정부에서 지원받을 수 있는 금액은 제외한다)으로 한다.\n1. 참여연구자가 정부출연기관에 소속된 경우:「근로기준법」 등 관련 법령과 정부출연기관의 인사규정, 취업규칙 등 자체규정\n2. 참여연구자가 정부출연기관에 소속되지 아니한 경우\n가.참여연구자가 다른 기관ㆍ단체에 소속된 경우: 「근로기준법」 등 관련 법령과 참여연구자의 소속 기관ㆍ단체의 인사규정, 취업규칙 등 자체규정\n나.참여연구자가 다른 기관ㆍ단체에 소속되지 아니한 경우(개인사업자 및 강사를 포함한다): 참여연구자가 연구개발과제를 수행하는 정부출연기관과 체결한 연구참여계약서에 명시된 기준\n3. 연구근접지원인력의 경우: 「근로기준법」 등 관련 법령과 정부출연기관의 인사규정, 취업규칙 등 자체규정\n④ 정부출연기관의 장은 참여연구자 및 연구근접지원인력의 인건비를 현금으로 계상할 수 있다. 다만, 다음 각 호의 어느 하나에 해당하는 참여연구자의 인건비는 현금으로 계상하여서는 아니 된다.\n1. 대학에 소속된 「고등교육법」 제14조제2항에 따른 교원(단, 「고등교육법」 제14조의2의 적용을 받아 임용된 강사 중 「국민건강보험법」제6조제2항 단서에 따른 직장가입자가 아닌 자 및 「고등교육법」제17조의 적용을 받아 임용된 겸임교원 및 초빙교원 등의 인건비는 현금으로 계상할 수 있다)\n2. 국가 또는 지방자치단체가 직접 설치하여 운영하는 연구개발기관에 소속된 공무원\n3. 영리기관 소속 임직원(단, 중앙행정기관의 장이 인정하는 경우는 제외한다)\n⑤ 정부출연기관의 장은 소속 참여연구자(학생연구자는 제외한다)별로 제1항에 따른 인건비계상률, 제40조제1항에 따른 학생인건비계상률, 제26조제3항에 따른 미지급인건비계상률, 제91조제2항에 따른 학생인건비 지급률의 합(이하 \"총인건비계상률\"이라 한다)이 연평균 130퍼센트를 초과하지 아니 하도록 관리하여야 하며, 연구근접지원인력별로 총인건비계상률이 연평균 100퍼센트를 초과하지 아니 하도록 관리하여야 한다.\n⑥ 제22조제1항에도 불구하고 정부출연기관의 장은 제5항에 따라 참여연구자의 연평균 총인건비계상률이 100퍼센트를 초과하더라도 해당 참여연구자에게 제3항에 따른 연 급여를 초과하여 인건비를 지급하여서는 아니 된다.\n⑦ 정부출연기관의 장은 매년 제1항에 따라 계상한 인건비의 합이 해당 정부출연기관의 인건비 총액을 초과하지 아니하도록 관리하여야 하며, 초과하는 금액이 발생한 경우에는 이사회의 승인을 받아 연구개발 관련 용도로 사용하고, 초과하는 금액과 그 사용계획 및 사용내역을 다음해 4월 30일까지 기획재정부장관, 과학기술정보통신부장관 및 주무관청의 장에게 보고하여야 한다. 이 경우 정부출연기관의 장은 정규직 직원별로 계상한 인건비의 합과 실제 지급한 인건비의 합의 차액이 제44조제1항제2호에 따른 출연금인건비계상액을 초과하지 아니하도록 관리하여야 한다.\n⑧ 정부출연기관의 장은 제1항에 따라 계상된 인건비를 효율적으로 관리하기 위하여 참여연구자에게 인건비를 지급하기 이전에 별도 계정을 설정하여 여러 연구개발과제의 인건비를 이체 또는 계정대체할 수 있다. 이 경우 정부출연기관의 장은 참여연구자의 과제별 인건비 계상률을 관리하여야 한다.\n⑨ 정부출연기관의 장은 연구근접지원인력의 인건비를 직접비와 간접비로 중복 또는 분할하여 계상하여서는 아니 된다.\n⑩ 정부출연기관의 장은 다른 기관ㆍ단체에 소속된 참여연구자의 인건비를 계상하려는 때에는 해당 참여연구자가 연구개발과제에 참여함을 확인하는 서류를 해당 참여연구자의 소속 기관ㆍ단체로부터 제출받아야 하며, 다른 기관ㆍ단체에 소속된 참여연구자의 인건비를 계상한 때에는 그 금액을 해당 참여연구자의 소속 기관ㆍ단체에 통보하여야 한다.", "effective_from": "2026-05-06", "effective_to": null, "is_active": true}, {"article_key": "MAIN_ART_40", "article_number": "40", "article_title": "정부출연기관 학생인건비 사용기준", "section": "MAIN", "source_article": "제40조", "paragraph_start": 336, "paragraph_end": 357, "original_text": "제40조(정부출연기관 학생인건비 사용기준) ① 정부출연기관의 장은 학생연구자의 학생인건비를 월 단위, 학기 단위 또는 학년 단위로 다음의 계산식에 따라 산출된 학생인건비계상률에 따라 계상하여야 한다.\n② 정부출연기관의 장과 연구책임자 및 학생연구자는 협의하여 학생인건비계상률을 월 단위로 산출하고, 이를 반영하여 별지 제1호 또는 제2호 서식에 따른 학생연구자 연구참여확약서를 학기 단위 또는 학년 단위로 작성하여야 하며, 이를 연구비통합관리시스템에 해당 회계연도 종료일까지 입력하여야 한다. 다만, 정부출연기관의 장과 학생연구자가 「근로기준법」제2조제4호에 따른 근로계약을 체결한 경우 별지 제1호 또는 제2호 서식에 따른 학생연구자 연구참여확약서를 작성하지 아니할 수 있다.\n③ 정부출연기관의 장과 연구책임자 및 학생연구자는 다음 각 호의 경우에만 협의를 거쳐 제2항에 따른 연구참여확약서를 변경할 수 있다.\n1. 연구개발과제 협약 체결ㆍ변경ㆍ중단ㆍ해약\n2. 학생연구자 학적 변동\n3. 학생연구자 개인의 사정\n4. 학생연구자가 질병ㆍ실종ㆍ형사소추 등으로 업무 수행이 불가능한 경우\n5. 학생연구자 업무량 변동에 따라 학생연구자에게 지급하는 학생인건비 금액을 변경하려는 경우\n④ 정부출연기관의 장은 다음 각 호에 따른 금액 이상으로 학위과정별 학생인건비(4대보험의 기관부담금 및 퇴직급여충당금은 제외한다) 계상기준을 정하여야 한다. 이 경우 학과, 연구부서, 연구책임자 등에 따라 별도의 기준을 두어서는 아니 된다.\n1. 학사과정(전문학사과정을 포함한다) : 월 1,300,000원\n2. 석사과정 : 월 2,200,000원\n3. 박사과정 : 월 3,000,000원\n4. 통합과정 : 제1호부터 제3호까지의 기준을 고려하여 연구개발기관의 장이 별도로 정한 금액\n⑤ 정부출연기관의 장은 소속 학생연구자의 월별 총인건비계상률이 100퍼센트를 초과하지 아니하도록 관리하여야 하며, 다음 각 호의 어느 하나에 해당하는 금액은 총인건비계상률을 산정하는 데 포함하여서는 아니 된다.\n1. 소속 학생연구자가 고등교육재정지원사업 및 인문사회분야 학술지원사업으로부터 받는 인건비(학생인건비 포함) 및 장학금\n2. 「고등교육법」 제14조의2에 따른 강사나 제17조에 따른 겸임교원 및 초빙교원으로 임용된 학생연구자가 강사, 겸임교원 및 초빙교원으로서 받는 인건비\n3. 소속 학생연구자의 기타 근로소득 및 사업소득\n⑥ 정부출연기관의 장은 학생인건비를 효율적으로 관리하기 위하여 별도 계정을 설정하여 여러 연구개발과제의 학생인건비를 이체 또는 계정대체할 수 있다. 이 경우 정부출연기관의 장은 학생연구자의 연구개발과제별 학생인건비계상률을 관리하여야 한다.\n⑦ 정부출연기관의 장은 다른 기관ㆍ단체에 소속된 학생연구자의 학생인건비를 계상한 때에는 그 금액을 해당 학생연구자의 소속 기관ㆍ단체에 통보하여야 한다.\n⑧ 학생연구자에게 학생인건비를 지급하는 연구개발기관의 장은 제88조제1항제1호 및 같은 조 같은 항 제5호부터 제8호까지의 사항을 포함하는 학생연구자 지원규정을 마련하여 운영하여야 한다. 이 경우 학생연구자 지원규정의 공개에 관하여는 제88조제2항에 따른다.\n⑨ 과학기술정보통신부장관은 소속 학생연구자가 있는 연구개발기관이 학생연구자 지원규정을 마련ㆍ운영하는 데 활용할 수 있도록 학생연구자 지원규정 작성 기준을 마련하여 인터넷 홈페이지에 게시하는 방법 등으로 제공하여야 한다.\n⑩ 정부출연기관의 장은 소속 학생연구자에게 지급한 학생연구자별 학생인건비의 합이 제4항 각 호에서 정한 금액의 10% 이상이 되도록 관리하여야 한다. 단, 다른 연구개발기관의 인건비 또는 학생인건비 지급액에 따라 월별 총인건비계상률이 90퍼센트를 초과하는 경우에는 그러하지 아니한다.", "effective_from": "2026-05-06", "effective_to": null, "is_active": true}, {"article_key": "MAIN_ART_41", "article_number": "41", "article_title": "정부출연기관 연구활동비 사용기준", "section": "MAIN", "source_article": "제41조", "paragraph_start": 358, "paragraph_end": 359, "original_text": "제41조(정부출연기관 연구활동비 사용기준) ① 정부출연기관의 장은 참여연구자와 해당 정부출연기관 내 동일한 부서(정부출연기관 자체규정에 따른 최소단위 부서를 말한다)에 소속된 자에 대하여 전문가 활용비를 계상하여서는 아니 된다.\n② 정부출연기관의 장은 제10조제5호의 소프트웨어 활용비를 계상할 때에 여러 연구개발과제에서 소프트웨어 활용비를 모아 기관 단위로 통합구매ㆍ관리할 수 있으며, 해당 정부출연기관의 장은 기관 단위 소프트웨어 통합구매를 위하여 연구개발과제별로 필요한 비용을 분담하게 할 수 있다.", "effective_from": "2026-05-06", "effective_to": null, "is_active": true}, {"article_key": "MAIN_ART_42", "article_number": "42", "article_title": "정부출연기관 연구개발부담비 사용기준", "section": "MAIN", "source_article": "제42조", "paragraph_start": 360, "paragraph_end": 362, "original_text": "제42조(정부출연기관 연구개발부담비 사용기준) ① 정부출연기관의 연구개발과제계정에서 법 제4조에 따른 사업 중 영 제19조제4항 각 호의 어느 하나에 해당하는 연구개발과제의 연구개발기관의 계정으로 이체 또는 계정대체된 연구개발부담비를 사용실적보고서등에서 사용된 연구개발비로 본다.\n② 정부출연기관의 장은 연구개발부담비 사용에 관한 계좌이체증명 등 증명자료를 갖추어야 한다.\n③ 법 제4조에 따른 사업 중 영 제19조제4항 각 호의 어느 하나에 해당하는 연구개발과제의 주관연구개발기관의 장은 제1항에 따라 이체 또는 계정대체된 금액을 사용할 때에 영 제20조제1항에 따른 사용용도와 이 고시에 따른 사용기준에 따라야 한다.", "effective_from": "2026-05-06", "effective_to": null, "is_active": true}, {"article_key": "MAIN_ART_43", "article_number": "43", "article_title": "정부출연기관 간접비 사용기준", "section": "MAIN", "source_article": "제43조", "paragraph_start": 363, "paragraph_end": 372, "original_text": "제43조(정부출연기관 간접비 사용기준) ① 정부출연기관의 장은 여러 연구개발과제의 간접비를 효율적으로 관리하기 위하여 별도 계정으로 이체 또는 계정대체할 수 있다.\n② 정부출연기관이 제1항에 따라 연구개발과제계정에서 별도 계정으로 이체 또는 계정대체한 간접비는 사용실적보고서등에서 사용된 연구개발비로 본다. 다만, 법 제12조제3항 또는 법 제15조제1항에 따라 연구개발과제가 중단된 경우에는 별도 계정에서 사용된 금액을 사용실적보고서등에서 사용된 연구개발비로 본다.\n③ 중앙행정기관의 장은 정부출연기관의 장이 연구개발과제의 해당 연도 직접비가 부족하여 해당 연도 간접비의 조정을 요청한 경우에는 특별한 사유가 없으면 그 요청에 따라야 한다.\n④ 삭제\n⑤ 정부출연기관의 장은 법 제4조에 따른 기본사업에서 기관 공통 비용을 사용하려는 경우 자체규정에 따라 기관 공통 비용을 계상할 수 있다.\n⑥ 정부출연기관의 장은 연구개발능률성과급을 해당 기관의 회계연도 간접비 총액의 10퍼센트 이하로 계상하여야 한다.\n⑦ 정부출연기관의 장은 연구개발능률성과급을 지급할 때에 참여연구자와 연구지원인력을 모두 포함하여 자체적으로 성과평가를 실시한 후 지급하여야 한다.\n⑧ 정부출연기관의 장은 연구개발 관련 기반시설 및 장비의 운영비, 공동활용시설 내에 구축하는 연구개발시설ㆍ장비 구입비는 연구지원비로 계상할 수 없다.\n⑨ 정부출연기관의 장은 연구실안전관리비를 계상할 때 「연구실 안전환경 조성에 관한 법률」 제22조제3항, 「연구실 안전환경 조성에 관한 법률 시행규칙」 제13조에 따라 정하는 금액 이상으로 계상하여야 한다.\n⑩ 정부출연기관의 장은 기술창업 출연ㆍ출자금을 해당 연도 간접비 총액의 10퍼센트 범위에서 설립 이후 5년까지 계상할 수 있으며, 정부출연기관의 장이 필요하다고 인정하는 경우에는 자체규정에 따라 당초의 기간을 포함하여 최장 10년까지 계상할 수 있다.", "effective_from": "2026-05-06", "effective_to": null, "is_active": true}, {"article_key": "MAIN_ART_44", "article_number": "44", "article_title": "기본사업연구개발비계상기준 등", "section": "MAIN", "source_article": "제44조", "paragraph_start": 373, "paragraph_end": 380, "original_text": "제44조(기본사업연구개발비계상기준 등) ① 정부출연기관의 기본사업의 연구개발비는 다음 각 호의 연구개발기관출연금으로 구성한다.\n1. 기본사업의 연구개발과제 수행을 위한 연구개발기관출연금(이하 \"주요사업비\"라 한다)\n2. 정부출연기관의 인건비 지급을 위한 연구개발기관출연금(이하 \"출연금인건비\"라 한다)\n3. 정부출연기관의 운영을 위한 연구개발기관출연금(이하 \"출연금경상비\"라 한다)\n4. 정부출연기관의 시설 구축, 유지, 보수를 위한 연구개발기관출연금(이하 \"출연금건축비\"라 한다)\n② 정부출연기관의 기본사업의 연구개발비 사용용도별 계상기준(이하 \"기본사업연구개발비계상기준\"이라 한다)은 별표 1과 같다.\n③ 제2항에도 불구하고 정부출연기관의 기본사업 중 과학기술정보통신부장관이 인정하는 연구개발과제의 경우, 기본사업연구개발비계상기준을 달리 정할 수 있다.\n제4절 대학의 계상기준 및 인정기준", "effective_from": "2026-05-06", "effective_to": null, "is_active": true}, {"article_key": "MAIN_ART_45", "article_number": "45", "article_title": "대학 연구개발비 구성ㆍ지급ㆍ이관", "section": "MAIN", "source_article": "제45조", "paragraph_start": 381, "paragraph_end": 381, "original_text": "제45조(대학 연구개발비 구성ㆍ지급ㆍ이관) 대학이 사용하는 연구개발비의 구성ㆍ지급ㆍ이관에 관하여는 제34조부터 제44조까지를 준용한다. 이 경우 \"정부출연기관\"은 \"대학\"으로 본다.", "effective_from": "2026-05-06", "effective_to": null, "is_active": true}, {"article_key": "MAIN_ART_46", "article_number": "46", "article_title": "대학 간접비비율 적용기준", "section": "MAIN", "source_article": "제46조", "paragraph_start": 382, "paragraph_end": 386, "original_text": "제46조(대학 간접비비율 적용기준) ① 대학이 사용하는 연구개발비의 간접비비율은 연구개발과제(연구개발과제가 단계로 구분된 경우에는 해당 단계를 말한다)가 시작되는 시점에 해당 대학의 간접비고시비율을 적용하는 것을 원칙으로 한다.\n② 제1항에도 불구하고 각 호의 어느 하나에 해당하는 연구개발과제에 대하여는 간접비비율을 대학별 간접비고시비율보다 낮게 적용할 수 있다.\n1. 삭제\n2. 제37조제2항제2호부터 제7호까지에 해당하는 연구개발과제\n③ 제2항에 따라 연구개발과제의 간접비비율을 대학별 간접비고시비율보다 낮게 적용할 경우에는 연구개발과제의 목적과 특성 등을 고려하여 제37조제3항 각 호의 어느 하나의 방법으로 적용하여야 한다. 이 경우 중앙행정기관의 장은 법 제9조제4항에 따라 연구개발과제를 공모할 때 그 간접비비율 적용 방법을 알려야 한다.", "effective_from": "2026-05-06", "effective_to": null, "is_active": true}, {"article_key": "MAIN_ART_47", "article_number": "47", "article_title": "대학 연구개발비 현금ㆍ현물 구분기준", "section": "MAIN", "source_article": "제47조", "paragraph_start": 387, "paragraph_end": 387, "original_text": "제47조(대학 연구개발비 현금ㆍ현물 구분기준) 대학이 사용하는 연구개발비의 현금ㆍ현물 구분기준에 관하여는 제38조를 준용한다. 이 경우 \"정부출연기관\"은 \"대학\"으로 본다.", "effective_from": "2026-05-06", "effective_to": null, "is_active": true}, {"article_key": "MAIN_ART_48", "article_number": "48", "article_title": "대학 인건비 사용기준", "section": "MAIN", "source_article": "제48조", "paragraph_start": 388, "paragraph_end": 403, "original_text": "제48조(대학 인건비 사용기준) ① 대학의 장은 참여연구자ㆍ연구근접지원인력의 인건비를 월 단위로 제39조제1항의 계산식에 따른 인건비계상률에 따라 계상하여야 한다. 다만, 제39조제1항의 계산식에서 \"연 급여\"는 \"월 급여\"로 본다.\n② 대학의 장과 참여연구자ㆍ연구근접지원인력은 협의하여 제1항에 따른 인건비계상률을 월 단위로 산출하고, 이를 연구비통합관리시스템에 해당 회계연도 종료일까지 입력하여야 한다.\n③ 참여연구자ㆍ연구근접지원인력의 월 급여는 다음 각 호의 법령과 규정 등에 따라 지급하는 1개월간의 급여(연구수당 및 연구개발능률성과급은 제외한다) 총액으로 한다. 다만, 출산전후휴가 기간 동안의 급여는 관계 법령 또는 자체규정에 따라 대학이 지급할 의무가 있는 급여 총액(「고용보험법」 등에 따라 정부에서 지원받을 수 있는 금액은 제외한다)으로 한다.\n1. 참여연구자가 대학에 소속된 경우:「근로기준법」 등 관련 법령과 대학의 인사규정, 취업규칙 등 자체규정\n2. 참여연구자가 대학에 소속되지 아니한 경우\n가.참여연구자가 다른 기관ㆍ단체에 소속된 경우: 「근로기준법」 등 관련 법령과 참여연구자의 소속 기관ㆍ단체의 인사규정, 취업규칙 등 자체규정\n나.참여연구자가 다른 기관ㆍ단체에 소속되지 아니한 경우(개인사업자 및 강사를 포함한다): 참여연구자가 연구개발과제를 수행하는 대학과 체결한 연구참여계약서에 명시된 기준\n3. 연구근접지원인력의 경우: 「근로기준법」 등 관련 법령과 대학의 인사규정, 취업규칙 등 자체규정\n④ 대학의 장은 참여연구자 및 연구근접지원인력의 인건비를 현금으로 계상할 수 있다. 다만, 다음 각 호의 어느 하나에 해당하는 참여연구자의 인건비는 현금으로 계상하여서는 아니 된다.\n1. 대학에 소속된 「고등교육법」 제14조제2항에 따른 교원(단, 「고등교육법」 제14조의2의 적용을 받아 임용된 강사 중 「국민건강보험법」제6조제2항 단서에 따른 직장가입자가 아닌 자 및 「고등교육법」제17조의 적용을 받아 임용된 겸임교원 및 초빙교원 등의 인건비는 현금으로 계상할 수 있다)\n2. 국가 또는 지방자치단체가 직접 설치하여 운영하는 연구개발기관에 소속된 공무원\n3. 영리기관 소속 임직원(단, 중앙행정기관의 장이 인정하는 경우는 제외한다)\n⑤ 대학의 장은 소속 참여연구자ㆍ연구근접지원인력별로 총인건비계상률이 월별 100퍼센트를 초과하지 아니 하도록 관리하여야 한다.\n⑥ 대학의 장은 제1항에 따라 계상된 인건비를 효율적으로 관리하기 위하여 참여연구자에게 인건비를 지급하기 이전에 별도 계정을 설정하여 여러 연구개발과제의 인건비를 이체 또는 계정대체할 수 있다. 이 경우 대학의 장은 참여연구자의 연구개발과제별 인건비 계상률을 관리하여야 한다.\n⑦ 대학의 장은 연구근접지원인력의 인건비를 직접비와 간접비로 중복 또는 분할하여 계상하여서는 아니 된다.\n⑧ 대학의 장은 다른 기관ㆍ단체에 소속된 참여연구자의 인건비를 계상하려는 때에는 해당 참여연구자가 연구개발과제에 참여함을 확인하는 서류를 해당 참여연구자의 소속 기관ㆍ단체로부터 제출받아야 하며, 다른 기관ㆍ단체에 소속된 참여연구자의 인건비를 계상한 때에는 그 금액을 해당 참여연구자의 소속 기관ㆍ단체에 통보하여야 한다.", "effective_from": "2026-05-06", "effective_to": null, "is_active": true}, {"article_key": "MAIN_ART_49", "article_number": "49", "article_title": "대학 학생인건비 사용기준", "section": "MAIN", "source_article": "제49조", "paragraph_start": 404, "paragraph_end": 404, "original_text": "제49조(대학 학생인건비 사용기준) 대학이 사용하는 학생인건비의 사용기준에 관하여는 제40조를 준용한다. 이 경우 \"정부출연기관\"은 \"대학\"으로 본다.", "effective_from": "2026-05-06", "effective_to": null, "is_active": true}, {"article_key": "MAIN_ART_50", "article_number": "50", "article_title": "대학 연구활동비 사용기준", "section": "MAIN", "source_article": "제50조", "paragraph_start": 405, "paragraph_end": 406, "original_text": "제50조(대학 연구활동비 사용기준) ① 대학의 장은 참여연구자와 해당 대학 내 동일한 연구실에 소속된 자에 대하여 전문가 활용비를 계상하여서는 아니 된다.\n② 대학이 사용하는 소프트웨어 활용비의 계상에 관하여는 제41조제2항을 준용한다. 이 경우 \"정부출연기관\"은 \"대학\"으로 본다.", "effective_from": "2026-05-06", "effective_to": null, "is_active": true}, {"article_key": "MAIN_ART_51", "article_number": "51", "article_title": "대학 간접비 사용기준", "section": "MAIN", "source_article": "제51조", "paragraph_start": 407, "paragraph_end": 412, "original_text": "제51조(대학 간접비 사용기준) ① 대학의 장은 여러 연구개발과제의 간접비를 효율적으로 관리하기 위하여 별도 계정으로 이체 또는 계정대체할 수 있다.\n② 별도 계정을 설치한 대학에 대하여는 연구개발과제계정에서 별도 계정으로 이체 또는 계정대체된 간접비를 사용실적보고서등에서 사용된 연구개발비로 본다. 다만, 법 제12조제3항 또는 법 제15조제1항에 따라 연구개발과제가 중단된 경우에는 별도 계정에서 사용된 금액을 사용실적보고서등에서 사용된 연구개발비로 본다.\n③ 산학협력단 회계를 운영하는 대학은 제2항에 따라 별도 계정으로 이체 또는 계정대체된 간접비를 연구개발과제가 종료된 이후에도 별도로 구분하여 관리하여야 한다.\n④ 대학이 사용하는 직접비의 부족에 따른 간접비의 조정, 연구개발능률성과급, 연구실안전관리비, 기술창업 출연ㆍ출자금의 계상에 관하여는 제43조제3항, 제6항, 제7항, 제9항, 제10항을 준용한다. 이 경우 \"정부출연기관\"은 \"대학\"으로 본다.\n⑤ 대학의 장은 직접비로 계상하지 아니한 1억 원 이상(부가가치세 및 구입ㆍ설치 등에 필요한 부대비용을 포함한다)의 공동연구장비 구축ㆍ운영비를 계상할 경우 「국가연구개발 시설ㆍ장비의 관리 등에 관한 표준지침」 제4조제1항에 따른 국가연구시설ㆍ장비심의위원회의 심의를 거쳐야 한다.\n제5절 기타비영리기관의 계상기준 및 인정기준", "effective_from": "2026-05-06", "effective_to": null, "is_active": true}, {"article_key": "MAIN_ART_52", "article_number": "52", "article_title": "기타비영리기관 연구개발비 구성", "section": "MAIN", "source_article": "제52조", "paragraph_start": 413, "paragraph_end": 413, "original_text": "제52조(기타비영리기관 연구개발비 구성) 기타비영리기관이 사용하는 연구개발비의 구성에 관하여는 제34조를 준용한다. 이 경우 \"정부출연기관\"은 \"기타비영리기관\"으로 본다.", "effective_from": "2026-05-06", "effective_to": null, "is_active": true}, {"article_key": "MAIN_ART_53", "article_number": "53", "article_title": "기타비영리기관 연구개발비 지급", "section": "MAIN", "source_article": "제53조", "paragraph_start": 414, "paragraph_end": 418, "original_text": "제53조(기타비영리기관 연구개발비 지급) ① 중앙행정기관의 장은 연구비통합관리시스템 중 통합이지바로(통합Ezbaro)를 사용하여 기타비영리기관에 연구개발비를 지급하는 경우에 다음 각 호에 따라 연구개발비를 지급하여야 한다.\n1. 기타비영리기관에 연구지원부서가 있는 경우: 일괄지급\n2. 기타비영리기관에 연구지원부서가 없는 경우: 건별지급\n② 중앙행정기관의 장은 연간 연구개발비 규모가 100억 원 이상인 연구개발과제에 대하여는 기타비영리기관에 이자를 포함한 연구개발비 사용규모의 정확한 파악을 위하여 별도계좌로 연구개발비를 관리하도록 요구할 수 있고, 이 경우 제1항에도 불구하고 기타비영리기관에 연구개발비를 건별지급할 수 있다.\n③ 중앙행정기관의 장은 통합알시엠에스(통합RCMS)를 사용하여 기타비영리기관에 연구개발비를 지급하는 경우에 연구개발비를 건별지급하여야 한다.", "effective_from": "2026-05-06", "effective_to": null, "is_active": true}, {"article_key": "MAIN_ART_54", "article_number": "54", "article_title": "기타비영리기관 연구개발비 이관", "section": "MAIN", "source_article": "제54조", "paragraph_start": 419, "paragraph_end": 419, "original_text": "제54조(기타비영리기관 연구개발비 이관) 기타비영리기관이 사용하는 연구개발비의 이관에 관하여는 제36조를 준용한다. 이 경우 \"정부출연기관\"은 \"기타비영리기관\"으로 본다.", "effective_from": "2026-05-06", "effective_to": null, "is_active": true}, {"article_key": "MAIN_ART_55", "article_number": "55", "article_title": "기타비영리기관 간접비비율 적용기준", "section": "MAIN", "source_article": "제55조", "paragraph_start": 420, "paragraph_end": 420, "original_text": "제55조(기타비영리기관 간접비비율 적용기준) 기타비영리기관이 사용하는 연구개발비의 간접비비율 적용기준에 관하여는 제37조를 준용한다. 이 경우 \"정부출연기관\"은 \"기타비영리기관\"으로 본다.", "effective_from": "2026-05-06", "effective_to": null, "is_active": true}, {"article_key": "MAIN_ART_56", "article_number": "56", "article_title": "기타비영리기관 연구개발비 현금ㆍ현물 구분기준", "section": "MAIN", "source_article": "제56조", "paragraph_start": 421, "paragraph_end": 421, "original_text": "제56조(기타비영리기관 연구개발비 현금ㆍ현물 구분기준) 기타비영리기관이 사용하는 연구개발비의 현금ㆍ현물 구분기준에 관하여는 제38조를 준용한다. 이 경우 \"정부출연기관\"은 \"기타비영리기관\"으로 본다.", "effective_from": "2026-05-06", "effective_to": null, "is_active": true}, {"article_key": "MAIN_ART_57", "article_number": "57", "article_title": "기타비영리기관 인건비 사용기준", "section": "MAIN", "source_article": "제57조", "paragraph_start": 422, "paragraph_end": 423, "original_text": "제57조(기타비영리기관 인건비 사용기준) ① 기타비영리기관 중 「산업기술혁신 촉진법」 제42조제1항에 따른 전문생산기술연구소가 사용하는 인건비의 사용기준에 관하여는 제39조를 준용한다. 이 경우 \"정부출연기관\"은 \"기타비영리기관\"으로 본다.\n② 전문생산기술연구소가 아닌 기타비영리기관이 사용하는 인건비의 사용기준에 관하여는 제48조를 준용한다. 이 경우 \"대학\"은 \"기타비영리기관\"으로 본다.", "effective_from": "2026-05-06", "effective_to": null, "is_active": true}, {"article_key": "MAIN_ART_58", "article_number": "58", "article_title": "기타비영리기관 연구활동비 사용기준", "section": "MAIN", "source_article": "제58조", "paragraph_start": 424, "paragraph_end": 424, "original_text": "제58조(기타비영리기관 연구활동비 사용기준) 기타비영리기관이 사용하는 연구활동비의 사용기준에 관하여는 제41조를 준용한다. 이 경우 \"정부출연기관\"은 \"기타비영리기관\"으로 본다.", "effective_from": "2026-05-06", "effective_to": null, "is_active": true}, {"article_key": "MAIN_ART_59", "article_number": "59", "article_title": "기타비영리기관 간접비 사용기준", "section": "MAIN", "source_article": "제59조", "paragraph_start": 425, "paragraph_end": 426, "original_text": "제59조(기타비영리기관 간접비 사용기준) 기타비영리기관이 사용하는 간접비의 사용기준에 관하여는 제43조를 준용한다. 이 경우 \"정부출연기관\"은 \"기타비영리기관\"으로 본다.\n제6절 영리기관의 계상기준 및 인정기준", "effective_from": "2026-05-06", "effective_to": null, "is_active": true}, {"article_key": "MAIN_ART_60", "article_number": "60", "article_title": "영리기관 연구개발비 구성", "section": "MAIN", "source_article": "제60조", "paragraph_start": 427, "paragraph_end": 431, "original_text": "제60조(영리기관 연구개발비 구성) ① 영리기관이 사용하는 연구개발비는 다음 각 호에 따라 구성한다.\n1. 정부가 지원하는 연구개발비\n2. 영리기관이 부담하는 연구개발비\n3. 그 외 기관ㆍ단체ㆍ개인이 지원하는 연구개발비\n② 영 제19조제1항에 따라 영리기관이 연구개발비를 부담하거나 그 외 기관ㆍ단체ㆍ개인이 연구개발비를 지원하려는 경우에는 해당 금액을 연구개발과제협약에서 정하는 기한까지 중앙행정기관에 납부하여야 한다. 다만, 연구개발과제협약에서 별도로 기한을 정하지 않은 경우 연도별 연구개발기간이 종료되기 3개월 전까지 납부해야 한다.", "effective_from": "2026-05-06", "effective_to": null, "is_active": true}, {"article_key": "MAIN_ART_61", "article_number": "61", "article_title": "영리기관 연구개발비 지급", "section": "MAIN", "source_article": "제61조", "paragraph_start": 432, "paragraph_end": 436, "original_text": "제61조(영리기관 연구개발비 지급) ① 중앙행정기관의 장은 연구비통합관리시스템 중 통합이지바로(통합Ezbaro)를 사용하여 영리기관에 연구개발비를 지급하는 경우에 다음 각 호에 따라야 한다.\n1. 해당 영리기관이 「공공기관의 운영에 관한 법률」 제4조부터 제6조까지에 따라 지정ㆍ고시된 공기업인 경우: 일괄지급\n2. 해당 영리기관이 공기업이 아닌 경우: 건별지급\n② 중앙행정기관의 장은 연간 연구개발비 규모가 100억 원 이상인 연구개발과제에 대하여는 영리기관에 이자를 포함한 연구개발비 사용규모의 정확한 파악을 위하여 별도계좌로 연구개발비를 관리하도록 요구할 수 있고, 제1항에도 불구하고 영리기관에 연구개발비를 건별지급할 수 있다.\n③ 중앙행정기관의 장은 통합알시엠에스(통합RCMS)를 사용하여 영리기관에 연구개발비를 지급하는 경우에 연구개발비를 건별지급하여야 한다.", "effective_from": "2026-05-06", "effective_to": null, "is_active": true}, {"article_key": "MAIN_ART_62", "article_number": "62", "article_title": "영리기관 연구개발비 이관", "section": "MAIN", "source_article": "제62조", "paragraph_start": 437, "paragraph_end": 437, "original_text": "제62조(영리기관 연구개발비 이관) 연구개발과제의 협약이 체결된 후에 연구개발기관이 영리기관에서 다른 기관ㆍ단체로 변경된 경우에는 영리기관은 직접비와 간접비 잔액을 다른 기관ㆍ단체로 이관하여야 한다.", "effective_from": "2026-05-06", "effective_to": null, "is_active": true}, {"article_key": "MAIN_ART_63", "article_number": "63", "article_title": "영리기관 간접비비율 적용기준", "section": "MAIN", "source_article": "제63조", "paragraph_start": 438, "paragraph_end": 438, "original_text": "제63조(영리기관 간접비비율 적용기준) 영리기관이 사용하는 연구개발비의 간접비비율은 연구개발과제(연구개발과제가 단계로 구분된 경우에는 해당 단계를 말한다)가 시작되는 시점에 해당 영리기관의 간접비고시비율의 범위에서 필요한 비율을 적용하는 것을 원칙으로 한다.", "effective_from": "2026-05-06", "effective_to": null, "is_active": true}, {"article_key": "MAIN_ART_64", "article_number": "64", "article_title": "영리기관 연구개발비 현금ㆍ현물 구분기준", "section": "MAIN", "source_article": "제64조", "paragraph_start": 439, "paragraph_end": 443, "original_text": "제64조(영리기관 연구개발비 현금ㆍ현물 구분기준) ① 영리기관의 장은 직접비를 다음 각 호에서 정하는 바에 따라 현금 또는 현물로 계상하여야 한다. 다만, 제65조부터 제68조까지에서 따로 정하는 경우에는 그에 따른다.\n1. 영리기관이 연구개발과제(연구개발과제가 단계로 구분된 경우에는 해당 단계를 말한다. 이하 이 조에서 같다)의 연구개발기간 시작일 전 보유한 자산의 가액은 현물로 계상\n2. 영리기관이 연구개발과제 연구개발기간 동안 구입ㆍ임차하는 비용(부대비용을 포함한다) 및 사용대차에 따른 부대비용은 현금 또는 현물로 계상\n② 영리기관의 장은 부담하여야 하는 연구개발비 중 현물로 부담할 수 있는 사용용도에 대하여 동일한 금액을 현금으로 부담할 수 있다.\n③ 영리기관의 장은 간접비를 현금으로 계상하여야 한다.", "effective_from": "2026-05-06", "effective_to": null, "is_active": true}, {"article_key": "MAIN_ART_65", "article_number": "65", "article_title": "영리기관 인건비 사용기준", "section": "MAIN", "source_article": "제65조", "paragraph_start": 444, "paragraph_end": 462, "original_text": "제65조(영리기관 인건비 사용기준) ① 영리기관의 장은 참여연구자의 인건비를 월 단위로 다음의 계산식에 따른 인건비계상률에 따라 계상하여야 한다.\n② 영리기관의 장과 참여연구자는 협의하여 제1항에 따른 인건비계상률을 월 단위로 산출하고, 이를 연구비통합관리시스템에 해당 회계연도 종료일까지 입력하여야 한다.\n③ 참여연구자의 월 급여는 다음 각 호의 법령과 규정 등에 따라 지급하는 1개월간의 급여(연구수당 및 연구개발능률성과급은 제외한다) 총액으로 한다. 다만, 출산전후휴가 기간 동안의 급여는 관계 법령 또는 자체규정에 따라 영리기관이 지급할 의무가 있는 급여 총액(「고용보험법」 등에 따라 정부에서 지원받을 수 있는 금액은 제외한다)으로 한다.\n1. 참여연구자가 영리기관에 소속된 경우:「근로기준법」 등 관련 법령과 영리기관의 인사규정, 취업규칙 등 자체규정\n2. 참여연구자가 영리기관에 소속되지 아니한 경우\n가.참여연구자가 다른 기관ㆍ단체에 소속된 경우: 「근로기준법」 등 관련 법령과 참여연구자의 소속 기관ㆍ단체의 인사규정, 취업규칙 등 자체규정\n나.참여연구자가 다른 기관ㆍ단체에 소속되지 아니한 경우(개인사업자 및 강사를 포함한다): 참여연구자가 연구개발과제를 수행하는 영리기관과 체결한 연구참여계약서에 명시된 기준\n④ 영리기관의 장은 다음 각 호의 어느 하나에 해당하는 참여연구자에 대하여는 인건비를 현금으로 계상할 수 있다.\n1. 중소ㆍ중견기업인 연구개발기관이 신규로 채용하는 참여연구자(채용일부터 연구개발과제 공고일까지의 기간이 6개월 이내인 연구자를 포함한다)\n2. 「연구산업진흥법」제2조제1호가목 및 나목의 산업을 영위하는 사업자 중 제6조제1항에 따른 전문사업연구자로 신고한 연구개발기관에 소속되어 해당 연구개발과제에 참여하는 참여연구자\n3. 연구개발성과의 전부 또는 일부를 국가의 소유로 하는 연구개발과제의 참여연구자로서 중앙행정기관의 장이 인건비의 현금 계상이 필요하다고 인정하는 참여연구자\n4. 중소ㆍ중견기업인 연구개발기관이 채용한 참여연구자 중 제1호에 해당하지 아니하는 참여연구자로서 중앙행정기관의 장이 인건비의 현금 계상이 필요하다고 인정하는 참여연구자\n5. 대기업인 연구개발기관이 채용한 참여연구자로서 중앙행정기관의 장이 인건비의 현금 계상이 필요하다고 인정하는 참여연구자\n6. 그 밖에 중앙행정기관의 장이 인건비의 현금 계상이 필요하다고 인정하는 참여연구자\n⑤ 삭제\n⑥ 영리기관의 장은 제4항에 따른 참여연구자의 인건비를 별지 제3호 서식에 따라 구분하여 관리하여야 한다.\n⑦ 영리기관의 장은 소속 참여연구자별로 총인건비계상률이 월 100퍼센트를 초과하지 아니 하도록 관리하여야 한다.\n⑧ 영리기관의 장은 현금으로 계상하는 인건비를 원래계획보다 증액하거나 감액하여 계상하려는 때에는 제73조제1항제4호에 따라 중앙행정기관의 장의 사전 승인을 받아야 한다.\n⑨ 영리기관의 장은 다른 기관ㆍ단체에 소속된 참여연구자의 인건비를 계상하려는 때에는 해당 참여연구자가 연구개발과제에 참여함을 확인하는 서류를 해당 참여연구자의 소속 기관ㆍ단체로부터 제출받아야 하며, 다른 기관ㆍ단체에 소속된 참여연구자의 인건비를 계상한 때에는 그 금액을 해당 참여연구자의 소속 기관ㆍ단체에 통보하여야 한다.", "effective_from": "2026-05-06", "effective_to": null, "is_active": true}, {"article_key": "MAIN_ART_66", "article_number": "66", "article_title": "영리기관 연구시설ㆍ장비비 사용기준", "section": "MAIN", "source_article": "제66조", "paragraph_start": 463, "paragraph_end": 466, "original_text": "제66조(영리기관 연구시설ㆍ장비비 사용기준) ① 영리기관의 장은 해당 영리기관이 생산ㆍ판매하거나 연구개발과제가 시작되기 전부터 소유ㆍ임차ㆍ사용대차하고 있는 연구시설ㆍ장비 또는 연구개발과제가 시작된 후 영리기관의 자체재원으로 구입ㆍ임차ㆍ사용대차하고 있는 연구시설ㆍ장비에 대하여 연구시설ㆍ장비 구입ㆍ설치비를 구입가의 20퍼센트 내에서 현물로 계상하여야 한다. 이 경우 연구시설ㆍ장비 구입 완료일이 연구개발과제 시작일의 5년 이내이어야 하고, 영리기관의 자체규정에 따라 계상된 내용연수 만료일이 현물로 계상한 연도의 말일 이후이어야 한다.\n② 하나의 연구시설ㆍ장비에 대하여 여러 개의 연구개발과제에서 제1항에 따라 현물로 계상한 경우에 그 금액의 합이 해당 연구시설ㆍ장비의 구입가를 초과하여서는 아니 된다.\n③ 영리기관의 장이 국가연구개발사업으로 구축한 연구시설ㆍ장비를 연구개발과제에 현물로 계상한 경우에 해당 연구시설ㆍ장비는 연구시설ㆍ장비종합정보시스템(ZEUS)에 등록되어야 한다.\n④ 영리기관의 장은 해당 영리기관이 연구개발과제가 시작되는 날 전부터 소유ㆍ임차ㆍ사용대차하고 있는 부지ㆍ시설ㆍ장비에 대하여 연구인프라조성비를 현물로 계상하여야 한다.", "effective_from": "2026-05-06", "effective_to": null, "is_active": true}, {"article_key": "MAIN_ART_67", "article_number": "67", "article_title": "영리기관의 연구재료비 사용기준", "section": "MAIN", "source_article": "제67조", "paragraph_start": 467, "paragraph_end": 467, "original_text": "제67조(영리기관의 연구재료비 사용기준) 영리기관의 장은 해당 영리기관이 생산ㆍ판매하거나 연구개발과제가 시작되기 전부터 소유하고 있는 시약ㆍ재료 또는 연구개발과제가 시작된 후 영리기관의 자체재원으로 구입한 시약ㆍ재료에 대하여 연구재료 구입비를 현물로 계상하여야 한다.", "effective_from": "2026-05-06", "effective_to": null, "is_active": true}, {"article_key": "MAIN_ART_68", "article_number": "68", "article_title": "영리기관의 연구활동비 사용기준", "section": "MAIN", "source_article": "제68조", "paragraph_start": 468, "paragraph_end": 472, "original_text": "제68조(영리기관의 연구활동비 사용기준) ① 영리기관의 장은 연구개발과제가 시작되기 전 또는 연구개발과제가 시작된 후에 영리기관의 자체재원으로 도입한 기술에 대하여 기술도입비를 실제 기술 도입에 소요된 비용의 50퍼센트 이내에서 현물로 계상하여야 한다. 이 경우 해당 기술의 도입 완료일이 연구개발과제 시작일의 2년 이내이어야 한다.\n② 영리기관의 장은 연구개발과제가 시작되기 전 구입ㆍ임차한 소프트웨어(영리기관이 개발한 소프트웨어 및 사무용 소프트웨어는 제외한다. 이하 이 조에서 같다) 또는 연구개발과제가 시작된 후 영리기관의 자체재원으로 구입ㆍ임차하고 있는 소프트웨어에 대하여 소프트웨어 활용비를 구입가의 20퍼센트 내에서 현물로 계상하여야 한다. 이 경우 소프트웨어 구입 완료일이 연구개발과제 시작일로 부터 5년 이내이어야 하고, 영리기관의 자체규정에 따라 계상된 내용연수 만료일이 현물로 계상한 연도의 말일 이후이어야 한다.\n③ 하나의 소프트웨어에 대하여 여러 개의 연구개발과제에서 제2항에 따라 현물로 계상한 경우에 그 금액의 합이 해당 소프트웨어의 구입가를 초과하여서는 아니 된다.\n④ 영리기관의 장은 연구실운영비 중 연구실 운영에 필요한 소모성 비용을 계상하여서는 아니 되며, 사무용 기기 및 사무용 소프트웨어에 소요되는 비용, 연구실 냉난방 및 청결한 환경 유지비용을 연구개발과제의 협약 체결 당시 별지 제4호 서식에 따른 영리기관의 연구실운영비활용ㆍ관리계획을 작성하여 연구개발계획서에 첨부한 경우에만 계상할 수 있다.\n⑤ 영리기관의 장은 제2항에 따른 영리기관의 연구실운영비활용ㆍ관리계획을 변경하여 사용하고자 하는 경우에는 제73조제1항제6호에 따른 중앙행정기관의 장의 사전 승인을 받아야 한다.", "effective_from": "2026-05-06", "effective_to": null, "is_active": true}, {"article_key": "MAIN_ART_69", "article_number": "69", "article_title": "영리기관 간접비 사용기준", "section": "MAIN", "source_article": "제69조", "paragraph_start": 473, "paragraph_end": 481, "original_text": "제69조(영리기관 간접비 사용기준) ① 영리기관의 장은 연구개발과제별로 별도 계정을 설정하여 간접비를 관리하여야 한다.\n② 영리기관의 장은 간접비를 연구개발과제의 연구개발기간 동안에 사용하여야 한다.\n③ 영리기관의 장은 연구개발능률성과급을 해당 연구개발과제 간접비의 10퍼센트 이하로 계상하여야 한다.\n④ 영리기관의 장은 연구개발능률성과급을 지급할 때에 참여연구자와 연구지원인력을 모두 포함하여 자체적으로 성과평가를 실시한 후 지급하여야 한다.\n⑤ 영리기관의 장은 다음 각호에 해당하는 자의 육아휴직기간동안 4대보험의 기관부담금 및 퇴직급여충당금을 계상하려는 경우 해당 연구개발과제의 간접비로 계상하여야한다.\n1. 연구개발과제에서 인건비를 지급받는 연구지원인력\n2. 제65조 제4항 각호에 따른 연구개발과제의 참여연구자\n⑥ 영리기관의 장은 연구실안전관리비를 계상할 때 「연구실 안전환경 조성에 관한 법률」 제22조제3항, 「연구실 안전환경 조성에 관한 법률 시행규칙」 제13조에 따라 정하는 금액 이상으로 계상하여야 한다.\n제7절 사용절차 등", "effective_from": "2026-05-06", "effective_to": null, "is_active": true}, {"article_key": "MAIN_ART_70", "article_number": "70", "article_title": "연구개발비 사용절차", "section": "MAIN", "source_article": "제70조", "paragraph_start": 482, "paragraph_end": 497, "original_text": "제70조(연구개발비 사용절차) ① 연구개발비는 연구개발기관의 장이 사용하여야 한다. 이 경우 직접비 중 다음 각 호의 사용용도에 해당하는 경우에는 연구책임자의 발의를 거쳐야 한다.\n1. 연구시설ㆍ장비비(제101조제1항에 따른 통합관리하는 연구시설ㆍ장비비는 제외한다)\n2. 연구재료비\n3. 연구활동비\n4. 연구수당\n② 연구개발기관의 장은 연구개발비 사용내역을 다음 각 호에서 정하는 바에 따라 연구비통합관리시스템에 입력하여야 한다.\n1. 일괄지급 대상 연구개발과제: 다음 각 목에서 정하는 시기에 연구개발비 사용내역을 연구비통합관리시스템에 입력\n가.연구개발비카드를 사용한 경우: 연구개발비카드 결제대금이 이체되는 날부터 5일 이내\n나.그 밖의 경우: 연구개발비를 사용한 날부터 5일 이내\n2. 건별지급 대상 연구개발과제: 다음 각 목에서 정하는 시기에 연구개발비 사용내역(증명자료를 포함한다)을 연구비통합관리시스템에 입력\n가.연구개발비카드를 사용한 경우: 연구개발비카드를 결제한 날부터 카드결제대금이 이체되는 날의 전일까지\n나.그 밖의 경우: 연구개발비를 사용하기 전\n③ 제2항제1호에도 불구하고 일괄지급 대상 연구개발과제의 인건비 등에 대하여는 다음 호의 기준에 따라 사용내역을 연구비통합관리시스템에 입력할 수 있다.\n1. 인건비 및 학생인건비: 해당 회계연도 종료일까지\n2. 제22조제4항 각 호의 어느 하나에 해당하는 비용: 사용실적 보고일까지\n3. 정부출연기관의 기본사업의 연구개발비(제1호ㆍ제2호를 제외한다): 연구개발비 사용 후 1개월 이내", "effective_from": "2026-05-06", "effective_to": null, "is_active": true}, {"article_key": "MAIN_ART_71", "article_number": "71", "article_title": "연구개발비 지급 이전의 사용", "section": "MAIN", "source_article": "제71조", "paragraph_start": 498, "paragraph_end": 499, "original_text": "제71조(연구개발비 지급 이전의 사용) ① 중앙행정기관의 장과 연구개발기관의 장은 연구개발과제 협약을 체결할 때에 연구개발기간의 시작일을 연구개발기관 선정통보일이 포함된 월의 첫 날부터 협약 체결일까지 중 어느 하루로 정할 수 있다.\n② 중앙행정기관의 장은 부득이하게 연구개발과제 협약 체결 또는 연구개발비 지급이 지연된 경우 연구개발기간의 시작일부터 연구개발비 지급일까지 연구개발과제 수행을 위하여 연구개발기관의 자체재원을 활용한 것을 정부가 지원한 연구개발비를 사용한 것으로 인정할 수 있다.", "effective_from": "2026-05-06", "effective_to": null, "is_active": true}, {"article_key": "MAIN_ART_72", "article_number": "72", "article_title": "연구개발비 사용 증명자료의 보관", "section": "MAIN", "source_article": "제72조", "paragraph_start": 500, "paragraph_end": 504, "original_text": "제72조(연구개발비 사용 증명자료의 보관) ① 연구개발기관의 장은 연구개발비 사용에 관한 증명자료를 연구개발과제(연구개발과제가 단계로 구분된 경우 해당 단계를 말한다)가 종료된 후 5년간 보관하여야 한다.\n② 연구개발기관의 장은 제1항에 따른 증명자료가 「전자문서 및 전자거래 기본법」 제5조제1항 각 호의 요건을 모두 갖춘 전자문서 또는 제5조제2항 각 호의 요건을 모두 갖춘 전자화문서인 경우에 그 증명자료를 보관함으로써 관계 법령에서 정하는 문서의 보관을 갈음할 수 있다. 다만, 다른 법령에 특별한 규정이 있는 경우에는 그 법령의 해당 규정에 따른다.\n③ 제1항 및 제2항에도 불구하고 법 제20조에 따른 통합정보시스템에 제출하여 등록된 자료는 보관한 것으로 간주한다.\n④ 그 밖에 증명자료의 보관에 관하여는 「전자문서 및 전자거래 기본법」 등 관련 법령에 따라야 한다.\n제3장 연구개발비 사용 계획의 변경을 위하여 사전 승인이 필요한 경우에 대한 사항", "effective_from": "2026-05-06", "effective_to": null, "is_active": true}, {"article_key": "MAIN_ART_73", "article_number": "73", "article_title": "사전 승인 대상", "section": "MAIN", "source_article": "제73조", "paragraph_start": 505, "paragraph_end": 530, "original_text": "제73조(사전 승인 대상) ① 법 제13조제4항제3호에 따라 연구개발비 사용계획의 변경을 위하여 중앙행정기관의 장의 사전 승인이 필요한 경우는 다음 각 호와 같다.\n1. 전체 연구개발기간 동안의 연구개발비 총액(연구개발과제가 단계로 구분되는 경우에는 해당 단계의 총액을 말한다)을 변경하려는 경우\n2. 연도별 정부지원연구개발비 또는 기관부담연구개발비를 변경(현금부담금액과 현물부담금액의 변경을 포함한다)하려는 경우\n3. 전체 연구개발기간 동안의 간접비 총액(연구개발과제가 단계로 구분되는 경우에는 해당단계의 간접비 총액을 말한다)을 증액하려는 경우\n4. 영리기관이 현금으로 계상하려는 인건비를 변경하려는 경우로서 다음 각 목의 어느 하나에 해당하는 경우\n가.인건비 총액이 변경되는 경우\n나.신규인력에 대한 현금 계상 인건비가 감액되는 경우\n5. 연구시설ㆍ장비비와 관련된 변경 중 다음 각 목의 어느 하나에 해당하는 경우\n가.원래계획에 반영되지 아니한 3천만 원(부가가치세 및 구입ㆍ설치 등에 필요한 부대비용을 포함한다) 이상이 소요되는 연구시설ㆍ장비를 새로 구입하거나 임차하려는 경우\n나.원래계획에 반영된 3천만 원(부가가치세 및 구입ㆍ설치 등에 필요한 부대비용을 포함한다) 이상이 소요되는 연구시설ㆍ장비를 변경하여 구입하거나 임차하려는 경우(다만, 환율변동, 물가상승 등 불가피한 사유로 원래계획에 반영된 금액의 20% 이내로 증감되는 경우는 제외한다)\n다.원래계획에 반영된 3천만 원(부가가치세 및 구입ㆍ설치 등에 필요한 부대비용을 포함한다) 이상이 소요되는 연구시설ㆍ장비를 구입 또는 임차하지 않으려는 경우(원래계획에 따라 구입하거나 임차하려던 연구시설ㆍ장비를 연구시설ㆍ장비종합정보시스템(ZEUS)을 통하여 다른 기관으로부터 무상으로 이전받은 경우는 제외한다)\n라.연구시설ㆍ장비 구축을 주된 목적으로 하는 연구개발과제로 구축된 연구시설ㆍ장비를 원래계획에 따른 공간 외의 장소에 설치ㆍ운영하려는 경우\n6. 영리기관의 장이 연구활동비 중 연구실운영비를 원래계획과 다르게 변경하려는 경우로서 다음 각 목의 어느 하나에 해당하는 경우\n가.총 금액이 증액되는 경우\n나.품목이 변경되는 경우\n다.특정 품목의 수량이 증가되는 경우\n7. 위탁연구개발비를 원래계획의 20퍼센트 이상 증액하여 사용하려는 경우\n8. 국제공동연구개발비를 원래계획과 다르게 변경하려는 경우(단, 환율의 변동만으로 금액이 달라지는 경우에는 제외한다)\n9. 해당 단계의 연구개발비 중 직접비(현물 및 연구수당은 제외한다)를 다음 단계의 연구개발비에 포함하여 사용하려는 경우\n10. 제26조제3항에 따라 전체 연구개발기간 동안의 연구수당 총액(연구개발과제가 단계로 구분되는 경우에는 해당단계의 연구수당 총액을 말한다)을 증액하려는 경우\n11. 연구시설ㆍ장비비통합관리계정에 적립할 금액을 변경하려는 경우\n12. 전체 연구개발기간 동안의 해외연구자 유치 지원비 총액(연구개발과제가 단계로 구분되는 경우에는 해당 단계의 해외연구자 유치 지원비 총액을 말한다)을 증액하려는 경우(단, 환율의 변동만으로 금액이 달라지는 경우에는 제외한다)\n13. 제25조의2제4항에 따라 전체 연구개발기간 동안의 연구혁신비 총액(연구개발과제가 단계로 구분되는 경우에는 해당 단계의 연구혁신비 총액을 말한다)을 증액하려는 경우\n② 제1항에도 불구하고 다음 각 목의 어느 하나에 해당하는 경우에는 연구개발비 사용계획의 변경을 위한 중앙행정기관의 장의 사전 승인을 필요로 하지 아니 한다.\n1. 정부출연기관의 기본사업인 경우\n2. 중앙행정기관의 장이 국가안보 또는 사회ㆍ경제적 긴급한 상황 등에 따라 필요하다고 인정하는 경우", "effective_from": "2026-05-06", "effective_to": null, "is_active": true}, {"article_key": "MAIN_ART_74", "article_number": "74", "article_title": "사전 승인 절차", "section": "MAIN", "source_article": "제74조", "paragraph_start": 531, "paragraph_end": 534, "original_text": "제74조(사전 승인 절차) ① 연구개발기관의 장은 제73조제1항 각 호의 사항을 사전 승인 받고자 하는 경우에는 중앙행정기관의 장에게 연구개발비 사용 계획의 변경 사유와 내용을 제출하여야 한다.\n② 중앙행정기관의 장은 연구개발기관의 장이 제출한 변경 사유와 내용에 보완이 필요한 경우에 그 보완을 요구할 수 있다.\n③ 중앙행정기관의 장은 연구개발비 사용 계획의 변경 승인 여부를 사용계획 변경신청 접수 후 15일 이내에 연구개발기관의 장에게 통보하여야 한다. 다만, 중앙행정기관의 장은 15일 이내에 변경 승인 여부를 결정하기 어려운 경우 기간을 연장할 수 있으며 연장한 기간을 연구개발기관의 장에게 통보하여야 한다.\n제4장 정부가 지원한 연구개발비 이자의 사용용도", "effective_from": "2026-05-06", "effective_to": null, "is_active": true}, {"article_key": "MAIN_ART_75", "article_number": "75", "article_title": "정부지원금이자의 사용용도", "section": "MAIN", "source_article": "제75조", "paragraph_start": 535, "paragraph_end": 544, "original_text": "제75조(정부지원금이자의 사용용도) ① 연구개발기관의 장은 연구개발과제의 연구개발기간(단계로 구분된 경우 해당 단계로 한다. 이하 이장에서 같다.) 및 연구개발기간 종료 후 기간 동안 정부가 지원한 연구개발비에서 발생한 이자(이하 \"정부지원금이자\"라고 한다)를 국고 또는 해당 기금에 납입하여야 한다. 다만, 중앙행정기관의 장의 승인을 받은 경우 다음 각 호의 용도로 사용할 수 있다.\n1. 해당 연구개발과제의 연구개발비에 산입\n2. 연구개발에 재투자\n3. 연구개발성과의 창출지원, 보호, 활용역량의 강화\n4. 그 밖에 중앙행정기관의 장의 승인을 받은 용도\n② 제1항에도 불구하고 제87조제1항에 따른 학생인건비통합관리계정, 제101조제2항에 따른 연구시설ㆍ장비비통합관리계정 및 정부출연기관의 기본사업비에서 발생한 이자는 다음 각 호의 용도로 사용할 수 있다.\n1. 제87조제1항에 따른 학생인건비통합관리계정에 산입(학생인건비통합관리계정에서 발생한 이자만 해당한다)\n2. 제101조제2항에 따른 연구시설ㆍ장비비통합관리계정에 산입(연구시설ㆍ장비비통합관리계정에서 발생한 이자만 해당한다)\n3. 정부출연기관의 기본사업비(정부출연기관의 기본사업비에서 발생하는 이자만 해당한다)\n③ 연구개발기관의 장은 제1항 각 호에 따른 용도로 정부지원연구개발비의 이자를 사용하는 경우 그 사용내역을 해당 과제의 사용실적보고서등에 포함하여 중앙행정기관의 장에게 제출해야 한다.", "effective_from": "2026-05-06", "effective_to": null, "is_active": true}, {"article_key": "MAIN_ART_76", "article_number": "76", "article_title": "전문기관 등의 이자 납입", "section": "MAIN", "source_article": "제76조", "paragraph_start": 545, "paragraph_end": 545, "original_text": "제76조(전문기관 등의 이자 납입) 전문기관(연구비관리전담기관을 포함한다)의 장은 중앙행정기관의 장의 연구개발비 지급 업무를 대행하면서 정부가 지원하려는 연구개발비에서 발생한 이자를 국고 또는 해당 기금에 납입하여야 한다.", "effective_from": "2026-05-06", "effective_to": null, "is_active": true}, {"article_key": "MAIN_ART_77", "article_number": "77", "article_title": "정부지원금이자 산출기준", "section": "MAIN", "source_article": "제77조", "paragraph_start": 546, "paragraph_end": 546, "original_text": "제77조(정부지원금이자 산출기준) 정부지원금이자는 다음 계산식에 따라 계산한 금액으로 한다.", "effective_from": "2026-05-06", "effective_to": null, "is_active": true}, {"article_key": "MAIN_ART_78", "article_number": "78", "article_title": "연구개발기관의 정부지원금이자 납입", "section": "MAIN", "source_article": "제78조", "paragraph_start": 547, "paragraph_end": 548, "original_text": "제78조(연구개발기관의 정부지원금이자 납입) 연구개발기관의 장이 정부지원금이자를 제75조제1항 각 호 외의 부분 및 같은 조 제2항에 따라 국고 또는 해당 기금에 납입하려는 경우에 납입 절차와 방법에 대하여는 제83조에 따른 연구개발비 회수에 관한 규정을 준용한다.\n제5장 연구개발비 정산ㆍ회수의 방법과 절차", "effective_from": "2026-05-06", "effective_to": null, "is_active": true}, {"article_key": "MAIN_ART_79", "article_number": "79", "article_title": "연구개발비 정산 대상", "section": "MAIN", "source_article": "제79조", "paragraph_start": 549, "paragraph_end": 553, "original_text": "제79조(연구개발비 정산 대상) 법 제13조제7항에 따라 중앙행정기관의 장이 실시하는 정산은 다음 각 호의 연구개발비를 대상으로 한다.\n1. 정부가 지원하는 연구개발비\n2. 연구개발기관이 부담하는 연구개발비\n3. 그 외 기관ㆍ단체ㆍ개인이 지원하는 연구개발비\n4. 정부지원금이자 중 해당 연구개발과제의 연구개발비에 산입한 금액", "effective_from": "2026-05-06", "effective_to": null, "is_active": true}, {"article_key": "MAIN_ART_80", "article_number": "80", "article_title": "연구개발비 정산기준", "section": "MAIN", "source_article": "제80조", "paragraph_start": 554, "paragraph_end": 575, "original_text": "제80조(연구개발비 정산기준) ① 중앙행정기관의 장은 연구개발기관이 부담한 연구개발비가 영 제19조제1항에 따른 연구개발비 부담기준에 부합하고, 연구개발기관이 사용한 연구개발비가 영 제20조제1항에 따른 사용용도, 제5조부터 제72조까지에 따른 연구개발비의 계상기준, 인정기준 및 사용절차, 제73조부터 제74조까지에 따른 사전승인이 필요한 경우, 제75조부터 제78조까지에 따른 이자의 사용용도에 부합하는 경우에 해당 연구개발비를 적정하게 사용한 연구개발비로 인정하여야 한다.\n② 중앙행정기관의 장은 비영리기관에 지급된 간접비가 간접비 관리를 위한 별도 계정에, 학생인건비통합관리기관에 지급된 학생인건비가 제87조제1항에 따른 학생인건비통합관리계정에, 연구시설ㆍ장비비통합관리기관에 지급된 연구시설ㆍ장비비가 제101조제2항에 따른 연구시설ㆍ장비비통합관리계정에 기한 내 이체 또는 계정대체된 경우에 해당 연구개발비를 적정하게 사용한 연구개발비로 인정할 수 있다.\n③ 중앙행정기관의 장은 연구개발기관의 장이 제22조제4항제4호에 따라 사용할 것으로 예상하는 논문게재료ㆍ저술출판비용은 적정하게 사용한 연구개발비로 간주한다. 다만, 연구비통합관리시스템에 논문게재료 등의 실제 사용금액을 연구개발기간 종료일로부터 2년 이내에 입력하여야 한다.\n④ 중앙행정기관의 장은 직접비 중 제1항 및 제2항에 따라 적정하게 사용한 직접비로 인정한 금액을 제외한 금액을 영 제26조제5항제1호에 따른 직접비 사용 잔액으로 본다.\n⑤ 중앙행정기관의 장은 영리기관(공기업은 제외한다)에 대하여 간접비 중 제1항에 따라 적정하게 사용한 간접비로 인정한 금액을 제외한 금액을 영 제26조제5항제5호에 따른 간접비 사용 잔액으로 본다.\n⑥ 제2항에도 불구하고 중앙행정기관의 장이 법 제11조제4항에 따라 협약이 해약된 경우의 간접비 사용 잔액을 산출하는 경우 다음 각 호에 따른다.\n1. 법 제15조제1항제1호, 제2호 및 제5호에 해당하는 연구개발기관 또는 연구자의 귀책사유로 중단되는 경우에는 다음 각 목에 따라 계산한 금액 중 많은 금액\n가.중단일이 포함된 달의 간접비 1개월분 전액을 포함하여 간접비를 월할 계산한 금액\n나.영 제26조제5항제3호의 계산식에 따라 계산한 금액\n2. 연구개발기관 또는 연구자의 귀책사유가 아닌 사유로 협약이 해약되는 경우에는 영 제26조제5항제3호의 계산식에 따라 계산한 금액\n⑦ 연구개발기관의 장은 연구개발비 사용실적보고서를 제출할 때에 별지 제5호 서식에 따른 자체 회계감사 의견서를 함께 제출하여야 하고, 연구개발기관의 자체규정을 적용하여 연구개발비를 계상한 경우 해당 자체규정을 함께 제출하여야 한다.\n⑧ 연구개발기관의 장은 연구개발비를 현물로 부담한 경우 연구개발비 사용실적보고서를 제출할 때에 별지 제6호 서식에 따른 현물부담 확인서를 제출하여야 한다.\n⑨ 제8항에 따라 중앙행정기관의 장이 현물부담 확인서를 제출받은 경우 연구개발기관이 연구개발비를 현물로 적정하게 부담한 것으로 추정한다. 다만, 중앙행정기관의 장은 연구개발기관의 현물부담 금액이 제1항에 따라 적정하게 사용되었음을 확인하기 위한 경우 또는 제출받은 현물부담 확인서에 오류나 누락이 있다고 판단되는 경우에는 제81조에 따른 방법으로 정산을 실시할 수 있다.\n⑩ 중앙행정기관의 장은 법 제11조제4항에 따라 연구개발과제 협약이 해약된 경우에는 해약된 날을 연구개발기간 종료일로 보고 정산하여야 한다.\n⑪ 중앙행정기관의 장은 연구개발기관의 장이 연구개발과제(연구개발과제가 단계로 구분되는 경우에는 해당 단계를 말한다)가 종료된 날부터 3개월 이내에 사용실적보고서를 제출하지 아니한 경우 연구비통합관리시스템에 입력된 사용내역을 사용실적보고서 등으로 갈음할 수 있다.\n⑫ 영 제26조제3항제3호에서 \"연구개발비 규모와 정산 필요성 등을 고려하여 과학기술정보통신부장관이 정하여 고시하는 방법\"이란 매월 연구개발기간이 종료되는 연차별 연구개발비 평균 금액이 5천만원 미만인 연구개발과제(이하 \"소액 과제\"라 한다) 중 다음 각 호에 어느 하나에 해당하는 연구개발과제(이하 \"필수 선별 대상 과제\"라 한다)를 해당 월에 종료되는 소액 과제 수를 기준으로 15퍼센트의 범위 내에서 선별하는 것을 말한다.\n1. 연구개발비 사용실적보고서를 정당한 사유없이 기한내에 제출하지 않은 연구개발과제\n2. 법 제12조제3항에 따른 단계평가 또는 제15조제1항(단, 같은 항 제3호 및 제4호의 경우는 제외한다)에 따른 특별평가 결과에 따라 중단된 연구개발과제\n3. 국회, 감사원 등 외부지적사항이 존재하는 연구개발과제\n4. 법 제31조제1항에 따라 국가연구개발사업 관련 부정행위가 발생한 연구개발과제\n5. 그 밖에 중앙행정기관의 장이 정산이 필요하다고 인정하는 연구개발과제\n⑬ 중앙행정기관의 장은 제12항에도 불구하고 해당 월의 모든 필수 선별 대상 과제의 정산을 실시할 수 있다.", "effective_from": "2026-05-06", "effective_to": null, "is_active": true}, {"article_key": "MAIN_ART_81", "article_number": "81", "article_title": "연구개발비 정산 방법", "section": "MAIN", "source_article": "제81조", "paragraph_start": 576, "paragraph_end": 580, "original_text": "제81조(연구개발비 정산 방법) ① 중앙행정기관의 장은 연구비통합관리시스템을 통하여 정산을 실시하여야 한다. 다만, 중앙행정기관의 장이 연구비통합관리시스템을 통하여 정산을 실시하기 어렵다고 판단하는 경우에는 연구비통합관리시스템을 통하지 아니하고 정산을 실시할 수 있다.\n② 중앙행정기관의 장은 제1항 본문에 따라 정산을 실시하는 경우에 연구비통합관리시스템에 등록된 정보나 증명자료를 활용하여야 한다.\n③ 중앙행정기관의 장은 제1항 단서에 따라 정산을 실시하는 경우에 정산에 필요한 정보나 자료(참여연구자의 총인건비계상률에 관한 정보 및 연구개발기관의 부적절한 연구비 관리ㆍ사용으로 인해 내부 및 외부기관으로부터 수사ㆍ조사ㆍ감사ㆍ자료요구 등을 받은 사안 또는 결과를 포함한다)의 제출을 연구개발기관의 장에게 요구할 수 있다.\n④ 중앙행정기관의 장은 연구비통합관리시스템에 등록되거나 제3항에 따라 제출받은 정보나 증명자료에 오류나 누락이 발견된 경우에 연구개발기관의 장에게 해당 정보나 증명자료의 정정이나 보완을 요구할 수 있다. 다만, 중앙행정기관의 장이 불가피한 사유가 있다고 인정하는 경우에는 정보나 증명자료의 제출을 생략하게 할 수 있다.\n⑤ 중앙행정기관의 장은 정산을 실시할 때에 연구개발기관의 장에게 제72조제2항에 따라 보관되는 전자문서 및 전자화문서에 대한 출력을 요구하여서는 아니 된다.", "effective_from": "2026-05-06", "effective_to": null, "is_active": true}, {"article_key": "MAIN_ART_82", "article_number": "82", "article_title": "연구개발비 상시점검", "section": "MAIN", "source_article": "제82조", "paragraph_start": 581, "paragraph_end": 582, "original_text": "제82조(연구개발비 상시점검) ① 중앙행정기관의 장은 연구개발과제 수행에 지장을 주지 아니하는 범위 내에서 정산 실시 전에 연구비통합관리시스템을 통하여 연구개발비의 사용 내역을 점검하고, 그 결과 연구개발비 사용용도나 사용기준을 위반할 소지가 있다고 판단되는 사용 내역에 대하여는 연구개발기관의 장에게 확인을 요구할 수 있다.\n② 중앙행정기관의 장은 연구개발기관의 장이 제70조제2항 및 제3항에서 정하는 바에 따라 연구개발비 사용내역을 입력하지 아니하는 경우 연구개발기관의 장에게 확인을 요구할 수 있다.", "effective_from": "2026-05-06", "effective_to": null, "is_active": true}, {"article_key": "MAIN_ART_83", "article_number": "83", "article_title": "연구개발비 회수", "section": "MAIN", "source_article": "제83조", "paragraph_start": 583, "paragraph_end": 587, "original_text": "제83조(연구개발비 회수) ① 중앙행정기관의 장은 법 제13조제7항에 따라 연구개발과제(연구개발과제가 단계로 구분되는 경우에는 해당 단계를 말한다)가 종료된 날부터 3개월 이내에 연구개발비 정산에 착수하여야 하며, 제80조에 따라 정산 결과를 반영하여 다음 각 호에 해당하는 금액을 영 제26조제5항에 따른 회수 금액으로 결정하여 연구개발기관의 장에게 통보하여야 한다.\n1. 연구개발기관이 부담하는 연구개발비 중 현물로 부담한 금액이 다음의 계산식에 따라 산출된 현물 부담액(계산식에 따라 현물 부담액을 산출하는 것이 불가한 경우에는 협약에서 정한 현물 부담액으로 한다)보다 부족한 경우 그 부족분에 해당하는 금액\n2. 현금으로 계상된 연구개발비에서 적정하게 사용된 연구개발비로 인정하는 금액을 제외한 금액에 대하여는 다음의 계산식에 따라 계산된 정부 지원금 지분에 해당하는 금액\n② 중앙행정기관의 장은 제80조제3항에 따라 연구개발기관의 장이 예상한 논문게재료ㆍ저술출판비용과 연구비통합관리시스템에 입력된 금액의 차액을 회수 금액으로 결정하여 연구개발기관의 장에게 통보하여야 한다.\n③ 제1항, 제2항에 따라 회수 금액을 통보받은 연구개발기관의 장은 통보를 받은 날부터 1개월 이내에 중앙행정기관의 장이 지정하는 계좌에 회수 금액을 반납하여야 한다. 다만, 국가안보 또는 사회ㆍ경제적 긴급한 상황이 발생하여 중앙행정기관의 장이 연구개발비 회수의 시기와 방법을 달리 정하는 경우에는 이에 따라 회수 금액을 반납하여야 한다.", "effective_from": "2026-05-06", "effective_to": null, "is_active": true}, {"article_key": "MAIN_ART_84", "article_number": "84", "article_title": "연구개발비 정산 이의신청", "section": "MAIN", "source_article": "제84조", "paragraph_start": 588, "paragraph_end": 590, "original_text": "제84조(연구개발비 정산 이의신청) ① 연구개발기관의 장은 제83조제1항에 따라 통보받은 결과에 이의가 있는 경우 통보를 받은 날부터 1개월 이내에 별지 제7호 서식에 따른 국가연구개발사업 정산 이의신청서를 작성하여 중앙행정기관의 장에게 정산 이의신청을 할 수 있다. 이 경우 이의신청은 1회에 한한다.\n② 중앙행정기관의 장은 정산 이의신청을 검토한 결과 타당하다고 인정하는 경우 재정산을 실시하여 제83조제1항에 따라 결정한 회수 금액을 변경할 수 있다.\n③ 중앙행정기관의 장은 정산 이의신청이 타당하지 아니하다고 판단하거나 제2항에 따라 결정한 회수 금액을 변경한 경우에는 이를 연구개발기관의 장에게 통보하여야 한다. 이 경우 회수 금액의 반납에 관한 사항은 제83조제3항을 준용한다.", "effective_from": "2026-05-06", "effective_to": null, "is_active": true}, {"article_key": "MAIN_ART_85", "article_number": "85", "article_title": "연구개발비 회수의 유예", "section": "MAIN", "source_article": "제85조", "paragraph_start": 591, "paragraph_end": 594, "original_text": "제85조(연구개발비 회수의 유예) ① 중앙행정기관의 장은 연구개발기관이 부도ㆍ폐업ㆍ파산 또는 이에 준하는 경영 악화에 처하거나 재난, 재해, 그 밖에 경제적ㆍ사회적으로 중대한 사유가 발생하여 회수 금액을 제때 반납하기 곤란하다고 인정하는 경우에는 연구개발기관의 장의 신청을 받아 회수 금액의 반납기한을 2년의 범위에서 연장하거나 분할하여 납부하도록 할 수 있다.\n② 제1항에도 불구하고 중앙행정기관의 장이 회수 절차 진행을 위해 사용되는 금액이 회수 금액보다 큰 경우에는 제1항에 따른 회수 금액을 회수하지 아니할 수 있다.\n③ 중앙행정기관의 장은 제1항에 따른 반납기한의 연장 또는 제2항에 따른 회수 금액의 면제 여부를 검토하는 데 필요한 경우에 실태조사를 실시할 수 있다.\n제6장 학생인건비 사용의 특례", "effective_from": "2026-05-06", "effective_to": null, "is_active": true}, {"article_key": "MAIN_ART_86", "article_number": "86", "article_title": "학생인건비통합관리기관의 지정", "section": "MAIN", "source_article": "제86조", "paragraph_start": 595, "paragraph_end": 604, "original_text": "제86조(학생인건비통합관리기관의 지정) ① 과학기술정보통신부장관은 별표 2의 학생인건비통합관리기관 전산시스템 구축 요건을 충족하는 전산시스템과 제88조제1항에 따른 학생연구자 지원규정을 모두 갖추고 있는 대학 또는 정부출연기관을 학생인건비통합관리기관으로 지정할 수 있다.\n② 학생인건비통합관리기관으로 지정받으려는 연구개발기관의 장은 다음 각 호의 문서를 작성하여 과학기술정보통신부장관에게 신청하여야 한다.\n1. 별지 제8호 서식의 학생인건비통합관리기관 지정ㆍ변경 신청서\n2. 제1항에 따른 전산시스템의 구축 완료 보고서\n3. 제88조제1항에 따른 학생연구자 지원규정\n③ 과학기술정보통신부장관은 제2항에 따른 지정ㆍ변경 신청서 접수 후 제2항 각 호를 평가하여 학생인건비통합관리기관 지정 여부를 해당 연구개발기관의 장에게 신청을 받은 날부터 2개월 이내에 통보하여야 한다.\n④ 학생인건비통합관리기관의 장은 다음 각 호의 조치를 실시하여야 한다.\n1. 「연구실 안전환경 조성에 관한 법률」제26조제1항에 따른 보험 가입\n2. 연구비통합관리시스템과 제1항에 따른 전산시스템의 상호 연계\n3. 별표 3의 학생인건비통합관리기관의 학생인건비 표준정보에 따라 학생인건비 지급 정보 관리", "effective_from": "2026-05-06", "effective_to": null, "is_active": true}, {"article_key": "MAIN_ART_87", "article_number": "87", "article_title": "학생인건비통합관리계정의 설정", "section": "MAIN", "source_article": "제87조", "paragraph_start": 605, "paragraph_end": 613, "original_text": "제87조(학생인건비통합관리계정의 설정) ① 제86조제3항에 따라 학생인건비통합관리기관으로 지정받은 연구개발기관의 장은 학생인건비 관리를 위한 별도 계정(이하 \"학생인건비통합관리계정\"이라 한다)을 설정하여 하나 이상의 연구개발과제의 학생인건비를 통합관리하여야 한다.\n② 학생인건비통합관리기관의 장은 다음 각 호로 구분되는 학생인건비통합관리계정을 병행 설정하여야 한다. 다만, 과학기술정보통신부장관이 인정하는 경우에는 연구책임자계정만 설정할 수 있다.\n1. 각 목의 어느 하나 이상의 연구개발기관계정\n가.기관(대학의 경우 산학협력단) 단위로 관리하는 연구개발기관 전체 계정\n나.단과대학, 학과, 연구부서 등의 단위로 관리하는 연구개발기관 세부 계정(다만, 연구책임자계정이 설정되어 있거나 설정 예정인 소속 전임교원의 80퍼센트 이상이 동의하는 경우 설정할 수 있다)\n2. 연구책임자 단위로 관리하는 연구책임자계정\n③ 제2항 단서에 따라 연구책임자계정만 설정한 학생인건비통합관리기관(이하 \"연구책임자단위통합관리기관\"이라 한다)이 연구개발기관계정과 연구책임자계정을 병행 설정하는 학생인건비통합관리기관(이하 \"연구개발기관단위통합관리기관\"이라 한다)이 되려는 경우에는 제86조제2항 각 호의 문서를 과학기술정보통신부장관에게 제출하여야 하며, 과학기술정보통신부장관은 이를 검토하여 적절하다고 판단하는 경우에 해당 연구책임자단위통합관리기관을 연구개발기관단위통합관리기관으로 변경하여 지정하여야 한다.\n④ 학생인건비통합관리기관의 장은 학생인건비통합관리계정별로 학생인건비통합관리계정의 계정책임자를 설정할 수 있다.\n⑤ 학생인건비통합관리기관의 장은 제1항에 따라 통합관리하는 학생인건비를 전용 계좌에 이체하여 별도로 구분하여 관리하여야 한다.", "effective_from": "2026-05-06", "effective_to": null, "is_active": true}, {"article_key": "MAIN_ART_88", "article_number": "88", "article_title": "학생연구자 지원규정 마련ㆍ운영", "section": "MAIN", "source_article": "제88조", "paragraph_start": 614, "paragraph_end": 623, "original_text": "제88조(학생연구자 지원규정 마련ㆍ운영) ① 학생인건비통합관리기관의 장은 다음 각 호의 사항을 포함하는 학생연구자 지원규정을 마련하여 운영하여야 한다.\n1. 학생연구자의 학업ㆍ연구개발활동 보장, 처우 개선, 인권ㆍ권익 보호 및 관리ㆍ감독 등에 관한 사항\n2. 제86조제1항에 따른 전산시스템의 구축 및 운영에 관한 사항\n3. 제87조에 따른 학생인건비통합관리계정의 설정 및 관리에 관한 사항\n4. 학생인건비 수입ㆍ지출ㆍ잔액 관리에 관한 사항\n5. 학생인건비 계상기준에 관한 사항\n6. 제91조제2항ㆍ제3항에 따른 연구참여확약서 작성ㆍ변경에 관한 사항\n7. 제92조에 따른 학생인건비부당회수 방지에 관한 사항\n8. 학생연구자의 상해ㆍ사망에 대비하는 보험 가입에 관한 사항\n② 학생인건비통합관리기관의 장은 제1항에 따른 학생연구자 지원규정을 기관 홈페이지 등을 통하여 공개하여야 한다.", "effective_from": "2026-05-06", "effective_to": null, "is_active": true}, {"article_key": "MAIN_ART_89", "article_number": "89", "article_title": "학생인건비의 계상", "section": "MAIN", "source_article": "제89조", "paragraph_start": 624, "paragraph_end": 624, "original_text": "제89조(학생인건비의 계상) 제40조 및 제49조에도 불구하고 학생인건비통합관리기관의 장은 연구개발과제별로 학생인건비 총액만을 계상하고, 학생연구자별로 학생인건비를 계상하여서는 아니 된다.", "effective_from": "2026-05-06", "effective_to": null, "is_active": true}, {"article_key": "MAIN_ART_90", "article_number": "90", "article_title": "학생인건비의 사용", "section": "MAIN", "source_article": "제90조", "paragraph_start": 625, "paragraph_end": 628, "original_text": "제90조(학생인건비의 사용) ① 학생인건비통합관리기관의 장은 연구개발비를 전체 또는 일부 지급받거나 학생인건비를 변경하는 날부터 90일 이내 또는 해당 연차 연구개발기간 종료일 중 먼저 도래하는 날까지 해당 학생인건비를 해당 과제 연구책임자의 학생인건비통합관리계정으로 이체하여야 한다. 이 경우, 해당 연차 연구개발기간 종료일까지 전체 금액을 이체 완료하여야 한다.\n② 제1항에도 불구하고 학생인건비통합관리기관의 장이 인정하는 경우에는 기관 내 해당 과제 연구책임자의 연구책임자계정 대신 참여연구자의 연구책임자계정으로 이체할 수 있다.\n③ 제1항 및 제2항에 따라 학생인건비통합관리계정으로 이체된 학생인건비는 해당 단계에 등록된 학생연구자가 있을 때 사용실적보고서등에서 사용된 연구개발비로 본다.\n④ 통합관리하는 학생인건비 사용 증명자료는 연구개발기관의 자체규정에 따라 관리하되, 증명자료가 생성된 날이 속하는 다음 연도의 1월 1일부터 5년간 보존하여야 한다.", "effective_from": "2026-05-06", "effective_to": null, "is_active": true}, {"article_key": "MAIN_ART_91", "article_number": "91", "article_title": "학생인건비의 지급", "section": "MAIN", "source_article": "제91조", "paragraph_start": 629, "paragraph_end": 643, "original_text": "제91조(학생인건비의 지급) ① 학생인건비통합관리기관의 장은 제87조제4항에 따라 학생인건비통합관리계정의 계정책임자를 설정한 경우 그 계정책임자와 협의하여 연구개발기관계정 및 연구책임자계정의 잔액을 고려하여 연구개발기관계정 및 연구책임자계정에서 학생인건비를 지급할 학생연구자를 정하고, 이를 전산시스템에 등록ㆍ관리 하여야 한다.\n② 학생인건비통합관리기관의 장과 계정책임자 및 학생연구자는 협의하여 다음 계산식에 따라 계산한 학생인건비지급률을 정하고, 별지 제1호 서식의 연구참여확약서를 학기(6개월) 또는 학년(12개월) 단위로 작성하여야 한다. 다만, 정부출연기관의 장과 학생연구자가 「근로기준법」제2조제4호에 따른 근로계약을 체결한 경우 별지 제1호 서식의 학생연구자 연구참여확약서를 작성하지 아니할 수 있다.\n③ 학생인건비통합관리기관의 장과 계정책임자 및 학생연구자는 다음 각 호의 경우에만 협의를 거쳐 제2항에 따른 연구참여확약서를 변경할 수 있다.\n1. 연구개발과제 협약 체결ㆍ변경ㆍ중단ㆍ해약\n2. 학생연구자 학적 변동\n3. 학생연구자 개인의 사정\n4. 학생연구자가 질병ㆍ실종ㆍ형사소추 등으로 업무 수행이 불가능한 경우\n5. 학생연구자 업무량 변동에 따라 학생연구자에게 지급하는 학생인건비 금액을 변경하려는 경우\n④ 학생인건비통합관리기관의 장은 연구참여확약서에 따라 연구개발기관계정에서 학생인건비를 지급할 때에는 해당 학생연구자의 개인계좌로 이체하여야 한다. 이 경우 필요한 금액을 다른 학생인건비통합관리계정으로부터 해당 연구개발기관계정으로 이체 또는 계정대체할 수 있다.\n⑤ 학생인건비통합관리기관의 장은 연구개발기관계정에서 제40조제4항 각 호에서 정한 금액의 20퍼센트 이상의 금액을 학생연구자 간 균등하게 지급하도록 노력하여야 한다.\n⑥ 제4항에 따라 학생인건비를 지급할 때에는 매월 지급하는 것을 원칙으로 한다. 다만, 학생인건비통합관리기관의 장이 필요하다고 인정하는 경우에는 연구참여확약서에 따른 학기별 또는 학년별 연구개발기관계정 지급 총액을 연구참여확약서 작성 직후에 일괄지급할 수 있다.\n⑦ 학생인건비통합관리기관의 장은 연구참여확약서에 따라 연구책임자계정에서 학생인건비를 지급할 때에는 해당 학생연구자의 개인계좌로 이체하여야 한다.\n⑧ 학생인건비통합관리기관의 장은 신규 또는 후속 연구개발과제를 준비하고 있는 학생연구자에게 학생인건비통합관리계정에서 학생인건비를 지급할 수 있다.\n⑨ 학생인건비통합관리기관의 장은 법 제12조제3항, 법 제15조제1항 및 제2항에 따라 연구개발과제가 중단된 경우에도 이미 학생인건비통합관리계정으로 이체된 금액을 학생인건비로 지급할 수 있다.\n⑩ 학생인건비통합관리기관의 장은 학생연구자의 졸업일이 포함된 월의 말일까지의 학생인건비를 학생연구자의 개인계좌로 이체할 수 있다.", "effective_from": "2026-05-06", "effective_to": null, "is_active": true}, {"article_key": "MAIN_ART_91_2", "article_number": "91의2", "article_title": "학생인건비 잔액의 사용", "section": "MAIN", "source_article": "제91의2조", "paragraph_start": 644, "paragraph_end": 651, "original_text": "제91조의2(학생인건비 잔액의 사용) ① 학생인건비통합관리기관의 장은 연구책임자계정(학생연구자가 연구책임자인 계정은 제외한다.)에서 당해 연도 12월 31일 기준 다음 계산식에 해당하는 금액 이상을 연구개발기관계정으로 차년도 3월 31일까지 이체 또는 계정대체하여야 한다.\n② 학생인건비통합관리기관의 장은 당해 연도 휴직이나 교육ㆍ지도, 학문연구 또는 산학협력만을 전담한 연구책임자의 연구책임자계정의 경우 제1항의 당해 연도를 휴직이나 교육ㆍ지도, 학문연구 또는 산학협력만을 전담하지 아니한 가장 최근 연도로 본다.\n③ 학생인건비통합관리기관의 장은 제1항 또는 제2항에 따른 금액을 이체 또는 계정대체할 연구개발기관계정이 없는 연구책임자계정의 해당 금액을 과학기술정보통신부장관에게 매년 3월 31일까지 반납하여야 한다.\n④ 과학기술정보통신부장관은 제1항에 따른 이체나 계정대체 및 제3항에 따른 반납과 관련하여 다음 각 호의 사항을 고려한 절차 등을 국가과학기술자문회의의 심의를 거쳐 마련하여야 한다.\n1. 제1항의 계산식에 따른 연구개발기관계정으로 이체 또는 계정대체하여야 할 금액 산정을 위한 방법 및 기준, 자료 제출 목록 및 시기 등\n2. 제1호에 따라 제출된 자료를 통해 산정된 연구개발기관계정으로 이체 또는 계정대체하여야할 금액을 학생인건비통합관리기관으로 통보하는 방법 및 시기\n3. 제1항의 계산식에 따라 산정된 금액에 대한 이의신청 방법 및 처리 기준\n4. 제2호 및 제3호에 따라 연구개발기관계정으로 이체 또는 계정대체하여야할 금액, 과학기술정보통신부장관에게 반납하여야 하는 금액을 이체 또는 계정대체하거나 반납하는 시기 및 방법", "effective_from": "2026-05-06", "effective_to": null, "is_active": true}, {"article_key": "MAIN_ART_92", "article_number": "92", "article_title": "학생인건비부당회수에 대한 조치", "section": "MAIN", "source_article": "제92조", "paragraph_start": 652, "paragraph_end": 654, "original_text": "제92조(학생인건비부당회수에 대한 조치) 학생인건비통합관리기관의 장이 학생연구자에게 학생인건비를 지급하지 아니하거나 통합관리계정책임자 등이 학생연구자에게 지급된 학생인건비를 정당한 사유 없이 회수하여 관리ㆍ사용하는 행위(이하 \"학생인건비부당회수\"라 한다)를 하여 중앙행정기관의 장이 법 제31조제1항제2호에 따른 연구개발비의 사용용도와 연구개발비 사용 기준을 위반한 행위로 법 제32조제1항제3호에 따라 제재처분을 할 때에 해당 중앙행정기관의 장은 다음 각 호에 따른 소관 중앙행정기관의 장으로 본다.\n1. 학생인건비부당회수가 발생한 시점에 진행 중인 연구개발과제가 있는 경우에는 해당 연구개발과제의 소관 중앙행정기관의 장\n2. 학생인건비부당회수가 발생한 시점에 진행 중인 연구개발과제가 없는 경우에는 그 시점에서 가장 최근에 종료된 연구개발과제의 소관 중앙행정기관의 장", "effective_from": "2026-05-06", "effective_to": null, "is_active": true}, {"article_key": "MAIN_ART_93", "article_number": "93", "article_title": "학생인건비통합관리 점검", "section": "MAIN", "source_article": "제93조", "paragraph_start": 655, "paragraph_end": 668, "original_text": "제93조(학생인건비통합관리 점검) ① 학생인건비통합관리기관의 장은 학생인건비통합관리 운영현황 등에 대하여 연 1회 이상 별지 제9호 서식에 따른 자체점검을 실시하여야 한다.\n② 학생인건비통합관리기관의 장은 전산시스템을 변경한 경우 별표 2의 학생인건비통합관리기관 전산시스템 구축 요건을 자체점검하고, 그 결과를 지체 없이 과학기술정보통신부장관에게 제출하여야 한다.\n③ 과학기술정보통신부장관은 학생인건비통합관리기관의 학생인건비통합관리 운영현황을 점검할 수 있으며, 점검에 필요한 다음 각 호의 자료를 학생인건비통합관리기관에 요구할 수 있다.\n1. 별표 2의 학생인건비통합관리기관 전산시스템 구축 요건에 대한 자체점검표\n2. 학생인건비통합관리계정 설정 및 관리 현황\n3. 학생연구자 지원규정 제ㆍ개정 사항\n4. 학생인건비 지급 현황\n5. 학생인건비부당회수 현황\n6. 학생인건비부당회수 방지를 위한 실적\n7. 그 밖의 운영현황 점검을 위하여 필요한 자료\n④ 과학기술정보통신부장관은 제3항에 따라 요구한 자료를 검토하여 자료가 미흡하다고 판단되는 경우에는 추가 자료를 요청할 수 있으며, 필요한 경우에는 현장점검을 실시할 수 있다.\n⑤ 학생인건비통합관리기관의 장은 제3항제4호 및 제5호의 자료를 과학기술정보통신부장관에게 제출하는 경우 해당 학생인건비통합관리기관의 평균 학생인건비 지급비율(학생인건비통합관리계정별 지급비율은 제외한다)과 학생인건비부당회수 비율(학생인건비통합관리계정별 부당회수 비율은 제외한다)을 기관 홈페이지 등에 공개한 후 제출하여야 한다.\n⑥ 과학기술정보통신부장관은 제4항에 따라 현장점검을 실시하려는 경우에는 현장점검일부터 7일 전까지 점검 일시ㆍ내용 등을 포함한 점검계획을 해당 학생인건비통합관리기관에 문서로 통지하여야 한다. 다만, 긴급한 경우에는 그러하지 아니할 수 있다.\n⑦ 과학기술정보통신부장관은 제3항에 따른 점검을 위하여 필요한 경우 제3항제5호 및 제7호의 자료를 소관 중앙행정기관의 장에게 요구할 수 있다. 이 경우 중앙행정기관의 장은 법 제20조제2항 및 제33조제7항에 따라 적극 협조하여야 한다.", "effective_from": "2026-05-06", "effective_to": null, "is_active": true}, {"article_key": "MAIN_ART_94", "article_number": "94", "article_title": "학생인건비통합관리기관의 지정취소", "section": "MAIN", "source_article": "제94조", "paragraph_start": 669, "paragraph_end": 681, "original_text": "제94조(학생인건비통합관리기관의 지정취소) ① 과학기술정보통신부장관은 제93조제3항에 따른 운영현황 점검 또는 같은 조 제4항에 따른 현장점검 결과가 다음 각 호의 어느 하나에 해당하는 경우에 해당 학생인건비통합관리기관의 소명을 거쳐 학생인건비통합관리기관 지정을 취소할 수 있다.\n1. 운영현황 점검 또는 현장점검을 완료한 연도의 1월 1일 기준으로 직전 5년 동안 학생인건비통합관리 대상 과제의 학생인건비부당회수로 제재처분을 받은 연구자 수가 전년도 연구책임자계정 수의 2퍼센트를 초과하는 경우\n2. 운영현황 점검 또는 현장점검을 완료한 연도의 직전년도 1월 1일부터 12월 31일까지의 기간 동안 제91조제4항ㆍ제7항에 따라 제7조 각호의 용도로 사용한 금액이 동일한 기간 동안 제90조제1항에 따라 연구개발과제계정에서 학생인건비통합관리계정으로 이체된 금액(동일한 기간 동안 연구개발비 사용계획 변경에 따라 학생인건비통합관리계정에서 연구개발과제계정으로 이체된 금액은 제외한다)과 전전년도 12월 31일 기준 학생인건비통합관리계정의 잔액 및 당해 연도 발생 이자수익의 합의 50퍼센트 미만인 경우가 2회 이상인 경우\n3. 별표 2에 따른 학생인건비통합관리기관 전산시스템 구축요건을 충족하지 못한 경우\n4. 제1호 또는 제2호에 해당하는 경우를 방지하기 위한 목적으로 학생인건비를 소급하여 지급한 것이 확인된 경우\n5. 제1호 또는 제2호에 해당하는 경우를 방지하기 위한 목적으로 학생인건비를 연구개발비 중 다른 항목으로 변경한 것이 확인된 경우\n6. 그 밖에 학생인건비통합관리와 관련하여 중대한 잘못이 발견된 경우\n② 과학기술정보통신부장관은 제1항제2호를 계산함에 있어 학생인건비통합관리기관이 제출하는 자료가 미흡한 경우에는 보완 제출을 요구할 수 있으며, 현장점검의 우선 대상 기관으로 선정할 수 있다.\n③ 삭제\n④ 과학기술정보통신부장관은 학생인건비통합관리기관의 장이 별지 제12호 서식에 따라 학생인건비통합관리기관 지정 취소를 요청한 경우에는 그 지정을 취소하여야 한다.\n⑤ 제1항 및 제2항에 따라 학생인건비통합관리기관 지정이 취소된 연구개발기관의 장은 모든 학생인건비통합관리계정의 잔액 내역을 지정취소 통보일로부터 30일 이내에 제출하고, 확정된 반납액을 과학기술정보통신부 장관에게 반납하여야 한다. 이 경우 반납액 산출 시 제91조제2항에 따라 이미 확약된 금액 및 다음 계산식에 따라 계산한 수행 중인 연구개발과제의 학생인건비 잔액은 제외할 수 있다.\n⑥ 삭제\n⑦ 지정취소된 연구개발기관의 장은 지정취소일로부터 3년이 경과된 후에 재지정을 신청할 수 있다.", "effective_from": "2026-05-06", "effective_to": null, "is_active": true}, {"article_key": "MAIN_ART_95", "article_number": "95", "article_title": "학생인건비의 이관 및 반납", "section": "MAIN", "source_article": "제95조", "paragraph_start": 682, "paragraph_end": 699, "original_text": "제95조(학생인건비의 이관 및 반납) ① 학생인건비통합관리기관의 장은 연구책임자의 소속 변경으로 해당 연구책임자가 수행 중인 연구개발과제가 다른 기관ㆍ단체로 연구개발기관이 변경된 경우 변경 후 연구개발기관의 연구개발과제계정으로, 같은 연구개발기관 내 다른 연구자로 연구책임자가 변경된 경우 변경 후 연구책임자계정으로 해당 연구책임자계정에서 다음 각 호에 따라 계산한 금액을 이체 또는 계정대체하여야 한다.\n1. 해당 연구책임자계정 잔액이 연구개발기관 또는 연구책임자가 변경된 연구개발과제의 다음의 계산식에 따라 계산한 학생인건비 잔액의 합 이상인 경우: 연구개발기관이 변경된 연구개발과제의 다음의 계산식에 따라 계산한 학생인건비 잔액의 합\n2. 해당 연구책임자계정 잔액이 연구개발기관 또는 연구책임자가 변경된 연구개발과제의 제1호의 계산식에 따라 계산한 학생인건비 잔액의 합 미만인 경우: 다음의 계산식에 따라 계산한 금액\n② 학생인건비통합관리기관의 장은 법 제12조제3항 또는 제15조제1항에 따라 연구개발과제의 협약이 해약되거나 연구개발과제가 중단된 경우에는 해당 연구책임자 단위로 관리하는 연구책임자계정의 잔액 중 다음의 계산식에 따라 계산한 금액을 소관 중앙행정기관의 장과 협의하여 연구개발기관계정으로 이체 또는 계정대체하거나 소관 중앙행정기관의 장에게 반납하여야 한다. 다만, 연구책임자계정의 잔액이 다음의 계산식에 따라 계산한 금액 미만인 경우에는 소관 중앙행정기관의 장과 협의하여 연구책임자계정 잔액을 모두 연구개발기관계정으로 이체 또는 계정대체하거나 소관 중앙행정기관의 장에게 반납하여야 한다.\n③ 학생인건비통합관리기관의 장은 다음 각 호의 어느 하나에 해당하여 연구개발과제의 협약이 해약되거나 연구개발과제가 중단된 경우 제2항에 따라 소관 중앙행정기관의 장에게 반납하여야 하는 금액을 연구개발기관계정으로 이체 또는 계정대체할 수 있다.\n1. 연구개발과제의 단계평가 결과가 영 제17조제1항제2호에 해당하는 경우\n2. 법 제15조제1항 제3호, 제4호, 제6호 중 어느 하나에 해당하는 사유로 특별평가를 거친 경우\n④ 학생인건비통합관리기관의 장은 다음 각 호의 어느 하나에 해당하는 경우 해당 연구책임자계정의 잔액을 연구개발기관계정으로 이체 또는 계정대체할 수 있다.\n1. 수행 중인 연구개발과제가 없는 경우\n2. 계정책임자가 법 제32조제1항에 따라 참여제한을 받은 경우\n3. 제1항 또는 제2항에 따른 이체 또는 계정대체 후 잔액이 있는 경우\n⑤ 제4항에도 불구하고 다음 각 호의 어느 하나에 해당하는 경우 연구개발기관계정이 아닌 연구책임자계정으로 이체 또는 계정대체할 수 있다.\n1. 계정책임자가 다른 학생인건비통합관리기관으로 소속을 변경하는 경우\n2. 학생인건비통합관리기관의 장이 정하는 바에 따라 신진연구자 등을 지원하는 경우\n⑥ 다음 각 호의 어느 하나에 해당하는 경우 연구개발기관계정의 잔액은 다른 학생인건비통합관리계정으로 이체 또는 계정대체하거나 중앙행정기관의 장에게 반납하는 금액에서 제외한다.\n1. 연구책임자의 소속 변경으로 해당 연구책임자가 수행 중인 연구개발과제가 다른 기관ㆍ단체로 연구개발기관이 변경되거나 같은 연구개발기관 내 다른 연구자로 연구책임자가 변경된 경우\n2. 계정책임자가 법 제32조제1항에 따라 참여제한을 받은 경우\n3. 법 제12조제3항 또는 제15조제1항에 따라 연구개발과제의 협약이 해약되거나 연구개발과제가 중단된 경우", "effective_from": "2026-05-06", "effective_to": null, "is_active": true}, {"article_key": "MAIN_ART_96", "article_number": "96", "article_title": "학생인건비의 이자 사용", "section": "MAIN", "source_article": "제96조", "paragraph_start": 700, "paragraph_end": 700, "original_text": "제96조(학생인건비의 이자 사용) 학생인건비통합관리기관의 장은 학생인건비통합관리 전용 계좌에서 발생한 이자를 연구개발기관계정에 적립하여 학생인건비를 지급ㆍ관리하여야 한다. 다만, 학생인건비통합관리기관의 장이 필요하다고 인정하는 경우에는 학생인건비통합관리 전용계좌에서 발생한 이자를 특정 학생인건비통합관리계정에 적립하여 학생인건비로 지급ㆍ관리할 수 있다.", "effective_from": "2026-05-06", "effective_to": null, "is_active": true}, {"article_key": "MAIN_ART_97", "article_number": "97", "article_title": "다른 사업의 학생인건비 관리", "section": "MAIN", "source_article": "제97조", "paragraph_start": 701, "paragraph_end": 701, "original_text": "제97조(다른 사업의 학생인건비 관리) 학생인건비통합관리기관의 장은 학생인건비의 안정적인 지급을 위하여 국가연구개발사업이 아닌 사업을 통하여 학생연구자에게 지급하는 인건비를 학생인건비통합관리계정으로 통합하여 관리할 수 있다. 이 경우 국가연구개발사업이 아닌 사업을 통하여 학생연구자에게 지급하는 인건비의 지급ㆍ관리에 관하여는 제86조부터 제96조까지의 규정을 준용한다.", "effective_from": "2026-05-06", "effective_to": null, "is_active": true}, {"article_key": "MAIN_ART_98", "article_number": "98", "article_title": "학생인건비통합관리기관의 연구지원체계평가", "section": "MAIN", "source_article": "제98조", "paragraph_start": 702, "paragraph_end": 702, "original_text": "제98조(학생인건비통합관리기관의 연구지원체계평가) 과학기술정보통신부장관은 학생인건비통합관리기관에 대하여 연구개발기관계정과 연구책임자계정에서 지급하는 학생인건비의 비율, 학생연구자 1인당 학생인건비 규모 등에 따라 법 제25조에 따른 연구지원체계평가 시에 차등하여 평가할 수 있다.", "effective_from": "2026-05-06", "effective_to": null, "is_active": true}, {"article_key": "MAIN_ART_99", "article_number": "99", "article_title": "전담기관의 지정ㆍ지원", "section": "MAIN", "source_article": "제99조", "paragraph_start": 703, "paragraph_end": 706, "original_text": "제99조(전담기관의 지정ㆍ지원) ① 과학기술정보통신부장관의 제86조에 따른 학생인건비통합관리의 지정, 제93조에 따른 학생인건비통합관리 점검, 제94조에 따른 학생인건비통합관리기관의 지정취소의 효율적인 추진을 위하여 관련 업무를 종합적으로 지원하는 전담기관(이하 \"학생인건비통합관리전담기관\"이라 한다)을 지정할 수 있다.\n② 과학기술정보통신부장관은 학생인건비통합관리전담기관의 운영 및 사업 수행에 필요한 비용의 일부 또는 전부를 지원하고 수행에 필요한 자료를 제공할 수 있다.\n③ 학생인건비통합관리전담기관은 「과학기술기본법」 제20조제1항에 따른 한국과학기술기획평가원으로 한다.\n제7장 연구시설ㆍ장비비 사용의 특례", "effective_from": "2026-05-06", "effective_to": null, "is_active": true}, {"article_key": "MAIN_ART_100", "article_number": "100", "article_title": "연구시설ㆍ장비비통합관리기관의 지정", "section": "MAIN", "source_article": "제100조", "paragraph_start": 707, "paragraph_end": 719, "original_text": "제100조(연구시설ㆍ장비비통합관리기관의 지정) ① 과학기술정보통신부장관은 다음 각 호의 요건을 모두 갖추고 있는 비영리기관을 연구시설ㆍ장비비통합관리기관으로 지정할 수 있다. 다만, 「공공기관의 운영에 관한 법률 시행령」 제7조의2에 따라 연구개발목적기관으로 지정된 기관이거나 제2항에 따라 연구시설ㆍ장비비통합관리기관 지정을 신청한 날을 기준으로 최근에 실시한 법 제25조에 따른 연구지원체계평가 결과가 B등급 이상인 기관에 대하여는 제1호부터 제2호까지의 요건을 갖추고 있는 경우에 연구시설ㆍ장비비통합관리기관으로 지정할 수 있다.\n1. 「국가연구개발 시설ㆍ장비의 관리 등에 관한 표준지침」 제6조에 따른 자체장비심의위원회(이하 \"자체장비심의위원회\")를 구성하고 있을 것\n2. 별표 5의 연구시설ㆍ장비비통합관리기관 전산시스템 구축요건을 충족하는 전산시스템을 보유하고 있을 것\n3. 연구개발기관 내 예산ㆍ협약ㆍ정산, 구매ㆍ자산ㆍ검수, 재무ㆍ회계, 성과관리 등의 업무를 지원하는 자체 연구지원시스템(이하 \"자체연구지원시스템\"이라 한다)이 구축되어 있고, 자체연구지원시스템이 연구비통합관리시스템과 연계되어 있을 것\n4. 영 제58조제1항에 따른 자체 연구윤리규정을 마련하고 있을 것\n5. 제2항에 따라 연구시설ㆍ장비비통합관리기관 지정을 신청한 날을 기준으로 최근 2년 간 국가연구개발사업에 대한 제재처분 또는 연구개발비 환수처분을 받지 아니할 것\n② 연구시설ㆍ장비비통합관리기관으로 지정받으려는 연구개발기관의 장은 다음 각 호의 서류 또는 자료를 작성하여 과학기술정보통신부장관에게 신청하여야 한다. 다만, 제1항 각 호 외의 부분 단서에 해당하는 경우에는 제1호부터 제3호까지의 서류 또는 자료를 작성하여 과학기술정보통신부장관에게 신청할 수 있다.\n1. 별지 제13호 서식의 연구시설ㆍ장비비통합관리기관 지정 신청서\n2. 최근 3년 간의 자체장비심의위원회 구축ㆍ운영 실적을 증명할 수 있는 자료\n3. 연구개발기관의 자체연구지원시스템이 연구시설ㆍ장비비를 통합관리할 수 있음을 증명할 수 있는 자료\n4. 자체연구지원시스템 구축 여부 및 연구비통합관리시스템과의 연계 증명자료\n5. 영 제58조제1항에 따른 자체 연구윤리규정\n③ 과학기술정보통신부장관은 제2항 각 호의 서류 또는 자료를 평가하여 적절하다고 판단하는 경우에는 해당 연구개발기관을 연구시설ㆍ장비비통합관리기관으로 지정하고, 이를 해당 연구개발기관의 장에게 통보하여야 한다.", "effective_from": "2026-05-06", "effective_to": null, "is_active": true}, {"article_key": "MAIN_ART_101", "article_number": "101", "article_title": "연구시설ㆍ장비비통합관리계정의 설정", "section": "MAIN", "source_article": "제101조", "paragraph_start": 720, "paragraph_end": 724, "original_text": "제101조(연구시설ㆍ장비비통합관리계정의 설정) ① 제100조제3항에 따라 연구시설ㆍ장비비통합관리기관으로 지정된 연구개발기관의 장은 다음 각 호에 해당하는 연구시설ㆍ장비비(이하 \"통합연구시설ㆍ장비비\"라 한다) 관리를 위한 별도 계정을 설정하여 하나 이상의 연구개발과제의 통합연구시설ㆍ장비비를 통합관리 할 수 있다. 다만, 수익창출활동을 통한 자립 운영을 전제로 지급되는 연구시설ㆍ장비비는 중앙행정기관의 장이 인정하는 경우 연구시설ㆍ장비비통합관리 대상에서 제외할 수 있다.\n1. 연구시설ㆍ장비 임차비 및 연구시설ㆍ장비 운영비\n2. 정부출연기관의 기본사업의 연구개발비 중 연구시설ㆍ장비 유지ㆍ보수비\n② 연구시설ㆍ장비비통합관리기관의 장은 제1항에 따른 통합연구시설ㆍ장비비 관리를 위한 계정(이하 \"연구시설ㆍ장비비통합관리계정\"이라 한다)을 연구개발기관 단위로 관리하는 연구개발기관계정, 연구개발기관 내 공동활용 연구시설ㆍ장비를 집적하여 운영하는 시설(이하 \"공동활용시설\"이라 한다) 단위로 관리하는 공동활용시설계정, 연구책임자 단위로 관리하는 연구책임자계정으로 구분하여 설정할 수 있다.\n③ 연구시설ㆍ장비비통합관리계정 책임자가 되고자 하는 참여연구자는 통합관리 단위를 선택하여 연구개발기관에 계정 설정을 요청하고, 연구시설ㆍ장비비통합관리기관은 제102조에 따른 내부 운영규정에 따라 적립금액의 적절성과 연구시설ㆍ장비 운영현황을 검토하여 적립할 연구시설ㆍ장비비통합관리계정의 단위를 조정할 수 있다.", "effective_from": "2026-05-06", "effective_to": null, "is_active": true}, {"article_key": "MAIN_ART_102", "article_number": "102", "article_title": "연구시설ㆍ장비비통합관리 내부 운영규정 마련ㆍ운영", "section": "MAIN", "source_article": "제102조", "paragraph_start": 725, "paragraph_end": 733, "original_text": "제102조(연구시설ㆍ장비비통합관리 내부 운영규정 마련ㆍ운영) 연구시설ㆍ장비비통합관리기관의 장은 다음 각 호의 사항을 포함하는 내부 운영규정을 마련하여 운영하여야 한다.\n1. 연구시설ㆍ장비비통합관리의 자체적인 관리ㆍ감독에 관한 사항\n2. 연구시설ㆍ장비비통합관리계정의 설정 및 관리에 관한 사항\n3. 통합연구시설ㆍ장비비의 수입ㆍ지출ㆍ잔액 관리에 관한 사항\n4. 통합연구시설ㆍ장비비의 관리를 위한 자체연구지원시스템의 구축 및 운영에 관한 사항\n5. 자체장비심의위원회의 역할 및 임무에 관한 사항\n6. 제110조에 따른 연구개발기관 지원금과 시설ㆍ장비 이용료 수입의 추가 적립에 관한 사항\n7. 연구시설ㆍ장비비통합관리계정에서 발생한 이자의 사용 및 관리에 관한 사항\n8. 그 밖에 연구시설ㆍ장비비통합관리기관의 장이 필요하다고 인정하는 사항", "effective_from": "2026-05-06", "effective_to": null, "is_active": true}, {"article_key": "MAIN_ART_103", "article_number": "103", "article_title": "연구시설ㆍ장비비의 적립", "section": "MAIN", "source_article": "제103조", "paragraph_start": 734, "paragraph_end": 743, "original_text": "제103조(연구시설ㆍ장비비의 적립) ① 연구시설ㆍ장비비통합관리기관의 장이 연구시설ㆍ장비비통합관리계정에 적립할 수 있는 적립한도는 다음 각 호와 같다. 다만, 연구시설ㆍ장비비통합관리기관의 장이 요청하여 과학기술정보통신부장관이 승인한 경우에는 이를 증액할 수 있다.\n1. 연구개발기관 단위로 설정된 계정: 10억 원\n2. 공동활용시설 단위로 설정된 계정: 7억 원\n3. 연구책임자 단위로 설정된 계정: 3억 원\n② 연구시설ㆍ장비비통합관리기관의 장은 연구개발과제 협약 체결 시에 연구시설ㆍ장비비통합관리계정에 적립할 금액을 연차별 수정직접비의 10퍼센트 이내에 중앙행정기관의 장이 인정하는 한도 내에서 결정하여야 한다.\n1. 삭제\n2. 삭제\n③ 제1항에 따라 결정된 한도를 증액하고자 하는 연구시설ㆍ장비비통합관리기관은 다음 각 호의 서류ㆍ자료를 작성하여 과학기술정보통신부장관에게 신청하고 승인을 받아야 한다.\n1. 별지 제14호 서식의 연구시설ㆍ장비비통합관리계정 적립한도 증액 신청서\n2. 신청한 연구시설ㆍ장비비통합관리계정의 최근 3년간 적립ㆍ사용내역", "effective_from": "2026-05-06", "effective_to": null, "is_active": true}, {"article_key": "MAIN_ART_104", "article_number": "104", "article_title": "연구시설ㆍ장비비의 사용", "section": "MAIN", "source_article": "제104조", "paragraph_start": 744, "paragraph_end": 745, "original_text": "제104조(연구시설ㆍ장비비의 사용) ① 연구시설ㆍ장비비통합관리기관의 장은 연구개발비를 전체 또는 일부 지급받거나 통합연구시설ㆍ장비비를 변경하는 날부터 90일 이내에 통합연구시설ㆍ장비비를 연구시설ㆍ장비비통합관리계정으로 이체 또는 계정대체하여야 하며, 해당 연차 연구개발기간 종료일까지 전체 금액을 이체 또는 계정대체하여야 한다.\n② 연구시설ㆍ장비비통합관리기관에 대하여는 제1항에 따라 이체 또는 계정대체된 연구시설ㆍ장비비를 사용실적보고서등에서 사용된 연구개발비로 본다.", "effective_from": "2026-05-06", "effective_to": null, "is_active": true}, {"article_key": "MAIN_ART_105", "article_number": "105", "article_title": "연구시설ㆍ장비비의 지출", "section": "MAIN", "source_article": "제105조", "paragraph_start": 746, "paragraph_end": 750, "original_text": "제105조(연구시설ㆍ장비비의 지출) ① 연구시설ㆍ장비비통합관리기관의 장은 연구시설ㆍ장비종합정보시스템(ZEUS)에 등록된 연구시설ㆍ장비로서 국가연구개발사업으로 구축되었거나 연구개발계획서 상에 명시되어 국가연구개발사업에 활용되었음이 확인되는 연구시설ㆍ장비에 대하여 연구시설ㆍ장비비통합관리계정의 통합연구시설ㆍ장비비를 다음 각 호의 용도로 지출할 수 있다.\n1. 연구시설ㆍ장비의 유지ㆍ보수\n2. 연구시설ㆍ장비의 임차ㆍ사용대차(기존의 임차ㆍ사용대차 계약을 연장하는 경우에만 사용가능하며, 계약 이후 소유권이 해당 연구개발기관으로 이전되는 경우는 제외한다)\n3. 연구시설ㆍ장비의 기관 간 양도 및 기관 내 공동활용시설로 재배치되는 이전ㆍ설치\n② 통합연구시설ㆍ장비비의 사용 증명자료는 연구개발기관의 자체규정에 따라 관리하되, 증명자료가 생산된 날이 속하는 다음 연도의 1월 1일부터 5년간 보존하여야 한다.", "effective_from": "2026-05-06", "effective_to": null, "is_active": true}, {"article_key": "MAIN_ART_106", "article_number": "106", "article_title": "연구시설ㆍ장비비통합관리 점검", "section": "MAIN", "source_article": "제106조", "paragraph_start": 751, "paragraph_end": 763, "original_text": "제106조(연구시설ㆍ장비비통합관리 점검) ① 연구시설ㆍ장비비통합관리기관의 장은 제100조부터 제105조에 따라 통합연구시설ㆍ장비비가 관리되었는지 등에 대하여 연 1회 이상 자체점검을 실시하여야 한다.\n② 연구시설ㆍ장비비통합관리기관의 장은 제1항에 따른 자체점검 결과 다음 각 호의 어느 하나에 해당하는 경우 이를 별지 제15호 서식에 따라 과학기술정보통신부 장관에게 보고하여야 한다.\n1. 자체점검 연도를 기준으로 전년도 1월 1일부터 12월 31일까지의 기간(이하 \"점검대상기간\"이라 한다) 중 통합연구시설ㆍ장비비를 제105조 각 호에 따른 용도 외의 용도로 지출한 경우\n2. 점검대상기간 중 제103조제2항에 따라 최초로 연구개발과제 협약 체결 시에 연구시설ㆍ장비비통합관리계정에 적립하기로 결정한 금액과 다르게 해당 연구시설ㆍ장비비통합관리계정에 적립하였거나 연구시설ㆍ장비비통합관리기관 내 다른 계정으로 이체 또는 계정대체한 경우\n3. 점검대상기간 중 제103조제1항에 따른 연구시설ㆍ장비비통합관리계정별 적립한도(같은 항 단서에 따라 적립한도를 증액한 경우에는 증액한 적립한도를 말한다)를 초과하여 적립한 경우\n4. 점검대상기간 중 연구시설ㆍ장비비통합관리 대상이 아닌 연구개발비를 통합관리한 경우\n③ 과학기술정보통신부장관은 연구시설ㆍ장비비통합관리기관의 연구시설ㆍ장비비통합관리 운영현황을 점검할 수 있으며, 점검에 필요한 다음 각 호의 자료를 연구시설ㆍ장비비통합관리기관에 요구할 수 있다.\n1. 제1항에 따른 연구시설ㆍ장비비통합관리기관의 자체점검 실적\n2. 연구시설ㆍ장비비통합관리계정의 세부 수입ㆍ지출내역\n3. 그 밖의 운영현황 점검에 관한 연구시설ㆍ장비비통합관리기관의 소명자료 등 필요한 자료\n④ 과학기술정보통신부장관은 제2항에 따라 보고받은 자료와 제3항에 따라 제출받은 자료를 검토하여 자료가 미흡하다고 판단하는 경우에는 추가 자료를 요청할 수 있으며, 현장점검을 실시할 수 있다.\n⑤ 과학기술정보통신부장관은 제4항에 따라 현장점검을 실시하려는 경우에는 현장점검일부터 7일 전까지 점검 일시ㆍ내용 등을 포함한 점검계획을 해당 연구시설ㆍ장비비통합관리기관에 문서로 통지하여야 한다. 다만, 긴급한 경우에는 그러하지 아니할 수 있다.\n⑥ 과학기술정보통신부장관은 중앙행정기관의 장에게 통합연구시설ㆍ장비비 지출내역 등의 자료 제출을 요구할 수 있으며, 연구시설ㆍ장비비통합관리 운영현황의 효율적인 점검을 위하여 연구시설ㆍ장비종합정보시스템(ZEUS)과 연구비통합관리시스템의 연계를 추진할 수 있다.", "effective_from": "2026-05-06", "effective_to": null, "is_active": true}, {"article_key": "MAIN_ART_107", "article_number": "107", "article_title": "연구시설ㆍ장비비통합관리기관 지정취소", "section": "MAIN", "source_article": "제107조", "paragraph_start": 764, "paragraph_end": 771, "original_text": "제107조(연구시설ㆍ장비비통합관리기관 지정취소) ① 과학기술정보통신부장관은 제106조제1항 및 제3항의 점검결과가 제106조제2항 각 호 또는 다음 각 호의 어느 하나에 해당하는 경우에는 연구시설ㆍ장비비통합관리기관에게 개선을 요구할 수 있다.\n1. 통합연구시설ㆍ장비비를 자체연구지원시스템으로 관리하지 아니하는 경우\n2. 제106조제2항에 따른 보고를 하지 아니한 경우\n② 연구시설ㆍ장비비통합관리기관의 장은 제1항에 따라 개선을 요구받은 때에는 특별한 사정이 없으면 요구를 받은 날부터 45일 이내에 별지 제16호 서식에 따라 개선계획을 작성하여 연구시설ㆍ장비종합정보시스템(ZEUS)을 통하여 과학기술정보통신부장관에게 제출하고, 요구를 받은 날부터 6개월 이내에 별지 제17호 서식에 따라 개선계획의 이행결과를 보고하여야 한다.\n③ 과학기술정보통신부장관은 제2항에 따른 개선계획을 검토하여 미흡하다고 판단되는 경우에는 보완을 요청할 수 있으며, 다음 각 호의 어느 하나에 해당하는 경우에는 해당 연구시설ㆍ장비비통합관리기관의 소명을 거쳐 연구시설ㆍ장비비통합관리기관 지정을 취소할 수 있다.\n1. 보완된 개선계획이 적절하지 않다고 판단되거나 이행되지 아니한 것으로 판단된 경우\n2. 개선계획 이행결과 보고 후 1년 이내에 동일한 개선 필요 사항이 반복하여 확인된 경우\n④ 제3항에 따라 연구시설ㆍ장비비통합관리기관 지정이 취소된 연구개발기관의 장은 연구시설ㆍ장비비통합관리계정 잔액을 지정 취소일과 연구개발기간 종료일이 가까운 연구개발과제 순으로 해당 중앙행정기관의 장에게 반납하여야 한다. 다만, 지정취소일 기준 수행 중인 연구개발과제의 통합연구시설ㆍ장비비는 제외한다.", "effective_from": "2026-05-06", "effective_to": null, "is_active": true}, {"article_key": "MAIN_ART_108", "article_number": "108", "article_title": "연구시설ㆍ장비비의 이관ㆍ반납", "section": "MAIN", "source_article": "제108조", "paragraph_start": 772, "paragraph_end": 777, "original_text": "제108조(연구시설ㆍ장비비의 이관ㆍ반납) ① 연구시설ㆍ장비비통합관리계정 책임자의 소속기관이 변경된 경우에는 통합연구시설ㆍ장비비 잔액을 다음 각 호에 따라 사용한다. 단, 공동활용시설단위 또는 연구개발기관단위의 통합연구시설ㆍ장비비는 타 연구시설이나 연구개발기관으로 이전할 수 없다.\n1. 연구시설ㆍ장비비통합관리계정 책임자가 이직과 동시에 수행 중인 연구개발과제를 승계하여 이전하는 경우에는 수행 중인 연구개발과제에서 적립한 통합연구시설ㆍ장비비를 남은 연구개발기간 비율로 산출하여 변경된 연구개발기관의 연구시설ㆍ장비비통합관리계정으로 이관하여 사용할 수 있다.\n2. 제1호에 해당하지 않는 경우에는 해당 통합연구시설ㆍ장비비 잔액을 기존 연구시설ㆍ장비비통합관리기관 내 다른 연구시설ㆍ장비비통합관리계정으로 이관하여 제105조제1항의 목적에 맞게 사용하여야 한다.\n② 공동활용시설단위 연구시설ㆍ장비비통합관리계정의 공동활용시설이 폐쇄될 경우 통합연구시설ㆍ장비비 잔액은 연구개발기관단위로 통합관리하여야 한다.\n③ 법 제12조제3항 또는 제15조제1항을 포함하여 중앙행정기관의 장이 정한 사유로 연구개발과제의 협약이 해약되거나 연구개발과제가 중단된 경우에는 연구개발과제의 연구개발기간 대비 남은 연구개발기간에 상당하는 비율로 연구개발과제의 통합 연구시설ㆍ장비비 잔액을 산출하여 해당 중앙행정기관의 장에게 반납하여야 한다.\n④ 연구시설ㆍ장비비통합관리기관 지정을 포기하거나 연구개발기관이 연구시설ㆍ장비비통합관리계정을 관리할 수 없는 경우를 포함하여 과학기술정보통신부 장관이 정한 사유로 연구시설ㆍ장비비통합관리기관이 연구시설ㆍ장비비통합관리계정을 관리할 수 없는 경우에는 잔액을 산출하여 중앙행정기관의 장에게 반납하여야 한다.", "effective_from": "2026-05-06", "effective_to": null, "is_active": true}, {"article_key": "MAIN_ART_109", "article_number": "109", "article_title": "연구시설ㆍ장비비의 이자 사용", "section": "MAIN", "source_article": "제109조", "paragraph_start": 778, "paragraph_end": 778, "original_text": "제109조(연구시설ㆍ장비비의 이자 사용) 연구시설ㆍ장비비통합관리기관의 장은 연구시설ㆍ장비비통합관리계정에서 발생한 이자를 연구시설ㆍ장비비통합관리계정에 적립하여 제105조 각 호의 용도로 지출ㆍ관리하여야 한다.", "effective_from": "2026-05-06", "effective_to": null, "is_active": true}, {"article_key": "MAIN_ART_110", "article_number": "110", "article_title": "다른사업수입등의 연구시설ㆍ장비비통합관리", "section": "MAIN", "source_article": "제110조", "paragraph_start": 779, "paragraph_end": 779, "original_text": "제110조(다른사업수입등의 연구시설ㆍ장비비통합관리) 연구시설ㆍ장비비통합관리기관의 장은 연구시설ㆍ장비의 효율적인 운영ㆍ활용을 위하여 간접비(국가연구개발사업이 아닌 사업의 간접비를 포함한다), 교비 등 연구개발기관 지원금과 연구시설ㆍ장비 운영ㆍ활용에 따른 이용료 수입 등(이하 \"다른사업수입등\"이라 한다)을 연구시설ㆍ장비비통합관리계정으로 통합하여 관리할 수 있다. 이 경우 다른사업수입등을 활용한 통합연구시설ㆍ장비비의 지출ㆍ관리에 관하여는 제100조부터 제109조까지의 규정을 준용할 수 있다.", "effective_from": "2026-05-06", "effective_to": null, "is_active": true}, {"article_key": "MAIN_ART_111", "article_number": "111", "article_title": "연구시설ㆍ장비비통합관리기관의 연구지원체계평가", "section": "MAIN", "source_article": "제111조", "paragraph_start": 780, "paragraph_end": 781, "original_text": "제111조(연구시설ㆍ장비비통합관리기관의 연구지원체계평가) 과학기술정보통신부장관은 연구시설ㆍ장비비통합관리기관에 대하여 연구지원체계평가 시에 차등하여 반영할 수 있다.\n제8장 간접비고시비율 산출", "effective_from": "2026-05-06", "effective_to": null, "is_active": true}, {"article_key": "MAIN_ART_112", "article_number": "112", "article_title": "간접비고시비율 산출기준", "section": "MAIN", "source_article": "제112조", "paragraph_start": 782, "paragraph_end": 783, "original_text": "제112조(간접비고시비율 산출기준) ① 과학기술정보통신부장관은 2년 마다 비영리기관인 연구개발기관의 간접비고시비율을 산출하기 위하여 간접비고시비율 산출기준을 마련하고, 영 제22조제1항에 따른 간접비계상기준산출위원회의 심의를 거쳐 확정하여야 한다.\n② 과학기술정보통신부장관은 간접비고시비율 산출기준을 30일 이상 공고하여야 한다.", "effective_from": "2026-05-06", "effective_to": null, "is_active": true}, {"article_key": "MAIN_ART_113", "article_number": "113", "article_title": "간접비고시비율 산출 신청", "section": "MAIN", "source_article": "제113조", "paragraph_start": 784, "paragraph_end": 788, "original_text": "제113조(간접비고시비율 산출 신청) ① 간접비고시비율 산출을 받으려는 비영리기관인 연구개발기관은 다음 각 호의 문서를 작성하여 과학기술정보통신부장관에게 신청하여야 한다.\n1. 별지 제18호 서식에 따른 간접비고시비율 산출 신청서\n2. 간접비고시비율을 산출하는 연도의 직전 2개 회계연도 동안의 과학기술정보통신부장관이 정하는 회계원칙에 따른 간접비고시비율 산출의 기초자료(대학의 경우에 별지 제19호 서식에 따른 국가연구개발사업 간접비 지출내역서와 별지 제20호 서식에 따른 국가연구개발사업 간접비 학교회계전출금 지출내역서를 포함하나, 「특정연구기관 육성법 시행령」 제3조 각 호에 해당하는 경우에는 제외한다. 이하 같다)\n② 제1항에 따라 간접비고시비율 산출을 신청하는 연구개발기관은 신청하는 날이 포함된 연도에 실시하는 법 제25조에 따른 연구지원체계평가를 받아야 한다. 다만, 신청하는 날이 포함된 연도에 실시하는 연구지원체계평가의 실시일 이후에 설립된 연구개발기관의 경우에는 연구지원체계평가를 받지 아니하더라도 신청할 수 있다.\n③ 과학기술정보통신부장관은 다른 중앙행정기관의 장의 요구가 있는 경우에 제1항제2호에 따른 간접비고시비율 산출의 기초자료를 제공하여야 한다.", "effective_from": "2026-05-06", "effective_to": null, "is_active": true}, {"article_key": "MAIN_ART_114", "article_number": "114", "article_title": "간접비고시비율 산출", "section": "MAIN", "source_article": "제114조", "paragraph_start": 789, "paragraph_end": 798, "original_text": "제114조(간접비고시비율 산출) ① 과학기술정보통신부장관은 제113조제1항에 따라 간접비고시비율 산출을 신청한 연구개발기관에 대하여 다음 각 호의 사항을 고려하여 해당 연구개발기관의 간접비고시비율을 산출하여야 한다.\n1. 제113조제1항제2호에 따른 간접비고시비율 산출의 기초자료\n2. 법 제25조제3항에 따른 연구지원체계평가 결과\n② 제1항에 따른 비영리기관인 연구개발기관의 간접비고시비율은 별표 6과 같다.\n③ 간접비고시비율을 산출하지 아니한 대학의 간접비고시비율은 5퍼센트로 하고, 대학이 아닌 비영리기관 및 제113조제2항 단서에 해당하는 연구개발기관의 간접비고시비율은 17퍼센트로 한다. 다만, 간접비계상기준산출위원회가 정하는 의무 산출기관이 간접비고시비율을 산출하지 아니한 경우에 해당 연구개발기관의 간접비고시비율은 5퍼센트로 한다.\n④ 영리기관(「공공기관의 운영에 관한 법률」 제4조부터 제6조까지의 규정에 따라 지정ㆍ고시된 공기업을 포함한다)인 연구개발기관의 간접비고시비율은 10퍼센트로 한다.\n⑤ 제1항부터 제4항까지에도 불구하고 연구개발기관이 통폐합 또는 분리되는 경우에 통폐합된 연구개발기관은 이전 연구개발기관의 간접비고시비율 중 어느 하나를, 분리된 연구개발기관은 이전 연구개발기관의 간접비고시비율을 적용할 수 있다.\n⑥ 과학기술정보통신부장관은 제113조제1항제2호에 따른 간접비고시비율 산출의 기초자료가 조작되었거나 미흡하다고 판단하는 경우에는 해당 연구개발기관에 보완 자료를 요구할 수 있으며, 이에 따른 보완 자료가 조작되었거나 미흡하다고 판단하는 경우에 해당 연구개발기관의 간접비고시비율을 산출할 때 불리하게 대우할 수 있다.\n⑦ 과학기술정보통신부장관은 제45조제5항을 위반하여 간접비를 연구개발과제 선정을 위한 대응자금으로 사용한 연구개발기관에 대하여 간접비고시비율을 산출할 때 불리하게 대우할 수 있다.\n⑧ 그 밖에 간접비고시비율 산출에 관한 사항은 과학기술정보통신부장관이 정하는 바에 따른다.", "effective_from": "2026-05-06", "effective_to": null, "is_active": true}, {"article_key": "MAIN_ART_115", "article_number": "115", "article_title": "전담기관의 지정ㆍ지원", "section": "MAIN", "source_article": "제115조", "paragraph_start": 799, "paragraph_end": 802, "original_text": "제115조(전담기관의 지정ㆍ지원) ① 과학기술정보통신부장관의 제112조제1항에 따른 간접비고시비율 산출기준 마련, 제114조에 따른 간접비고시비율 산출의 효율적인 추진을 위하여 관련 업무를 종합적으로 지원하는 전담기관(이하 \"간접비고시비율산출전담기관\"이라 한다)을 지정할 수 있다.\n② 과학기술정보통신부장관은 간접비고시비율산출전담기관의 운영 및 사업 수행에 필요한 비용의 일부 또는 전부를 지원할 수 있다.\n③ 간접비고시비율산출전담기관은 「과학기술기본법」 제20조제1항에 따라 설립된 한국과학기술기획평가원으로 한다.\n제9장 보칙", "effective_from": "2026-05-06", "effective_to": null, "is_active": true}, {"article_key": "MAIN_ART_116", "article_number": "116", "article_title": "연구개발비 사용기준 특례", "section": "MAIN", "source_article": "제116조", "paragraph_start": 803, "paragraph_end": 805, "original_text": "제116조(연구개발비 사용기준 특례) ① <삭 제>\n② <삭 제>\n③ 제18조부터 제74조까지에도 불구하고 중앙행정기관의 장은 외국의 정부ㆍ기관ㆍ단체(국내 소재 연구개발기관의 해외 분원을 포함한다. 이하 같다)가 사용하거나 외국의 정부ㆍ기관ㆍ단체가 지원하는 연구개발비에 대하여는 그 사용기준을 달리 정할 수 있다.", "effective_from": "2026-05-06", "effective_to": null, "is_active": true}, {"article_key": "MAIN_ART_117", "article_number": "117", "article_title": "재검토기한", "section": "MAIN", "source_article": "제117조", "paragraph_start": 806, "paragraph_end": 807, "original_text": "제117조(재검토기한) 과학기술정보통신부장관은 「훈령ㆍ예규 등의 발령 및 관리에 관한 규정」에 따라 이 기준에 대하여 2021년 1월 1일 기준으로 매3년이 되는 시점(매 3년째의 12월 31일까지를 말한다)마다 그 타당성을 검토하여 개선 등의 조치를 하여야 한다.\n부칙 <제2026-38호, 2026.05.06.>", "effective_from": "2026-05-06", "effective_to": null, "is_active": true}, {"article_key": "SUPP_2026_38_ART_1", "article_number": "1", "article_title": "시행일", "section": "SUPPLEMENT", "source_article": "제1조", "paragraph_start": 808, "paragraph_end": 808, "original_text": "제1조(시행일) 이 고시는 발령한 날부터 시행한다. 다만, 제5조, 제10조의2 및 제25조의2의 개정규정은 2026년 6월 11일부터 시행한다.", "effective_from": "2026-05-06", "effective_to": null, "is_active": true}]
$articles$::jsonb)
as x(article_key text, article_number text, article_title text, section text,
     original_text text, paragraph_start integer, paragraph_end integer,
     effective_from date, effective_to date, is_active boolean)
where v.version_code = 'NRD_COST_STANDARD_2026_38'
on conflict (version_id, article_key) do update set
    article_number = excluded.article_number,
    article_title = excluded.article_title,
    section = excluded.section,
    original_text = excluded.original_text,
    paragraph_start = excluded.paragraph_start,
    paragraph_end = excluded.paragraph_end,
    effective_from = excluded.effective_from,
    effective_to = excluded.effective_to,
    is_active = excluded.is_active;

insert into expense_allowed_items
    (version_id, item_code, category_code, item_name, description,
     institution_scope, availability_status, condition_summary,
     eligibility_condition, requires_approval, requires_recognition,
     restriction_summary, evidence_summary, source_article,
     source_article_keys, effective_from, effective_to, display_order, is_active)
select
    v.id, x.item_code, x.category_code, x.item_name, x.description,
    x.institution_scope, x.availability_status, x.condition_summary,
    x.eligibility_condition, x.requires_approval, x.requires_recognition,
    x.restriction_summary, x.evidence_summary, x.source_article,
    x.source_article_keys, x.effective_from, x.effective_to, x.display_order,
    x.is_active
