insert into expense_limit_rules
    (version_id, limit_code, category_code, limit_name, limit_type,
     limit_value, limit_unit, basis_code, formula_expression, ui_summary,
     over_limit_action, institution_scope, applicability_condition,
     source_article, source_article_keys, effective_from, effective_to,
     priority, is_active)
