as x(limit_code text, category_code text, limit_name text, limit_type text,
     limit_value numeric, limit_unit text, basis_code text,
     formula_expression text, ui_summary text, over_limit_action text,
     institution_scope text, applicability_condition jsonb,
     source_article text, source_article_keys jsonb,
     effective_from date, effective_to date, priority integer,
     is_active boolean)
where v.version_code = 'NRD_COST_STANDARD_2026_38'
on conflict (version_id, limit_code) do update set
    category_code = excluded.category_code,
    limit_name = excluded.limit_name,
    limit_type = excluded.limit_type,
    limit_value = excluded.limit_value,
    limit_unit = excluded.limit_unit,
    basis_code = excluded.basis_code,
    formula_expression = excluded.formula_expression,
    ui_summary = excluded.ui_summary,
    over_limit_action = excluded.over_limit_action,
    institution_scope = excluded.institution_scope,
    applicability_condition = excluded.applicability_condition,
    source_article = excluded.source_article,
    source_article_keys = excluded.source_article_keys,
    effective_from = excluded.effective_from,
    effective_to = excluded.effective_to,
    priority = excluded.priority,
    is_active = excluded.is_active;

insert into budget_screen_guides
    (version_id, profile_code, category_code, display_name, usage_summary,
     allowed_items_text, allowed_item_count, limit_display_type, limit_text,
     limit_detail_text, formula_expression, institution_scope,
     over_limit_action, source_articles, source_article_keys,
     effective_from, effective_to, display_order, is_active)
select
    v.id, x.profile_code, x.category_code, x.display_name, x.usage_summary,
    x.allowed_items_text, x.allowed_item_count, x.limit_display_type,
    x.limit_text, x.limit_detail_text, x.formula_expression,
    x.institution_scope, x.over_limit_action, x.source_articles,
    x.source_article_keys, x.effective_from, x.effective_to,
    x.display_order, x.is_active
