insert into regulation_rules
    (version_id, rule_code, rule_name, domain, category_code, rule_type,
     evaluation_stages, automation_level, condition_json, result_json,
     required_inputs, source_article, source_article_keys, source_text,
     effective_from, effective_to, severity, priority, review_status, is_active)
select
    v.id, x.rule_code, x.rule_name, x.domain, x.expense_category_code,
    x.rule_type, x.evaluation_stages, x.automation_level, x.condition,
    x.result, x.required_inputs, x.source_article, x.source_article_keys,
    x.source_text, x.effective_from, x.effective_to, x.severity,
    x.priority, x.review_status, x.is_active
